--[[
    SYGKMUNII — Custom Gizmo v4.27

    FIX v4.27 — GIZMO TIDAK AKTIF SETELAH KELUAR PLAYMODE:
    ═══════════════════════════════════════════════════
    ROOT CAUSE 1: Folder SYG_GizmoV4 dihancurkan saat PlayMode keluar.
      Studio Lite me-restore workspace ke state sebelum Play →
      folder yang dibuat session ini ikut hilang.
      · GF.Parent = nil setelah PlayMode
      · _G["SYG_GizmoFolder"].Parent = nil (referensi stale)
      · Heartbeat guard "if not GF or not GF.Parent then return end"
        → return setiap frame, gizmo tidak pernah aktif lagi.

    FIX:
      · initFolder() sekarang HAPUS referensi _G yang stale sebelum cek.
      · recreateParts() panggil initFolder() (bukan ensureFolder())
        → folder dibuat ulang jika dihancurkan PlayMode.
      · Heartbeat folder guard: jika GF hilang, panggil initFolder()
        dan lanjut (bukan langsung return).

    ROOT CAUSE 2: Guard berlebihan di Heartbeat.
      "if partsForcedOff and lastMode == "" and lastTarget == nil then return"
      → setelah PlayMode keluar, kondisi ini terpenuhi selama task.defer
        belum jalan, menyebabkan deadlock jika ada timing issue.

    FIX:
      · Hapus guard kompleks itu. Ganti dengan flag sederhana
        setupDone yang diset true setelah setupPlayModeDetection selesai.
      · Heartbeat cukup cek isInPlayMode dan setupDone saja.

    PLAYMODE DETECTION (sama seperti v4.26 — sudah bekerja):
      · StudioGui.Stop.Visible = true  → PlayMode aktif → gizmo mati
      · StudioGui.Stop.Visible = false → Edit mode     → gizmo aktif
]]

local RS      = game:GetService("RunService")
local Players = game:GetService("Players")
local LP      = Players.LocalPlayer
local PGui    = LP:WaitForChild("PlayerGui")

-- ══════════════════════════════════════════════════
--  DETEKSI MODE AWAL
-- ══════════════════════════════════════════════════
local IS_STUDIO_LITE = false
local SGui = PGui:FindFirstChild("StudioGui")
if not SGui then task.wait(3); SGui = PGui:FindFirstChild("StudioGui") end
if SGui then
    IS_STUDIO_LITE = true
    print("[SYG v4.27] MODE: Studio Lite ✓")
else
    print("[SYG v4.27] MODE: Runtime/CopyMap")
end

-- ══════════════════════════════════════════════════
--  WARNA
-- ══════════════════════════════════════════════════
local COL = {
    R        = Color3.fromRGB(220,  55,  55),
    G        = Color3.fromRGB( 50, 200,  80),
    B        = Color3.fromRGB( 50, 130, 245),
    SEL_LINE = Color3.fromRGB(  0, 200, 255),
    SEL_SURF = Color3.fromRGB( 30, 140, 255),
    GOLD     = Color3.fromRGB(255, 210,  60),
}

-- ══════════════════════════════════════════════════
--  KONSTANTA
-- ══════════════════════════════════════════════════
local SHAFT_LEN   = 9999
local SHAFT_DIA   = 0.07
local OFFSET_Y    = 4.5
local OFFSET_X    = 7.0
local OFFSET_Z    = 7.0
local ROT_LABEL_R = 4.5
local BB_MAX      = 3.0
local BB_MIN      = 0.3
local NEAR_DIST   = 8
local FAR_DIST    = 80
local DRAG_THR    = 0.001

local Camera = workspace.CurrentCamera
local ROT_X  = CFrame.identity
local ROT_Y  = CFrame.Angles(0, 0, math.pi/2)
local ROT_Z  = CFrame.Angles(0, math.pi/2, 0)

-- ══════════════════════════════════════════════════
--  FLAGS GLOBAL
-- ══════════════════════════════════════════════════
local isInPlayMode   = false
local gizmoEnabled   = false
local partsForcedOff = true
local setupDone      = false   -- true setelah setupPlayModeDetection selesai

local lastMode   = ""
local lastTarget = nil

-- ══════════════════════════════════════════════════
--  FOLDER — SATU SELAMANYA
--
--  FIX v4.27: initFolder() hapus referensi _G stale dulu.
--  Jika folder dihancurkan PlayMode (GF.Parent=nil),
--  initFolder() akan buat folder baru.
-- ══════════════════════════════════════════════════
local GF_NAME = "SYG_GizmoV4"
local GF      = nil

-- Hapus SEMUA duplikat SYG_GizmoV4, pertahankan hanya GF aktif
local function cleanupDuplicates()
    if not GF or not GF.Parent then return end
    for _, child in ipairs(workspace:GetChildren()) do
        if child.Name == GF_NAME and child ~= GF then
            pcall(function() child:Destroy() end)
            print("[SYG v4.27] Cleanup: hapus folder duplikat.")
        end
    end
end

local function initFolder()
    -- Bersihkan referensi _G stale (folder sudah dihancurkan)
    if _G["SYG_GizmoFolder"] and not _G["SYG_GizmoFolder"].Parent then
        _G["SYG_GizmoFolder"] = nil
    end

    -- GF masih valid → pakai saja
    if GF and GF.Parent then
        _G["SYG_GizmoFolder"] = GF
        -- Hapus duplikat lain yang mungkin muncul setelah restore PlayMode
        task.defer(cleanupDuplicates)
        return
    end

    -- _G masih valid → pakai
    if _G["SYG_GizmoFolder"] and _G["SYG_GizmoFolder"].Parent then
        GF = _G["SYG_GizmoFolder"]
        task.defer(cleanupDuplicates)
        return
    end

    -- Tidak ada yang valid → hancurkan SEMUA yang ada, buat satu folder baru
    -- Ini mencegah duplikasi saat Studio Lite restore workspace lama + kita buat baru
    for _, child in ipairs(workspace:GetChildren()) do
        if child.Name == GF_NAME then
            pcall(function() child:Destroy() end)
        end
    end

    local f = Instance.new("Folder")
    f.Name   = GF_NAME
    f.Parent = workspace
    GF = f
    _G["SYG_GizmoFolder"] = GF
    print("[SYG v4.27] Folder baru dibuat (semua lama dihapus).")

    -- Cleanup lagi setelah 0.5 detik untuk tangkap folder restore yang datang terlambat
    task.delay(0.5, cleanupDuplicates)
end

local function ensureFolder()
    -- Cek stale dulu
    if _G["SYG_GizmoFolder"] and not _G["SYG_GizmoFolder"].Parent then
        _G["SYG_GizmoFolder"] = nil
    end
    if GF and GF.Parent then return GF end
    if _G["SYG_GizmoFolder"] and _G["SYG_GizmoFolder"].Parent then
        GF = _G["SYG_GizmoFolder"]
        return GF
    end
    local existing = workspace:FindFirstChild(GF_NAME)
    if existing then
        GF = existing
        _G["SYG_GizmoFolder"] = GF
        return GF
    end
    return nil
end

initFolder()

-- ══════════════════════════════════════════════════
--  PARTS
-- ══════════════════════════════════════════════════
local function newCyl(color)
    local p = Instance.new("Part")
    p.Shape        = Enum.PartType.Cylinder
    p.Size         = Vector3.new(SHAFT_LEN, SHAFT_DIA, SHAFT_DIA)
    p.Color        = color
    p.Material     = Enum.Material.Neon
    p.Anchored     = true;  p.CanCollide  = false
    p.CanQuery     = false; p.CastShadow  = false
    p.Transparency = 1
    p.Parent       = GF
    return p
end

local function ensureShaft(t, key, color)
    if t[key] and t[key].Parent then
        if t[key].Parent ~= GF then
            pcall(function() t[key].Parent = GF end)
        end
        return
    end
    t[key] = newCyl(color)
end

local function fillShafts(t)
    ensureShaft(t, "x", COL.R)
    ensureShaft(t, "y", COL.G)
    ensureShaft(t, "z", COL.B)
end

local function initShafts(t)
    t.x = newCyl(COL.R)
    t.y = newCyl(COL.G)
    t.z = newCyl(COL.B)
end

local MoveShafts  = {}; initShafts(MoveShafts)
local ScaleShafts = {}; initShafts(ScaleShafts)

-- ══════════════════════════════════════════════════
--  AXIS LABELS
-- ══════════════════════════════════════════════════
local function newAxisLabel(axisColor)
    local t = {}
    local ap = Instance.new("Part")
    ap.Size = Vector3.new(0.05,0.05,0.05); ap.Anchored = true
    ap.CanCollide = false; ap.CanQuery = false
    ap.CastShadow = false; ap.Transparency = 1
    ap.Parent = GF

    local bb = Instance.new("BillboardGui")
    bb.AlwaysOnTop  = true; bb.LightInfluence = 0
    bb.ResetOnSpawn = false; bb.Enabled = false
    bb.Size         = UDim2.new(BB_MAX*2.4, 0, BB_MAX*1.1, 0)
    bb.Parent       = ap

    local bg = Instance.new("Frame")
    bg.Size = UDim2.new(1,0,1,0)
    bg.BackgroundColor3 = Color3.fromRGB(0,0,0)
    bg.BackgroundTransparency = 0.3
    bg.BorderSizePixel = 0; bg.Parent = bb

    local bgC = Instance.new("UICorner")
    bgC.CornerRadius = UDim.new(0.18,0); bgC.Parent = bg

    local bgS = Instance.new("UIStroke")
    bgS.Color = axisColor; bgS.Thickness = 1.0
    bgS.Transparency = 0.35; bgS.Parent = bg

    local val = Instance.new("TextLabel")
    val.Size = UDim2.new(1,0,0.56,0); val.Position = UDim2.new(0,0,0.02,0)
    val.BackgroundTransparency = 1; val.TextColor3 = axisColor
    val.Font = Enum.Font.GothamBold; val.TextScaled = true
    val.Text = "+0.000"; val.TextXAlignment = Enum.TextXAlignment.Center
    val.Parent = bg
    local vc = Instance.new("UITextSizeConstraint")
    vc.MinTextSize = 1; vc.MaxTextSize = 500; vc.Parent = val

    local dlt = Instance.new("TextLabel")
    dlt.Size = UDim2.new(1,0,0.40,0); dlt.Position = UDim2.new(0,0,0.58,0)
    dlt.BackgroundTransparency = 1; dlt.TextColor3 = COL.GOLD
    dlt.Font = Enum.Font.Gotham; dlt.TextScaled = true
    dlt.Text = "Δ+0.000"; dlt.TextXAlignment = Enum.TextXAlignment.Center
    dlt.Visible = false; dlt.Parent = bg
    local dc = Instance.new("UITextSizeConstraint")
    dc.MinTextSize = 1; dc.MaxTextSize = 500; dc.Parent = dlt

    t.part = ap; t.bb = bb; t.val = val; t.dlt = dlt
    return t
end

local function ensureAxisLabel(t, axisColor)
    if t.part and t.part.Parent then
        if t.part.Parent ~= GF then pcall(function() t.part.Parent = GF end) end
        if t.bb then t.bb.Enabled = false end
        return
    end
    local newT = newAxisLabel(axisColor)
    t.part = newT.part; t.bb = newT.bb
    t.val  = newT.val;  t.dlt = newT.dlt
end

local KEYS = {"x","y","z"}
local AL = {
    x = newAxisLabel(COL.R),
    y = newAxisLabel(COL.G),
    z = newAxisLabel(COL.B),
}

-- ══════════════════════════════════════════════════
--  RECREATE PARTS — FIX v4.27
--  Panggil initFolder() bukan ensureFolder()
--  agar folder dibuat ulang jika dihancurkan PlayMode.
-- ══════════════════════════════════════════════════
local function recreateParts()
    -- FIX: initFolder() bisa buat folder baru jika lama dihancurkan
    initFolder()
    if not GF or not GF.Parent then
        warn("[SYG v4.27] Folder tidak bisa dibuat ulang!")
        return
    end
    fillShafts(MoveShafts)
    fillShafts(ScaleShafts)
    ensureAxisLabel(AL.x, COL.R)
    ensureAxisLabel(AL.y, COL.G)
    ensureAxisLabel(AL.z, COL.B)
    print("[SYG v4.27] Parts direcreate — folder: " .. GF.Name)
end

-- ══════════════════════════════════════════════════
--  VISIBILITAS
-- ══════════════════════════════════════════════════
local function setVis(t, ...)
    for _, sh in ipairs({...}) do
        for _, p in pairs(sh) do
            if p and p.Parent then p.Transparency = t end
        end
    end
end

local function hideAll()
    setVis(1, MoveShafts, ScaleShafts)
end

local function updateShafts(sh, cf)
    local p = cf.Position
    sh.x.CFrame = CFrame.new(p) * cf.Rotation * ROT_X
    sh.y.CFrame = CFrame.new(p) * cf.Rotation * ROT_Y
    sh.z.CFrame = CFrame.new(p) * cf.Rotation * ROT_Z
end

local function placeLabel(lbl, wp)
    if not lbl.part or not lbl.part.Parent then return end
    lbl.part.CFrame = CFrame.new(wp)
    lbl.bb.Enabled  = true
    local d = math.max((Camera.CFrame.Position - wp).Magnitude, 0.1)
    local t2 = math.clamp((d - NEAR_DIST)/(FAR_DIST - NEAR_DIST), 0, 1)
    local s = BB_MAX + (BB_MIN - BB_MAX) * t2
    lbl.bb.Size = UDim2.new(s*2.4, 0, s*1.1, 0)
end

local function hideLabel(lbl)
    if lbl.bb then lbl.bb.Enabled = false end
end

local function hardDisableAllLabels()
    for _, k in ipairs(KEYS) do
        if AL[k].bb and AL[k].bb.Parent then AL[k].bb.Enabled = false end
        if AL[k].part and AL[k].part.Parent then
            AL[k].part.CFrame = CFrame.new(0, -9999, 0)
        end
    end
end

local function hideAllLabels()
    for _, k in ipairs(KEYS) do hideLabel(AL[k]) end
end

local function forceDisableAllParts()
    if not GF or not GF.Parent then return end
    for _, child in ipairs(GF:GetChildren()) do
        if child:IsA("BasePart") then
            child.Transparency = 1
            child.CanCollide   = false
            child.CanQuery     = false
            child.CastShadow   = false
        end
        for _, sub in ipairs(child:GetChildren()) do
            if sub:IsA("BillboardGui") then
                sub.Enabled = false
            end
        end
    end
    partsForcedOff = true
end

-- ══════════════════════════════════════════════════
--  FORMAT & STATE
-- ══════════════════════════════════════════════════
local function fmt(n)
    return (n < 0 and "-" or "+") .. string.format("%.3f", math.abs(n))
end
local function fmtDeg(n) return string.format("%.1f°", n % 360) end

local prevVals = { x=nil, y=nil, z=nil }
local active   = { x=false, y=false, z=false }

local function resetState()
    for _, k in ipairs(KEYS) do prevVals[k] = nil; active[k] = false end
    hideAllLabels()
end

local function activateAllLabels()
    for _, k in ipairs(KEYS) do active[k] = true end
end

local function primePrevVals(mode, target, cf)
    if mode == "Move" then
        local pos = cf.Position
        prevVals.x = pos.X; prevVals.y = pos.Y; prevVals.z = pos.Z
    elseif mode == "Scale" then
        local ok, size = pcall(function()
            return target:IsA("Model") and target:GetExtentsSize() or target.Size
        end)
        if ok then prevVals.x = size.X; prevVals.y = size.Y; prevVals.z = size.Z end
    elseif mode == "Rotate" then
        local ex, ey, ez = cf.Rotation:ToEulerAnglesXYZ()
        prevVals.x = math.deg(ex); prevVals.y = math.deg(ey); prevVals.z = math.deg(ez)
    end
end

-- ══════════════════════════════════════════════════
--  UPDATE LABELS
-- ══════════════════════════════════════════════════
local function updateLabels(mode, target, cf)
    local pos = cf.Position
    local rx  = cf.RightVector
    local ry  = cf.UpVector
    local rz  = -cf.LookVector
    local pos3 = {
        x = pos + rx * OFFSET_X,
        y = pos + ry * OFFSET_Y,
        z = pos + rz * OFFSET_Z,
    }

    if mode == "Move" then
        local raw = { x=pos.X, y=pos.Y, z=pos.Z }
        local fmtVals = { x=fmt(pos.X), y=fmt(pos.Y), z=fmt(pos.Z) }
        local fmtDeltas = {}
        for _, k in ipairs(KEYS) do
            if prevVals[k] ~= nil then
                local d = raw[k] - prevVals[k]
                fmtDeltas[k] = math.abs(d) > DRAG_THR and ("Δ"..fmt(d)) or nil
            end
        end
        for _, k in ipairs(KEYS) do prevVals[k] = raw[k] end
        local moving = { x=false, y=false, z=false }
        for _, k in ipairs(KEYS) do if fmtDeltas[k] then moving[k]=true end end
        if moving.x or moving.y or moving.z then
            for _, k in ipairs(KEYS) do
                if active[k] and not moving[k] then active[k]=false; hideLabel(AL[k]) end
                if moving[k] then active[k]=true end
            end
        end
        for _, k in ipairs(KEYS) do
            if active[k] then
                placeLabel(AL[k], pos3[k])
                AL[k].val.Text = fmtVals[k]
                if moving[k] and fmtDeltas[k] then
                    AL[k].dlt.Text = fmtDeltas[k]; AL[k].dlt.Visible = true
                else AL[k].dlt.Visible = false end
            end
        end

    elseif mode == "Scale" then
        local ok, size = pcall(function()
            return target:IsA("Model") and target:GetExtentsSize() or target.Size
        end)
        if not ok then return end
        local raw = { x=size.X, y=size.Y, z=size.Z }
        local moving = { x=false, y=false, z=false }
        for _, k in ipairs(KEYS) do
            if prevVals[k] ~= nil then
                moving[k] = math.abs(raw[k]-prevVals[k]) > DRAG_THR
            end
            prevVals[k] = raw[k]
        end
        if moving.x or moving.y or moving.z then
            for _, k in ipairs(KEYS) do
                if active[k] and not moving[k] then active[k]=false; hideLabel(AL[k]) end
                if moving[k] then active[k]=true end
            end
        end
        for _, k in ipairs(KEYS) do
            if active[k] then
                placeLabel(AL[k], pos3[k])
                AL[k].val.Text = fmt(raw[k])
                AL[k].dlt.Visible = false
            end
        end

    elseif mode == "Rotate" then
        local ex, ey, ez = cf.Rotation:ToEulerAnglesXYZ()
        local raw = { x=math.deg(ex), y=math.deg(ey), z=math.deg(ez) }
        local rotPos = {
            x = pos + ry * ROT_LABEL_R,
            y = pos + rx * ROT_LABEL_R,
            z = pos + ry*(ROT_LABEL_R*0.7) + rz*(ROT_LABEL_R*0.7),
        }
        local moving = { x=false, y=false, z=false }
        for _, k in ipairs(KEYS) do
            if prevVals[k] ~= nil then
                local d = math.abs(raw[k]-prevVals[k])
                if d > 180 then d = 360-d end
                moving[k] = d > 0.01
            end
            prevVals[k] = raw[k]
        end
        if moving.x or moving.y or moving.z then
            for _, k in ipairs(KEYS) do
                if active[k] and not moving[k] then active[k]=false; hideLabel(AL[k]) end
                if moving[k] then active[k]=true end
            end
        end
        for _, k in ipairs(KEYS) do
            if active[k] then
                placeLabel(AL[k], rotPos[k])
                AL[k].val.Text = fmtDeg(raw[k])
                AL[k].dlt.Visible = false
            end
        end
    end
end

-- ══════════════════════════════════════════════════
--  PLAYMODE TRANSITION HANDLERS
-- ══════════════════════════════════════════════════
local function onEnterPlayMode()
    if isInPlayMode then return end
    isInPlayMode   = true
    gizmoEnabled   = false
    partsForcedOff = true
    lastMode       = ""
    lastTarget     = nil
    hardDisableAllLabels()
    resetState()
    hideAll()
    forceDisableAllParts()
    print("[SYG v4.27] ▶ PlayMode MASUK — gizmo mati total.")
end

local function onExitPlayMode()
    if not isInPlayMode then return end
    isInPlayMode = false
    gizmoEnabled = false
    lastMode     = ""
    lastTarget   = nil
    -- task.defer: jalankan setelah 1 frame agar Studio Lite selesai restore workspace
    task.defer(function()
        -- FIX: recreateParts memanggil initFolder() yang bisa buat folder baru
        -- jika folder lama dihancurkan saat PlayMode restore workspace
        recreateParts()
        resetState()
        hardDisableAllLabels()
        hideAll()
        partsForcedOff = false  -- izinkan Heartbeat detect target
        print("[SYG v4.27] ◀ PlayMode KELUAR — gizmo siap, menunggu select.")
    end)
end

-- ══════════════════════════════════════════════════
--  PLAYMODE DETECTION via StudioGui.Stop.Visible
--  Stop.Visible = true  → PlayMode aktif
--  Stop.Visible = false → Edit mode
-- ══════════════════════════════════════════════════
local function setupPlayModeDetection(studioGui)
    local BtnStop = studioGui:FindFirstChild("Stop")
    if not BtnStop then
        BtnStop = studioGui:WaitForChild("Stop", 10)
    end

    if not BtnStop then
        warn("[SYG v4.27] ⚠ Stop button tidak ditemukan — PlayMode detection OFF.")
        -- Tetap aktifkan gizmo
        partsForcedOff = false
        setupDone      = true
        return
    end

    -- Set state awal dari kondisi Stop.Visible saat ini
    if BtnStop.Visible then
        isInPlayMode   = true
        partsForcedOff = true
        forceDisableAllParts()
        print("[SYG v4.27] Startup: PlayMode aktif (Stop visible) → gizmo mati.")
    else
        isInPlayMode   = false
        partsForcedOff = false
        print("[SYG v4.27] Startup: Edit mode (Stop tidak visible) → gizmo siap.")
    end

    -- Watch perubahan Stop.Visible
    BtnStop:GetPropertyChangedSignal("Visible"):Connect(function()
        if BtnStop.Visible then
            onEnterPlayMode()
        else
            onExitPlayMode()
        end
    end)

    setupDone = true
    print("[SYG v4.27] ✓ PlayMode detection AKTIF via Stop.Visible")
end

-- ══════════════════════════════════════════════════
--  STARTUP
-- ══════════════════════════════════════════════════
forceDisableAllParts()

-- ══════════════════════════════════════════════════
--  MODE A: STUDIO LITE
-- ══════════════════════════════════════════════════
if IS_STUDIO_LITE then

    local HR = SGui:WaitForChild("HandlesR",     10)
    local HG = SGui:WaitForChild("HandlesG",     10)
    local HB = SGui:WaitForChild("HandlesB",     10)
    local AH = SGui:WaitForChild("ArcHandles",   10)
    local SB = SGui:WaitForChild("SelectionBox", 10)

    if not (HR and HG and HB and AH and SB) then
        warn("[SYG v4.27] Handles tidak lengkap!"); return
    end

    local MainBar   = SGui:WaitForChild("MainBar", 10)
    local BtnMove   = MainBar and MainBar:WaitForChild("move",   8)
    local BtnScale  = MainBar and MainBar:WaitForChild("scale",  8)
    local BtnRotate = MainBar and MainBar:WaitForChild("rotate", 8)

    if not (BtnMove and BtnScale and BtnRotate) then
        warn("[SYG v4.27] Tombol mode tidak ditemukan!"); return
    end

    HR.Color3 = COL.R; HG.Color3 = COL.G; HB.Color3 = COL.B
    AH.Color3 = Color3.fromRGB(255,255,255)
    SB.Color3 = COL.SEL_LINE; SB.LineThickness = 0.04
    SB.SurfaceColor3 = COL.SEL_SURF; SB.SurfaceTransparency = 0.85

    -- Setup PlayMode detection (async agar tidak block init)
    task.defer(function()
        setupPlayModeDetection(SGui)
    end)

    local ACTIVE_COLOR = Color3.fromRGB(200,200,200)
    local function colorMatch(c1, c2)
        return math.abs(c1.R-c2.R) < 0.05
           and math.abs(c1.G-c2.G) < 0.05
           and math.abs(c1.B-c2.B) < 0.05
    end
    local function detectMode()
        if colorMatch(BtnRotate.BackgroundColor3, ACTIVE_COLOR) then return "Rotate"
        elseif colorMatch(BtnMove.BackgroundColor3, ACTIVE_COLOR)  then return "Move"
        elseif colorMatch(BtnScale.BackgroundColor3, ACTIVE_COLOR) then return "Scale"
        end
        return "Select"
    end
    local function getTarget(mode)
        if mode == "Rotate" then return AH.Adornee end
        return HR.Adornee or HG.Adornee or HB.Adornee
    end

    RS.Heartbeat:Connect(function()
        -- Guard 1: tunggu setup selesai
        if not setupDone then return end
        -- Guard 2: PlayMode aktif → skip total
        if isInPlayMode then return end
        -- Guard 3: FIX v4.27 — jika GF hilang (dihancurkan PlayMode),
        --          coba initFolder() untuk buat ulang, lanjut jika berhasil
        if not GF or not GF.Parent then
            initFolder()
            if not GF or not GF.Parent then return end
        end

        -- Restore warna handle
        if not colorMatch(HR.Color3, COL.R) then HR.Color3 = COL.R end
        if not colorMatch(HG.Color3, COL.G) then HG.Color3 = COL.G end
        if not colorMatch(HB.Color3, COL.B) then HB.Color3 = COL.B end

        local mode   = detectMode()
        local target = getTarget(mode)

        -- Deteksi perubahan target/mode → reset dan re-init
        if mode ~= lastMode or target ~= lastTarget then
            hideAll()
            resetState()
            lastMode   = mode
            lastTarget = target

            if target and mode ~= "Select" then
                local ok, cf = pcall(function() return target:GetPivot() end)
                if ok and cf then
                    primePrevVals(mode, target, cf)
                    activateAllLabels()
                    gizmoEnabled   = true
                    partsForcedOff = false
                else
                    gizmoEnabled   = false
                    partsForcedOff = true
                end
            else
                -- Tidak ada target / mode Select → matikan
                gizmoEnabled   = false
                partsForcedOff = true
                forceDisableAllParts()
            end
        end

        -- Guard: tidak ada select valid
        if partsForcedOff or not gizmoEnabled then return end

        if mode == "Select" or not target then
            hideAll(); resetState()
            gizmoEnabled   = false
            partsForcedOff = true
            forceDisableAllParts()
            return
        end

        local ok, cf = pcall(function() return target:GetPivot() end)
        if not ok or not cf then
            resetState()
            gizmoEnabled   = false
            partsForcedOff = true
            return
        end

        if mode == "Move" then
            updateShafts(MoveShafts, cf)
            setVis(0, MoveShafts); setVis(1, ScaleShafts)
        elseif mode == "Scale" then
            updateShafts(ScaleShafts, cf)
            setVis(0, ScaleShafts); setVis(1, MoveShafts)
        elseif mode == "Rotate" then
            hideAll()
        end

        updateLabels(mode, target, cf)
    end)

    script.AncestryChanged:Connect(function()
        if not script.Parent then
            pcall(function()
                HR.Color3 = Color3.fromRGB(1,0,0)
                HG.Color3 = Color3.fromRGB(0,1,0)
                HB.Color3 = Color3.fromRGB(0,0,1)
            end)
            if GF then pcall(function() GF:Destroy() end) end
        end
    end)

    print("[SYG v4.27] ✓ Studio Lite AKTIF — PlayMode via Stop.Visible, folder auto-recreate")

-- ══════════════════════════════════════════════════
--  MODE B: RUNTIME / COPYMAP
-- ══════════════════════════════════════════════════
else
    local function getCharPivot()
        local char = LP.Character
        if not char then return nil end
        local hrp = char:FindFirstChild("HumanoidRootPart")
        return hrp and hrp:GetPivot() or nil
    end
    partsForcedOff = false
    setupDone      = true
    setVis(0, MoveShafts)
    RS.Heartbeat:Connect(function()
        if isInPlayMode then return end
        if not GF or not GF.Parent then
            initFolder()
            if not GF or not GF.Parent then return end
        end
        local cf = getCharPivot()
        if not cf then setVis(1, MoveShafts); return end
        updateShafts(MoveShafts, cf)
        setVis(0, MoveShafts)
    end)
    script.AncestryChanged:Connect(function()
        if not script.Parent and GF then GF:Destroy() end
    end)
    print("[SYG v4.27] ✓ CopyMap Mode AKTIF")
end
--[[
  ╔══════════════════════════════════════════════════════════════════════╗
  ║   SL SIDEBAR PREMIUM — PC EDITION  v5.0  ★ HTML SYNC ★            ║
  ║                                                                      ║
  ║   SYNC 100% ke RobloxStudio_shell.html:                             ║
  ║   • Palette: bg0#1a1a1a bg1#242424 bg2#2d2d2d bg3#363636 bg4#404040║
  ║   • Accent:  #00a2ff / #0075cc                                      ║
  ║   • Text:    #e8e8e8 / #c0c0c0 / #8a8a8a                           ║
  ║   • Border:  #404040 / #505050                                      ║
  ║   • Roblox Red: #e2231a  Green: #4caf50                             ║
  ║   • Menubar: #1c1c1c  Toolbar: #242424                              ║
  ║   • Panel Toolbox: layout + pill cats + scrollbar sync              ║
  ╚══════════════════════════════════════════════════════════════════════╝
]]

local CoreGui   = game:GetService("CoreGui")
local Players   = game:GetService("Players")
local Workspace = game:GetService("Workspace")
local TweenSvc  = game:GetService("TweenService")

-- Bersihkan semua versi lama
for _, nm in ipairs({
    "SL_THEME","SL_THEME_V2","SL_THEME_V3",
    "SL_THEME_V33","SL_THEME_V34","SL_THEME_V35",
    "SL_THEME_V36","SL_THEME_V37","SL_THEME_V38",
    "SL_THEME_V39","SL_THEME_V40","SL_THEME_V50"
}) do
    pcall(function()
        local o = CoreGui:FindFirstChild(nm)
        if o then o:Destroy() end
    end)
end

local root    = Instance.new("Folder")
root.Name     = "SL_THEME_V50"
root.Parent   = CoreGui

local LP        = Players.LocalPlayer
local PlayerGui = LP:WaitForChild("PlayerGui", 20)
local StudioGui = PlayerGui and PlayerGui:WaitForChild("StudioGui", 20)
if not StudioGui then warn("[SL v4.0] StudioGui tidak ditemukan"); return end

-- ══════════════════════════════════════════════
--  PALETTE (v3.9)
-- ══════════════════════════════════════════════
-- ══════════════════════════════════════════════
--  PALETTE — SYNC 100% KE HTML CSS VARS
--  --bg0:#1a1a1a  --bg1:#242424  --bg2:#2d2d2d
--  --bg3:#363636  --bg4:#404040
--  --accent:#00a2ff  --accent2:#0075cc
--  --text0:#e8e8e8  --text1:#c0c0c0  --text2:#8a8a8a
--  --border:#404040  --border2:#505050
--  --roblox-red:#e2231a  --green:#4caf50
-- ══════════════════════════════════════════════
local C = {
    bg0   = Color3.fromRGB( 26,  26,  26),   -- #1a1a1a  body bg
    bg1   = Color3.fromRGB( 36,  36,  36),   -- #242424  toolbar/panel bg
    bg2   = Color3.fromRGB( 45,  45,  45),   -- #2d2d2d  secondary bg
    bg3   = Color3.fromRGB( 54,  54,  54),   -- #363636  input/hover bg
    bg4   = Color3.fromRGB( 64,  64,  64),   -- #404040  active/border
    bg5   = Color3.fromRGB( 80,  80,  80),   -- #505050  border2
    accA  = Color3.fromRGB(  0, 162, 255),   -- #00a2ff  accent
    accB  = Color3.fromRGB(  0, 117, 204),   -- #0075cc  accent2
    accC  = Color3.fromRGB(  0,  80, 160),   -- darker accent (pressed)
    glow  = Color3.fromRGB( 80, 180, 255),   -- glow accent
    txtP  = Color3.fromRGB(232, 232, 232),   -- #e8e8e8  text0 primary
    txtS  = Color3.fromRGB(192, 192, 192),   -- #c0c0c0  text1 secondary
    txtD  = Color3.fromRGB(138, 138, 138),   -- #8a8a8a  text2 dim
    bdr   = Color3.fromRGB( 64,  64,  64),   -- #404040  border
    bdrB  = Color3.fromRGB( 80,  80,  80),   -- #505050  border2
    bdrA  = Color3.fromRGB(  0, 117, 204),   -- accent border
    selBg = Color3.fromRGB(  0,  75, 150),   -- selection bg
    tbBg  = Color3.fromRGB( 28,  28,  28),   -- #1c1c1c  menubar bg
    panBg = Color3.fromRGB( 36,  36,  36),   -- #242424  panel bg
    red   = Color3.fromRGB(226,  35,  26),   -- #e2231a  roblox red
    green = Color3.fromRGB( 76, 175,  80),   -- #4caf50  green play
}

local PFX = "SLv50_"
local function isOwn(o)
    return type(o.Name)=="string" and o.Name:sub(1,#PFX)==PFX
end

-- ══════════════════════════════════════════════
--  UI HELPERS
-- ══════════════════════════════════════════════
local function corner(p, r)
    local u = Instance.new("UICorner")
    u.CornerRadius = UDim.new(0, r or 8)
    u.Parent = p; return u
end
local function stroke(p, col, thick, trans)
    local s = p:FindFirstChildOfClass("UIStroke") or Instance.new("UIStroke")
    s.Color=col or C.bdrB; s.Thickness=thick or 1
    s.Transparency=trans or 0; s.Parent=p; return s
end
local function gradient(p, c0, c1, rot)
    local g = p:FindFirstChildOfClass("UIGradient") or Instance.new("UIGradient")
    g.Color=ColorSequence.new(c0,c1); g.Rotation=rot or 90; g.Parent=p; return g
end
local function tw(obj, info, props)
    pcall(function() TweenSvc:Create(obj,info,props):Play() end)
end
local FAST = TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)

local function lum(c)    return c.R*0.299+c.G*0.587+c.B*0.114 end
local function isBlue(c) return c.B>0.25 and c.B>c.R+0.07 and c.B>c.G+0.07 end
local function isPlay(o)
    local n=o.Name:lower()
    return n=="play" or n=="playbtn" or n=="playbutton"
        or (n:sub(1,4)=="play" and #n<=12)
end

-- ══════════════════════════════════════════════
--  THEME ENGINE (v3.9 — threshold 0.62)
-- ══════════════════════════════════════════════
local lockedText = {}

-- Helper: deteksi apakah objek adalah color swatch material (harus dilindungi dari theming)
local function isColorSwatch(obj)
    local n = obj.Name or ""
    return n:sub(1,10)=="MatSwatch_" or n:sub(1,12)=="ColorSwatch_" or n=="MatDot" or n=="GrassDot" or n=="GroundDot"
end

local function themeObj(obj)
    if isOwn(obj) then return end
    -- SKIP: swatch warna material agar warna asli (hijau, coklat, dll) tidak ditimpa abu-abu
    if isColorSwatch(obj) then return end
    pcall(function()

        if obj:IsA("Frame") or obj:IsA("ScrollingFrame") then
            if obj.BackgroundTransparency >= 0.62 then return end
            -- SKIP swatch berdasarkan nama
            if isColorSwatch(obj) then return end
            local c=obj.BackgroundColor3; local b=lum(c)
            if isBlue(c) and b>0.10 then obj.BackgroundColor3=C.selBg; return end
            if     b>0.82 then obj.BackgroundColor3=C.bg0   -- putih → bg0 #1a1a1a
            elseif b>0.60 then obj.BackgroundColor3=C.bg1   -- abu terang → bg1 #242424
            elseif b>0.38 then obj.BackgroundColor3=C.bg2   -- abu sedang → bg2 #2d2d2d
            elseif b>0.20 then obj.BackgroundColor3=C.bg3   -- abu gelap → bg3 #363636
            else                obj.BackgroundColor3=C.bg4  -- paling gelap → bg4 #404040
            end
            if obj:IsA("ScrollingFrame") then
                obj.ScrollBarThickness=3
                obj.ScrollBarImageColor3=C.accB
            end
            return
        end

        if obj:IsA("TextButton") or obj:IsA("ImageButton") then
            -- Jangan beri background pada tombol "Select Multi" dan sejenisnya
            local nm = obj.Name:lower()
            local isMultiSelect = nm:find("selectmulti") or nm:find("select_multi")
                or nm:find("multi") or nm:find("selectchildren")
                or (nm:find("select") and nm:find("multi"))
            if not isMultiSelect then
                local t=obj.BackgroundTransparency
                if t<0.62 then
                    local b=lum(obj.BackgroundColor3)
                    if b>0.18 and not isBlue(obj.BackgroundColor3) then
                        obj.BackgroundColor3=C.bg3
                        obj.BackgroundTransparency=0.38
                    end
                end
            else
                -- Select Multi: paksa transparent, tanpa background
                pcall(function()
                    obj.BackgroundTransparency=1
                end)
            end
            pcall(function() obj.Active=true end)
            pcall(function() obj.AutoButtonColor=false end)
        end

        if obj:IsA("TextLabel") or obj:IsA("TextButton") or obj:IsA("TextBox") then
            local target=isPlay(obj) and C.red or C.txtP
            obj.TextColor3=target
            if not lockedText[obj] then
                lockedText[obj]=true
                obj:GetPropertyChangedSignal("TextColor3"):Connect(function()
                    pcall(function()
                        if obj.TextColor3~=target then obj.TextColor3=target end
                    end)
                end)
            end
        end

        -- Image: JANGAN ubah ImageColor3, pastikan visible
        if obj:IsA("ImageLabel") or obj:IsA("ImageButton") then
            pcall(function()
                if obj.ImageTransparency>0.05 then obj.ImageTransparency=0 end
                if obj.BackgroundTransparency<0.85 then
                    if lum(obj.BackgroundColor3)>0.15 then
                        obj.BackgroundColor3=C.bg3
                    end
                end
            end)
        end
    end)
end

local function themeAll()
    for _,obj in ipairs(StudioGui:GetDescendants()) do pcall(themeObj,obj) end
end
local function startThemeWatcher()
    StudioGui.DescendantAdded:Connect(function(obj)
        task.defer(function() pcall(themeObj,obj) end)
    end)
end

-- ══════════════════════════════════════════════
--  SNAP POPUP THEMING v1.0
--  Deteksi popup angka snap bawaan Studio Lite
--  (muncul di dekat tombol Move/Rotate/Scale saat hover)
--  Popup biasanya: Frame kecil (<120x80) berisi TextLabel angka + TextLabel label
--  Kita theme total: dark bg, border biru, rounded, font premium
-- ══════════════════════════════════════════════
local themedPopups = {}

local function isSnapPopup(obj)
    -- Popup snap: Frame kecil dekat toolbar, bukan milik kita
    if isOwn(obj) then return false end
    if not (obj:IsA("Frame") or obj:IsA("ScreenGui")) then return false end
    local w = obj.AbsoluteSize.X; local h = obj.AbsoluteSize.Y
    -- Ukuran kecil (popup snap ~40-130px lebar, ~40-90px tinggi)
    if w < 20 or w > 160 or h < 20 or h > 100 then return false end
    -- Posisi dekat toolbar (Y < 25% layar)
    local scrH = StudioGui.AbsoluteSize.Y
    if obj.AbsolutePosition.Y > scrH * 0.30 then return false end
    -- Harus punya anak TextLabel berisi angka
    local hasNum = false
    for _, ch in ipairs(obj:GetDescendants()) do
        if ch:IsA("TextLabel") or ch:IsA("TextBox") then
            local t = ch.Text or ""
            if t:match("^%s*%-?%d+%.?%d*%s*$") then hasNum = true; break end
        end
    end
    return hasNum
end

local function styleSnapPopup(obj)
    if themedPopups[obj] then return end
    themedPopups[obj] = true

    pcall(function()
        -- Background gelap premium
        obj.BackgroundColor3     = C.bg2
        obj.BackgroundTransparency = 0
        obj.BorderSizePixel      = 0

        -- Corner radius
        local uc = obj:FindFirstChildOfClass("UICorner") or Instance.new("UICorner")
        uc.CornerRadius = UDim.new(0, 6)
        uc.Parent = obj

        -- Border accent biru
        local us = obj:FindFirstChildOfClass("UIStroke") or Instance.new("UIStroke")
        us.Color       = C.accB
        us.Thickness   = 1
        us.Transparency = 0.35
        us.Parent = obj

        -- Theme semua descendant
        for _, ch in ipairs(obj:GetDescendants()) do
            pcall(function()
                if isOwn(ch) then return end

                if ch:IsA("Frame") then
                    ch.BackgroundColor3     = C.bg2
                    ch.BackgroundTransparency = 0
                    ch.BorderSizePixel      = 0
                end

                if ch:IsA("TextLabel") or ch:IsA("TextBox") then
                    local t = ch.Text or ""
                    local isNum = t:match("^%s*%-?%d+%.?%d*%s*$")
                    ch.BackgroundColor3       = C.bg3
                    ch.BackgroundTransparency = isNum and 0 or 1
                    ch.BorderSizePixel        = 0
                    ch.TextColor3             = isNum and C.accA or C.txtS
                    ch.Font                   = isNum and Enum.Font.GothamBold or Enum.Font.Gotham
                    ch.TextSize               = isNum and 11 or 9
                    ch.TextXAlignment         = Enum.TextXAlignment.Center

                    if isNum then
                        -- Box angka: corner + micro border
                        local uc2 = ch:FindFirstChildOfClass("UICorner") or Instance.new("UICorner")
                        uc2.CornerRadius = UDim.new(0, 4); uc2.Parent = ch
                        local us2 = ch:FindFirstChildOfClass("UIStroke") or Instance.new("UIStroke")
                        us2.Color = C.accB; us2.Thickness = 1; us2.Transparency = 0.5; us2.Parent = ch
                    end
                end
            end)
        end

        -- Watcher: kalau Studio Lite reset bg popup ini → kita paksa dark lagi
        obj:GetPropertyChangedSignal("BackgroundColor3"):Connect(function()
            task.defer(function()
                pcall(function()
                    if not isOwn(obj) then
                        obj.BackgroundColor3     = C.bg2
                        obj.BackgroundTransparency = 0
                    end
                end)
            end)
        end)
    end)
end

local function scanAndStylePopups()
    for _, obj in ipairs(StudioGui:GetDescendants()) do
        if isSnapPopup(obj) then
            pcall(styleSnapPopup, obj)
        end
    end
end

local function startSnapPopupWatcher()
    -- Scan semua yang sudah ada
    pcall(scanAndStylePopups)
    -- Watch descendant baru — popup biasanya muncul saat hover
    StudioGui.DescendantAdded:Connect(function(obj)
        task.defer(function()
            -- Cek obj itu sendiri
            if isSnapPopup(obj) then pcall(styleSnapPopup, obj); return end
            -- Cek parent (mungkin child masuk lebih dulu)
            local p = obj.Parent
            if p and isSnapPopup(p) then pcall(styleSnapPopup, p) end
        end)
    end)
end

-- ══════════════════════════════════════════════
--  SCROLLBAR
-- ══════════════════════════════════════════════
local function styleScrollbars()
    for _,obj in ipairs(StudioGui:GetDescendants()) do
        if obj:IsA("ScrollingFrame") and not isOwn(obj) then
            pcall(function()
                obj.ScrollBarThickness=3
                obj.ScrollBarImageColor3=C.accB
            end)
        end
    end
end

-- ══════════════════════════════════════════════
--  HOVER EFFECT (v3.9 tween)
-- ══════════════════════════════════════════════
local hovered = {}
local function applyHover(obj)
    if hovered[obj] then return end
    if isOwn(obj) then return end
    if not (obj:IsA("TextButton") or obj:IsA("ImageButton")) then return end
    -- Jangan terapkan hover pada tombol Select Multi
    local nm = obj.Name:lower()
    if nm:find("selectmulti") or nm:find("select_multi")
       or (nm:find("select") and nm:find("multi")) then return end
    local function setup()
        local sz=obj.AbsoluteSize
        if sz.X>240 or sz.Y>90 then return end
        hovered[obj]=true
        pcall(function() obj.Active=true end)
        pcall(function() obj.AutoButtonColor=false end)
        obj.MouseEnter:Connect(function()
            pcall(function()
                tw(obj,FAST,{BackgroundTransparency=0.84,BackgroundColor3=C.bg4})
                local s=obj:FindFirstChildOfClass("UIStroke") or Instance.new("UIStroke")
                s.Color=C.bdrB; s.Thickness=1; s.Transparency=0.3; s.Parent=obj
            end)
        end)
        obj.MouseLeave:Connect(function()
            pcall(function()
                tw(obj,FAST,{BackgroundTransparency=1})
                local s=obj:FindFirstChildOfClass("UIStroke")
                if s then s:Destroy() end
            end)
        end)
    end
    if obj.AbsoluteSize.X>0 then setup()
    else
        local conn
        conn=obj:GetPropertyChangedSignal("AbsoluteSize"):Connect(function()
            conn:Disconnect(); setup()
        end)
    end
end
local function applyHoverAll()
    for _,obj in ipairs(StudioGui:GetDescendants()) do pcall(applyHover,obj) end
end

-- ══════════════════════════════════════════════
--  PANEL DECORATION (v3.9)
-- ══════════════════════════════════════════════
local decorated = {}
local function addAccent(frame, side, name)
    if frame:FindFirstChild(name) then return end
    local bar=Instance.new("Frame"); bar.Name=name
    bar.Size=(side=="left") and UDim2.new(0,2,1,0) or UDim2.new(0,2,1,0)
    bar.Position=(side=="left") and UDim2.new(0,0,0,0) or UDim2.new(1,-2,0,0)
    bar.BackgroundColor3=C.accB; bar.BorderSizePixel=0
    bar.BackgroundTransparency=0.25
    bar.ZIndex=(frame.ZIndex or 1)+15; bar.Parent=frame
    gradient(bar,Color3.fromRGB(40,100,230),Color3.fromRGB(20,55,140),180)
    corner(bar,2)
end
local function addTBDiv(tb)
    if tb:FindFirstChild(PFX.."TBDiv") then return end
    local d=Instance.new("Frame"); d.Name=PFX.."TBDiv"
    d.Size=UDim2.new(1,0,0,1); d.Position=UDim2.new(0,0,1,0)
    d.BackgroundColor3=C.bdrB; d.BorderSizePixel=0
    d.BackgroundTransparency=0.55
    d.ZIndex=(tb.ZIndex or 1)+8; d.Parent=tb
end
local function addHLine(frame)
    if frame:FindFirstChild(PFX.."HLine") then return end
    local l=Instance.new("Frame"); l.Name=PFX.."HLine"
    l.Size=UDim2.new(1,0,0,1); l.Position=UDim2.new(0,0,1,-1)
    l.BackgroundColor3=C.bdrB; l.BorderSizePixel=0
    l.BackgroundTransparency=0.4
    l.ZIndex=(frame.ZIndex or 1)+5; l.Parent=frame
end
local function decoratePanels()
    local scrH=StudioGui.AbsoluteSize.Y; local scrW=StudioGui.AbsoluteSize.X
    for _,obj in ipairs(StudioGui:GetDescendants()) do
        if isOwn(obj) then continue end
        if decorated[obj] then continue end
        if not (obj:IsA("Frame") or obj:IsA("ScrollingFrame")) then continue end
        pcall(function()
            local n=obj.Name:lower()
            local absH=obj.AbsoluteSize.Y; local absW=obj.AbsoluteSize.X
            if n:find("toolbar") or n:find("topbar") then
                obj.BackgroundColor3=C.tbBg; addTBDiv(obj); decorated[obj]=true  -- #1c1c1c menubar
            end
            if (n:find("explorer") or n:find("property") or n:find("dockright"))
               and absH>scrH*0.2 and absW<scrW*0.5 then
                obj.BackgroundColor3=C.bg1                                        -- #242424 panel
                addAccent(obj,"left",PFX.."RAccent"); decorated[obj]=true
            end
            if (n:find("sidebar") or n:find("iconbar") or n:find("leftsidebar"))
               and absW<110 and absH>scrH*0.3 then
                obj.BackgroundColor3=C.bg1                                        -- #242424 sidebar
                addAccent(obj,"right",PFX.."LAccent"); decorated[obj]=true
            end
            if n:find("header") or n:find("titlebar") or n:find("paneltop") then
                obj.BackgroundColor3=C.bg0; addHLine(obj); decorated[obj]=true   -- #1a1a1a header
            end
        end)
    end
end

-- ══════════════════════════════════════════════
--  ICON DRAW (v2.0 drawSeg style, warna dari v3.9)
-- ══════════════════════════════════════════════
local function drawSeg(p, x1,y1, x2,y2, T, col, zi)
    local dx,dy=x2-x1,y2-y1
    local len=math.sqrt(dx*dx+dy*dy)
    if len<0.5 then return end
    local f=Instance.new("Frame"); f.Name=PFX.."Ico"
    f.Size=UDim2.new(0,math.ceil(len),0,T)
    f.Position=UDim2.new(0,math.floor((x1+x2)/2-len/2),0,math.floor((y1+y2)/2-T/2))
    f.Rotation=math.deg(math.atan2(dy,dx))
    f.BackgroundColor3=col or C.txtP
    f.BorderSizePixel=0; f.ZIndex=zi or 6; f.Parent=p
    local u=Instance.new("UICorner"); u.CornerRadius=UDim.new(0,1); u.Parent=f
end

-- ══════════════════════════════════════════════
--  RENDER HELPERS v6.1 — fill primitives untuk icon Studio-PC style
-- ══════════════════════════════════════════════
local function _fillRect(p, x, y, w, h, col, zi, smooth)
    if w < 1 then w = 1 end
    if h < 1 then h = 1 end
    local f = Instance.new("Frame")
    f.Name                   = PFX.."Ico"
    f.Size                   = UDim2.new(0, math.ceil(w), 0, math.ceil(h))
    f.Position               = UDim2.new(0, math.floor(x), 0, math.floor(y))
    f.BackgroundColor3       = col or C.txtP
    f.BorderSizePixel        = 0
    f.ZIndex                 = zi or 46
    f.Parent                 = p
    if smooth then
        local u = Instance.new("UICorner")
        u.CornerRadius = UDim.new(0, 1)
        u.Parent = f
    end
    return f
end

local function _fillCircle(p, cx, cy, rx, ry, col, zi)
    if rx < 1 then rx = 1 end
    if ry < 1 then ry = 1 end
    local f = Instance.new("Frame")
    f.Name                   = PFX.."Ico"
    f.Size                   = UDim2.new(0, math.ceil(rx*2), 0, math.ceil(ry*2))
    f.Position               = UDim2.new(0, math.floor(cx-rx), 0, math.floor(cy-ry))
    f.BackgroundColor3       = col or C.txtP
    f.BorderSizePixel        = 0
    f.ZIndex                 = zi or 46
    f.Parent                 = p
    local u = Instance.new("UICorner")
    u.CornerRadius = UDim.new(1, 0)
    u.Parent = f
    return f
end

local function _fillTri(p, x1, y1, x2, y2, x3, y3, col, zi)
    local minY = math.min(y1, y2, y3)
    local maxY = math.max(y1, y2, y3)
    local steps = math.max(4, math.ceil((maxY - minY) * 1.4))
    if steps > 48 then steps = 48 end
    local function interp(yA, xA, yB, xB, y)
        if math.abs(yB - yA) < 0.001 then return xA end
        return xA + (xB - xA) * ((y - yA) / (yB - yA))
    end
    for i = 0, steps do
        local y = minY + (maxY - minY) * (i / steps)
        local xs = {}
        if (y1 <= y and y2 >= y) or (y1 >= y and y2 <= y) then
            table.insert(xs, interp(y1, x1, y2, x2, y))
        end
        if (y2 <= y and y3 >= y) or (y2 >= y and y3 <= y) then
            table.insert(xs, interp(y2, x2, y3, x3, y))
        end
        if (y1 <= y and y3 >= y) or (y1 >= y and y3 <= y) then
            table.insert(xs, interp(y1, x1, y3, x3, y))
        end
        if #xs >= 2 then
            local xL = math.min(unpack(xs))
            local xR = math.max(unpack(xs))
            _fillRect(p, xL, y, xR - xL + 1, math.ceil((maxY - minY) / steps) + 1, col, zi or 46)
        end
    end
end

local function _fillQuad(p, x1, y1, x2, y2, x3, y3, x4, y4, col, zi)
    _fillTri(p, x1, y1, x2, y2, x3, y3, col, zi)
    _fillTri(p, x1, y1, x3, y3, x4, y4, col, zi)
end

local function _fillRing(p, cx, cy, rOut, rIn, col, bgCol, zi)
    _fillCircle(p, cx, cy, rOut, rOut, col, zi or 46)
    _fillCircle(p, cx, cy, rIn,  rIn,  bgCol, (zi or 46) + 1)
end

local function _arc(p, cx, cy, rx, ry, a0, a1, n, T, col, zi)
    n = math.max(8, n or 16)
    local da = (a1 - a0) / n
    for i = 0, n - 1 do
        local x1 = cx + math.cos(a0 + da * i)     * rx
        local y1 = cy + math.sin(a0 + da * i)     * ry
        local x2 = cx + math.cos(a0 + da * (i+1)) * rx
        local y2 = cy + math.sin(a0 + da * (i+1)) * ry
        drawSeg(p, x1, y1, x2, y2, T, col, zi)
    end
end

-- ══════════════════════════════════════════════
--  PALETTE — Studio PC clean look
-- ══════════════════════════════════════════════
local function _mix(a, b, t)
    return Color3.new(
        a.R + (b.R - a.R) * t,
        a.G + (b.G - a.G) * t,
        a.B + (b.B - a.B) * t
    )
end

local SHA = {
    hi    = _mix(C.accA, Color3.new(1,1,1), 0.50),
    lite  = _mix(C.accA, Color3.new(1,1,1), 0.22),
    base  = C.accA,
    mid   = _mix(C.accA, Color3.new(0,0,0), 0.22),
    dark  = _mix(C.accA, Color3.new(0,0,0), 0.45),
    deep  = _mix(C.accA, Color3.new(0,0,0), 0.65),
    rim   = _mix(C.accA, Color3.new(1,1,1), 0.70),
    shdw  = Color3.fromRGB(0, 0, 0),
}
local GRN = {
    hi    = _mix(C.green, Color3.new(1,1,1), 0.45),
    lite  = _mix(C.green, Color3.new(1,1,1), 0.18),
    base  = C.green,
    dark  = _mix(C.green, Color3.new(0,0,0), 0.28),
    deep  = _mix(C.green, Color3.new(0,0,0), 0.55),
    rim   = _mix(C.green, Color3.new(1,1,1), 0.65),
}
local MET = {
    hi    = Color3.fromRGB(245,245,250),
    lite  = Color3.fromRGB(210,215,225),
    base  = Color3.fromRGB(170,178,190),
    mid   = Color3.fromRGB(120,130,145),
    dark  = Color3.fromRGB( 70, 78, 92),
    deep  = Color3.fromRGB( 35, 40, 50),
}

-- ══════════════════════════════════════════════
--  SHAPE ICONS v6.1 — Studio PC style (clean 3D)
--  Silhouette tegas, shading 2-tier, outline tipis
-- ══════════════════════════════════════════════

-- ① BALOK — kubus isometrik
local function icoBlock(p, S, T)
    local cx    = math.floor(S * 0.50)
    local xL    = math.floor(S * 0.12)
    local xR    = math.ceil (S * 0.88)
    local yT    = math.floor(S * 0.14)
    local yMid  = math.floor(S * 0.36)
    local yMidB = math.ceil (S * 0.64)
    local yB    = math.ceil (S * 0.86)
    local yRsd  = yB - (yMid - yT)

    -- TOP face (paling terang)
    _fillQuad(p, cx, yT, xR, yMid, cx, yMidB, xL, yMid, SHA.lite, 46)
    -- RIGHT face (medium)
    _fillQuad(p, xR, yMid, xR, yRsd, cx, yB, cx, yMidB, SHA.mid, 46)
    -- LEFT face (gelap)
    _fillQuad(p, xL, yMid, cx, yMidB, cx, yB, xL, yRsd, SHA.dark, 46)
    -- Outline tegas (tipis, krisp)
    drawSeg(p, cx, yT,    xR, yMid,  1, SHA.deep, 49)
    drawSeg(p, xR, yMid,  cx, yMidB, 1, SHA.deep, 49)
    drawSeg(p, cx, yMidB, xL, yMid,  1, SHA.deep, 49)
    drawSeg(p, xL, yMid,  cx, yT,    1, SHA.deep, 49)
    drawSeg(p, cx, yMidB, cx, yB,    1, SHA.deep, 49)
    drawSeg(p, xL, yMid,  xL, yRsd,  1, SHA.deep, 49)
    drawSeg(p, xR, yMid,  xR, yRsd,  1, SHA.deep, 49)
    drawSeg(p, xL, yRsd,  cx, yB,    1, SHA.deep, 49)
    drawSeg(p, xR, yRsd,  cx, yB,    1, SHA.deep, 49)
end

-- ② BOLA — sphere clean
local function icoBall(p, S, T)
    local cx, cy = S/2, S/2
    local r      = math.floor(S * 0.40)
    -- Outline rim
    _fillCircle(p, cx, cy, r + 1, r + 1, SHA.deep, 45)
    -- Body
    _fillCircle(p, cx, cy, r, r, SHA.base, 46)
    -- Shading bawah-kanan
    _fillCircle(p, cx + r*0.10, cy + r*0.10, r*0.92, r*0.92, SHA.mid, 47)
    -- Body atas-kiri
    _fillCircle(p, cx - r*0.12, cy - r*0.12, r*0.78, r*0.78, SHA.base, 48)
    -- Highlight
    _fillCircle(p, cx - r*0.30, cy - r*0.30, r*0.42, r*0.30, SHA.lite, 49)
    _fillCircle(p, cx - r*0.38, cy - r*0.38, r*0.18, r*0.14, SHA.hi, 50)
    -- Specular
    _fillCircle(p, cx - r*0.42, cy - r*0.42, math.max(1, r*0.06), math.max(1, r*0.06), Color3.new(1,1,1), 51)
end

-- ③ SILINDER — cylinder 3D bersih
local function icoCylinder(p, S, T)
    local cx  = math.floor(S * 0.50)
    local rx  = math.floor(S * 0.32)
    local ry  = math.max(2, math.floor(S * 0.10))
    local yT  = math.floor(S * 0.18)
    local yB  = math.ceil (S * 0.82)
    local h   = yB - yT

    -- Body 3-strip (gelap kiri, base, lite kanan)
    _fillRect(p, cx - rx,             yT, math.ceil(rx*0.40), h, SHA.dark, 46)
    _fillRect(p, cx - rx + math.ceil(rx*0.40), yT, math.ceil(rx*0.70), h, SHA.base, 47)
    _fillRect(p, cx + math.ceil(rx*0.10), yT, math.ceil(rx*0.90), h, SHA.mid,  47)
    -- Highlight stripe
    _fillRect(p, cx - math.ceil(rx*0.12), yT + ry, math.max(1, math.floor(S*0.07)), h - ry*2, SHA.lite, 48)

    -- BOTTOM ellipse (gelap)
    _fillCircle(p, cx, yB, rx, ry, SHA.dark, 48)
    -- TOP ellipse
    _fillCircle(p, cx, yT, rx, ry, SHA.lite, 49)
    _fillCircle(p, cx - rx*0.08, yT - ry*0.08, rx*0.88, ry*0.78, SHA.hi, 50)

    -- Outline edges (tipis)
    drawSeg(p, cx - rx, yT, cx - rx, yB, 1, SHA.deep, 50)
    drawSeg(p, cx + rx, yT, cx + rx, yB, 1, SHA.deep, 50)
    _arc(p, cx, yT, rx, ry, 0, math.pi*2, 22, 1, SHA.deep, 51)
    _arc(p, cx, yB, rx, ry, 0, math.pi,    18, 1, SHA.deep, 51)
end

-- ④ WEDGE — triangular prism bersih
local function icoWedge(p, S, T)
    local x0 = math.floor(S * 0.12)
    local x1 = math.ceil (S * 0.74)
    local yT = math.floor(S * 0.18)
    local yB = math.ceil (S * 0.84)
    local dx = math.floor(S * 0.16)
    local dy = math.floor(S * 0.10)
    -- TOP slope face
    _fillQuad(p, x0, yT, x0 + dx, yT - dy, x1 + dx, yB - dy, x1, yB, SHA.mid, 46)
    -- RIGHT side (segitiga gelap)
    _fillTri(p, x1, yB, x1 + dx, yB - dy, x1, yT + math.floor((yB-yT)*0.40), SHA.dark, 47)
    -- FRONT triangle face (lite)
    _fillTri(p, x0, yT, x1, yB, x0, yB, SHA.lite, 47)

    -- Outline edges
    drawSeg(p, x0, yT, x1, yB, 1, SHA.deep, 50)
    drawSeg(p, x0, yT, x0, yB, 1, SHA.deep, 50)
    drawSeg(p, x0, yB, x1, yB, 1, SHA.deep, 50)
    drawSeg(p, x0, yT, x0 + dx, yT - dy, 1, SHA.deep, 50)
    drawSeg(p, x0 + dx, yT - dy, x1 + dx, yB - dy, 1, SHA.deep, 50)
    drawSeg(p, x1 + dx, yB - dy, x1, yB, 1, SHA.deep, 50)
end

-- ⑤ CORNER WEDGE — corner ramp clean
local function icoCorner(p, S, T)
    local xL = math.floor(S * 0.14)
    local xR = math.ceil (S * 0.78)
    local yT = math.floor(S * 0.18)
    local yB = math.ceil (S * 0.86)
    local dx = math.floor(S * 0.14)
    local dy = math.floor(S * 0.12)
    -- TOP slope (mid)
    _fillTri(p, xL, yT, xL + dx, yT - dy, xR + dx, yB - dy, SHA.mid, 46)
    _fillTri(p, xL, yT, xR + dx, yB - dy, xR, yB, SHA.mid, 46)
    -- RIGHT side (gelap)
    _fillTri(p, xR, yB, xR + dx, yB - dy, xR, yB - math.ceil((yB-yT)*0.35), SHA.dark, 47)
    -- FRONT (lite)
    _fillTri(p, xL, yT, xR, yB, xL, yB, SHA.lite, 47)

    -- Outline edges
    drawSeg(p, xL, yT, xR, yB, 1, SHA.deep, 50)
    drawSeg(p, xL, yT, xL, yB, 1, SHA.deep, 50)
    drawSeg(p, xL, yT, xL + dx, yT - dy, 1, SHA.deep, 50)
    drawSeg(p, xL, yB, xR, yB, 1, SHA.deep, 50)
    drawSeg(p, xR, yB, xR + dx, yB - dy, 1, SHA.deep, 50)
    drawSeg(p, xL + dx, yT - dy, xR + dx, yB - dy, 1, SHA.deep, 50)
end

-- ⑥ TERRAIN — gunung
local function icoTerrain(p, S, T)
    local sc = S / 24
    local pts = {{3,20},{9,8},{13,16},{16,11},{21,20},{3,20}}
    for i = 1, #pts - 1 do
        drawSeg(p, pts[i][1]*sc, pts[i][2]*sc, pts[i+1][1]*sc, pts[i+1][2]*sc, T, C.accA, 46)
    end
    drawSeg(p, 2, S-4, S-2, S-4, T, C.txtS, 45)
end


-- ══════════════════════════════════════════════
--  TOOLBAR HELPERS
-- ══════════════════════════════════════════════
local cachedTB = nil
local function findToolbar()
    if cachedTB and cachedTB.Parent then return cachedTB end
    -- Prioritas 1: cari MainBar langsung (nama persis dari GuiCopy)
    local mb = StudioGui:FindFirstChild("MainBar")
    if mb and mb:IsA("Frame") and mb.AbsoluteSize.X > 150 then
        cachedTB = mb; return mb
    end
    -- Prioritas 2: scan button bawaan yang namanya persis (dari GuiCopy)
    for _, nm in ipairs({"select","move","scale","rotate","play","toolbox"}) do
        local btn = StudioGui:FindFirstChild(nm, true)
        if btn and btn.Parent and btn.Parent:IsA("Frame")
           and btn.Parent.AbsoluteSize.X > 150 then
            cachedTB = btn.Parent; return btn.Parent
        end
    end
    -- Prioritas 3: fallback scan lama
    for _,obj in ipairs(StudioGui:GetDescendants()) do
        if obj:IsA("TextButton") or obj:IsA("ImageButton") then
            local n=obj.Name:lower()
            if n:find("play") or n:find("select") or n:find("pilih") or n:find("toolbox") then
                local p=obj.Parent
                if p and (p:IsA("Frame") or p:IsA("ScrollingFrame"))
                   and p.AbsoluteSize.X>150 then
                    cachedTB=p; return p
                end
            end
        end
    end
    return nil
end
local function getMaxX(tb)
    local mx=0
    for _,ch in ipairs(tb:GetChildren()) do
        if ch:IsA("GuiObject")
           and not ch:IsA("UIListLayout") and not ch:IsA("UICorner")
           and not ch:IsA("UIStroke")     and not ch:IsA("UIGradient") then
            pcall(function()
                local x=(ch.AbsolutePosition.X-tb.AbsolutePosition.X)+ch.AbsoluteSize.X
                if x>mx then mx=x end
            end)
        end
    end
    return mx
end
local function makeSep(tb, posX)
    local H=tb.AbsoluteSize.Y
    local sep=Instance.new("Frame"); sep.Name=PFX.."Sep"
    sep.Size=UDim2.new(0,1,0,math.floor(H*0.5))
    sep.Position=UDim2.new(0,posX+4,0,math.floor(H*0.25))
    sep.BackgroundColor3=C.bdrB; sep.BackgroundTransparency=0.4
    sep.BorderSizePixel=0; sep.ZIndex=5; sep.Parent=tb
end

-- ══════════════════════════════════════════════
--  INJECT BUTTONS (arsitektur v2.0 — cont/iconF/lbl/btn)
--  Hover: langsung set properti (bukan tween) seperti v2.0
--  ZERO selection manipulation
-- ══════════════════════════════════════════════
local function makePartBtn(tb, posX, label, icoFn, onClick)
    local H=tb.AbsoluteSize.Y
    local S=22; local T=2; local W=44
    local btnH=math.min(H-6,42)
    local padY=math.max(3,math.floor((btnH-S-14)/2))

    local cont=Instance.new("Frame"); cont.Name=PFX.."Btn_"..label
    cont.Size=UDim2.new(0,W,0,btnH)
    cont.Position=UDim2.new(0,posX,0,math.floor((H-btnH)/2))
    cont.BackgroundTransparency=1; cont.BorderSizePixel=0
    cont.ClipsDescendants=false; cont.ZIndex=5; cont.Active=true
    cont.Parent=tb; corner(cont,8)

    local icoF=Instance.new("Frame"); icoF.Name=PFX.."IcoF_"..label
    icoF.Size=UDim2.new(0,S,0,S)
    icoF.Position=UDim2.new(0,W/2-S/2,0,padY)
    icoF.BackgroundTransparency=1; icoF.ClipsDescendants=false
    icoF.ZIndex=6; icoF.Parent=cont
    pcall(icoFn,icoF,S,T)

    local lbl=Instance.new("TextLabel"); lbl.Name=PFX.."Lbl_"..label
    lbl.Size=UDim2.new(0,W,0,10)
    lbl.Position=UDim2.new(0,0,0,padY+S+2)
    lbl.BackgroundTransparency=1; lbl.Text=label:upper()
    lbl.TextColor3=C.txtD; lbl.TextSize=7
    lbl.Font=Enum.Font.GothamBold
    lbl.TextXAlignment=Enum.TextXAlignment.Center
    lbl.ZIndex=6; lbl.Parent=cont

    local btn=Instance.new("TextButton"); btn.Name=PFX.."Click_"..label
    btn.Size=UDim2.new(1,0,1,0); btn.BackgroundTransparency=1
    btn.Text=""; btn.ZIndex=7; btn.Active=true
    btn.AutoButtonColor=false; btn.Parent=cont

    -- Hover (v2.0 style — langsung set, tidak tween)
    btn.MouseEnter:Connect(function()
        pcall(function()
            cont.BackgroundColor3=C.bg4; cont.BackgroundTransparency=0
            stroke(cont,C.bdrB,1,0); lbl.TextColor3=C.txtS
        end)
    end)
    btn.MouseLeave:Connect(function()
        pcall(function()
            cont.BackgroundTransparency=1; lbl.TextColor3=C.txtD
            local s=cont:FindFirstChildOfClass("UIStroke")
            if s then s.Thickness=0 end
        end)
    end)
    btn.MouseButton1Down:Connect(function()
        pcall(function()
            cont.BackgroundColor3=C.accC; cont.BackgroundTransparency=0
        end)
    end)
    btn.MouseButton1Up:Connect(function()
        pcall(function()
            cont.BackgroundColor3=C.bg4; cont.BackgroundTransparency=0
        end)
    end)
    btn.MouseButton1Click:Connect(function()
        pcall(onClick)
    end)

    return cont, W
end

-- ══════════════════════════════════════════════
--  INSERT PART — logika v2.0 (ZERO selection touch)
--  ★ AUTO-FOLDER: tiap part masuk ke folder Workspace bernama
--    sesuai jenisnya (Balok / Bola / Silinder / Wedge / Corner)
--  ★ TOGGLE  : AUTO_FOLDER_PARTS_ENABLED (lihat panel CONVERT)
--    Kalau OFF, part langsung jadi child Workspace (perilaku
--    normal Roblox), tanpa bikin folder.
-- ══════════════════════════════════════════════
AUTO_FOLDER_PARTS_ENABLED = false  -- global, dipakai juga oleh panel (default OFF)
local function insertPart(partType, partName)
    pcall(function()
        local cam=Workspace.CurrentCamera
        local spawnCF=CFrame.new(0,5,0)
        if cam then
            local cf=cam.CFrame
            local fwd=Vector3.new(cf.LookVector.X,0,cf.LookVector.Z)
            if fwd.Magnitude>0.01 then fwd=fwd.Unit else fwd=Vector3.new(0,0,-1) end
            local pos=cf.Position+fwd*18
            spawnCF=CFrame.new(pos.X,math.max(pos.Y,3),pos.Z)
        end
        local part
        if     partType=="Block"       then part=Instance.new("Part");           part.Shape=Enum.PartType.Block
        elseif partType=="Ball"        then part=Instance.new("Part");           part.Shape=Enum.PartType.Ball
        elseif partType=="Cylinder"    then part=Instance.new("Part");           part.Shape=Enum.PartType.Cylinder
        elseif partType=="Wedge"       then part=Instance.new("WedgePart")
        elseif partType=="CornerWedge" then part=Instance.new("CornerWedgePart")
        else                                part=Instance.new("Part") end
        part.Size=Vector3.new(4,1.2,2); part.CFrame=spawnCF
        part.Anchored=true; part.Material=Enum.Material.SmoothPlastic
        part.Color=Color3.fromRGB(163,162,165)

        local folderName = partName or "Parts"
        part.Name = folderName

        if AUTO_FOLDER_PARTS_ENABLED then
            -- ✅ Auto-folder berdasar jenis part
            local folder = Workspace:FindFirstChild(folderName)
            if not folder or not folder:IsA("Folder") then
                folder = Instance.new("Folder")
                folder.Name   = folderName
                folder.Parent = Workspace
            end
            part.Parent = folder
        else
            -- ✅ Mode normal: langsung di Workspace (tanpa folder)
            part.Parent = Workspace
        end
        -- ✅ TIDAK ada sel:Set() — Selection service tidak disentuh

    end)
end

-- ══════════════════════════════════════════════
--  INJECT PART BUTTONS (arsitektur v2.0)
-- ══════════════════════════════════════════════
local partDone = false
local PARTS = {
    {name="Balok",    ico=icoBlock,    type="Block"},
    {name="Bola",     ico=icoBall,     type="Ball"},
    {name="Silinder", ico=icoCylinder, type="Cylinder"},
    {name="Wedge",    ico=icoWedge,    type="Wedge"},
    {name="Corner",   ico=icoCorner,   type="CornerWedge"},
}
local function injectParts()
    if partDone then return end
    local tb=findToolbar(); if not tb then return end
    if tb:FindFirstChild(PFX.."Btn_Balok") then partDone=true; return end
    for _,ch in ipairs(tb:GetChildren()) do
        local n=ch.Name:lower()
        if n:find("part") or n:find("insert") then
            pcall(function()
                ch.Visible=false
                for _,d in ipairs(ch:GetDescendants()) do
                    if d:IsA("GuiObject") then d.Visible=false end
                end
            end)
        end
    end
    local GAP=3; local curX=getMaxX(tb)+16; makeSep(tb,curX-12)
    for _,def in ipairs(PARTS) do
        local _,W=makePartBtn(tb,curX,def.name,def.ico,function() insertPart(def.type, def.name) end)
        curX=curX+W+GAP
    end
    partDone=true
end

-- ══════════════════════════════════════════════
--  NATIVE ICON SET v6.1 — STUDIO PC LOOK
--  Bentuk lebih clear, outline lebih bersih, mirip Studio asli
-- ══════════════════════════════════════════════

-- ⑦ SELECT — cursor putih klasik dengan outline tegas (Windows pointer)
local function icoNatSelect(p, S, T)
    -- 7 titik cursor
    local Ax, Ay = S*0.18, S*0.08    -- tip atas
    local Bx, By = S*0.78, S*0.58    -- ujung diagonal kanan-bawah
    local Cx, Cy = S*0.50, S*0.58    -- notch dalam
    local Dx, Dy = S*0.62, S*0.92    -- ekor kanan
    local Ex, Ey = S*0.46, S*0.96    -- ekor kanan-bawah
    local Fx, Fy = S*0.34, S*0.66    -- notch ekor
    local Gx, Gy = S*0.18, S*0.80    -- ujung kiri-bawah

    -- Body cursor (PUTIH terang)
    local WHT = Color3.fromRGB(245, 248, 252)
    _fillTri(p, Ax, Ay, Bx, By, Gx, Gy, WHT, 46)
    _fillTri(p, Bx, By, Cx, Cy, Fx, Fy, WHT, 46)
    _fillTri(p, Bx, By, Fx, Fy, Gx, Gy, WHT, 46)
    _fillQuad(p, Cx, Cy, Dx, Dy, Ex, Ey, Fx, Fy, WHT, 46)

    -- Subtle shadow di sisi kanan-bawah (depth)
    drawSeg(p, Bx-1, By, Cx+1, Cy, math.max(2, T), Color3.fromRGB(180,190,205), 47)
    drawSeg(p, Dx-1, Dy-1, Ex+1, Ey-1, math.max(1, T-1), Color3.fromRGB(180,190,205), 47)

    -- Outline tegas hitam pekat (krisp 1px)
    drawSeg(p, Ax, Ay, Bx, By, 1, SHA.shdw, 49)
    drawSeg(p, Bx, By, Cx, Cy, 1, SHA.shdw, 49)
    drawSeg(p, Cx, Cy, Dx, Dy, 1, SHA.shdw, 49)
    drawSeg(p, Dx, Dy, Ex, Ey, 1, SHA.shdw, 49)
    drawSeg(p, Ex, Ey, Fx, Fy, 1, SHA.shdw, 49)
    drawSeg(p, Fx, Fy, Gx, Gy, 1, SHA.shdw, 49)
    drawSeg(p, Gx, Gy, Ax, Ay, 1, SHA.shdw, 49)
end

-- ⑧ MOVE — 4-arrow gizmo Studio style
local function icoNatMove(p, S, T)
    local cx, cy = S/2, S/2
    local th  = math.max(2, math.floor(S * 0.12))   -- tebal arm tipis
    local arm = math.floor(S * 0.34)                 -- panjang arm
    local hd  = math.floor(S * 0.18)                 -- lebar arrowhead
    local hl  = math.floor(S * 0.16)                 -- panjang arrowhead

    -- Body cross (biru solid)
    _fillRect(p, cx - arm,  cy - th/2, arm*2, th, SHA.base, 46)
    _fillRect(p, cx - th/2, cy - arm,  th, arm*2, SHA.base, 46)

    -- 4 Arrowheads
    _fillTri(p, cx + arm, cy - hd, cx + arm + hl, cy, cx + arm, cy + hd, SHA.base, 47)
    _fillTri(p, cx - arm, cy - hd, cx - arm - hl, cy, cx - arm, cy + hd, SHA.base, 47)
    _fillTri(p, cx - hd, cy - arm, cx, cy - arm - hl, cx + hd, cy - arm, SHA.base, 47)
    _fillTri(p, cx - hd, cy + arm, cx, cy + arm + hl, cx + hd, cy + arm, SHA.base, 47)

    -- Highlight 1px (sisi atas arm horizontal & sisi kiri arm vertical)
    _fillRect(p, cx - arm,  cy - th/2,    arm*2, 1, SHA.lite, 48)
    _fillRect(p, cx - th/2, cy - arm,     1, arm*2, SHA.lite, 48)

    -- Outline tegas (rim) - 1px
    drawSeg(p, cx - arm, cy - th/2, cx + arm, cy - th/2, 1, SHA.deep, 49)
    drawSeg(p, cx - arm, cy + th/2, cx + arm, cy + th/2, 1, SHA.deep, 49)
    drawSeg(p, cx - th/2, cy - arm, cx - th/2, cy + arm, 1, SHA.deep, 49)
    drawSeg(p, cx + th/2, cy - arm, cx + th/2, cy + arm, 1, SHA.deep, 49)
    -- Outline arrowheads
    drawSeg(p, cx + arm, cy - hd, cx + arm + hl, cy, 1, SHA.deep, 49)
    drawSeg(p, cx + arm, cy + hd, cx + arm + hl, cy, 1, SHA.deep, 49)
    drawSeg(p, cx - arm, cy - hd, cx - arm - hl, cy, 1, SHA.deep, 49)
    drawSeg(p, cx - arm, cy + hd, cx - arm - hl, cy, 1, SHA.deep, 49)
    drawSeg(p, cx - hd, cy - arm, cx, cy - arm - hl, 1, SHA.deep, 49)
    drawSeg(p, cx + hd, cy - arm, cx, cy - arm - hl, 1, SHA.deep, 49)
    drawSeg(p, cx - hd, cy + arm, cx, cy + arm + hl, 1, SHA.deep, 49)
    drawSeg(p, cx + hd, cy + arm, cx, cy + arm + hl, 1, SHA.deep, 49)

    -- Pivot tengah (titik referensi)
    local pr = math.max(1, math.floor(S * 0.06))
    _fillCircle(p, cx, cy, pr + 1, pr + 1, SHA.deep, 50)
    _fillCircle(p, cx, cy, pr,     pr,     SHA.hi,   51)
end

-- ⑨ SCALE — square frame + 4 corner handles (Studio style)
local function icoNatScale(p, S, T)
    local pad  = math.floor(S * 0.22)
    local xL, xR = pad, S - pad
    local yT, yB = pad, S - pad
    local fr   = math.max(1, math.floor(S * 0.05))   -- ketebalan frame tipis
    local cr   = math.max(3, math.floor(S * 0.22))   -- corner handle

    -- Frame outline (4 sisi tipis)
    _fillRect(p, xL, yT,         (xR - xL), fr, SHA.base, 46)
    _fillRect(p, xL, yB - fr,    (xR - xL), fr, SHA.base, 46)
    _fillRect(p, xL, yT,         fr, (yB - yT), SHA.base, 46)
    _fillRect(p, xR - fr, yT,    fr, (yB - yT), SHA.base, 46)

    -- Frame outline rim
    drawSeg(p, xL, yT, xR, yT, 1, SHA.deep, 47)
    drawSeg(p, xL, yB, xR, yB, 1, SHA.deep, 47)
    drawSeg(p, xL, yT, xL, yB, 1, SHA.deep, 47)
    drawSeg(p, xR, yT, xR, yB, 1, SHA.deep, 47)

    -- 4 corner handles (kotak terang)
    local function handle(x, y)
        _fillRect(p, x - cr/2 - 1, y - cr/2 - 1, cr + 2, cr + 2, SHA.deep, 48)
        _fillRect(p, x - cr/2,     y - cr/2,     cr,     cr,     SHA.lite, 49)
        -- Highlight putih atas-kiri
        _fillRect(p, x - cr/2,     y - cr/2,     cr, 1, Color3.fromRGB(255,255,255), 50)
        _fillRect(p, x - cr/2,     y - cr/2,     1, cr, Color3.fromRGB(255,255,255), 50)
    end
    handle(xL, yT)
    handle(xR, yT)
    handle(xL, yB)
    handle(xR, yB)
end

-- ⑩ ROTATE — curved arrow ring (Studio rotate gizmo)
local function icoNatRotate(p, S, T)
    local cx, cy = S/2, S/2
    local rOut = math.floor(S * 0.42)
    local rIn  = math.floor(S * 0.28)
    local th   = rOut - rIn

    -- Ring 270° (gap di kanan-atas untuk arrowhead)
    local aStart = -math.pi * 0.40   -- sekitar jam 1
    local aEnd   = math.pi * 1.50    -- sekitar jam 12 (full putar minus gap)
    local n = 26
    local da = (aEnd - aStart) / n
    for i = 0, n - 1 do
        local a1 = aStart + da * i
        local a2 = aStart + da * (i + 1)
        local x1o = cx + math.cos(a1) * rOut
        local y1o = cy + math.sin(a1) * rOut
        local x2o = cx + math.cos(a2) * rOut
        local y2o = cy + math.sin(a2) * rOut
        local x1i = cx + math.cos(a1) * rIn
        local y1i = cy + math.sin(a1) * rIn
        local x2i = cx + math.cos(a2) * rIn
        local y2i = cy + math.sin(a2) * rIn
        _fillQuad(p, x1o, y1o, x2o, y2o, x2i, y2i, x1i, y1i, SHA.base, 46)
    end

    -- Outline ring (luar & dalam)
    _arc(p, cx, cy, rOut, rOut, aStart, aEnd, 30, 1, SHA.deep, 48)
    _arc(p, cx, cy, rIn,  rIn,  aStart, aEnd, 26, 1, SHA.deep, 48)

    -- Cap awal arc (sisi yang mulai)
    do
        local x1o = cx + math.cos(aStart) * rOut
        local y1o = cy + math.sin(aStart) * rOut
        local x1i = cx + math.cos(aStart) * rIn
        local y1i = cy + math.sin(aStart) * rIn
        drawSeg(p, x1o, y1o, x1i, y1i, 1, SHA.deep, 48)
    end

    -- ARROWHEAD di ujung arc (rotate ke arah luar)
    local aTip = aEnd
    local tipX = cx + math.cos(aTip) * (rOut + rIn) / 2
    local tipY = cy + math.sin(aTip) * (rOut + rIn) / 2
    -- Tangent direction (perpendicular ke radius)
    local tx = -math.sin(aTip)
    local ty =  math.cos(aTip)
    -- Outward direction (radial)
    local rx = math.cos(aTip)
    local ry = math.sin(aTip)
    local arwL = math.floor(S * 0.20)
    local arwW = math.floor(S * 0.14)

    local Px = tipX + tx * arwL
    local Py = tipY + ty * arwL
    local Qx = tipX + rx * arwW
    local Qy = tipY + ry * arwW
    local Rx = tipX - rx * arwW
    local Ry = tipY - ry * arwW

    _fillTri(p, Px, Py, Qx, Qy, Rx, Ry, SHA.base, 49)
    drawSeg(p, Px, Py, Qx, Qy, 1, SHA.deep, 50)
    drawSeg(p, Px, Py, Rx, Ry, 1, SHA.deep, 50)
    drawSeg(p, Qx, Qy, Rx, Ry, 1, SHA.deep, 50)

    -- Highlight 1px atas
    _arc(p, cx, cy, rOut - 1, rOut - 1, aStart + 0.15, aStart + 1.5, 16, 1, SHA.lite, 49)
end

-- ⑪ PLAY — segitiga hijau Studio bersih
local function icoNatPlay(p, S, T)
    local Ax, Ay = S*0.24, S*0.12
    local Bx, By = S*0.90, S*0.50
    local Cx, Cy = S*0.24, S*0.88

    -- Body flat hijau
    _fillTri(p, Ax, Ay, Bx, By, Cx, Cy, GRN.base, 46)
    -- Highlight wedge kiri-atas (mid → lite gradient via 2 layer)
    _fillTri(p, Ax, Ay, S*0.50, S*0.32, Ax, S*0.50, GRN.lite, 47)
    _fillTri(p, Ax, Ay, S*0.36, S*0.24, Ax, S*0.36, GRN.hi, 48)
    -- Outline tegas
    drawSeg(p, Ax, Ay, Bx, By, 1, GRN.deep, 49)
    drawSeg(p, Bx, By, Cx, Cy, 1, GRN.deep, 49)
    drawSeg(p, Cx, Cy, Ax, Ay, 1, GRN.deep, 49)
end

-- ⑫ TOOLBOX — briefcase Studio style
local function icoNatToolbox(p, S, T)
    -- Handle setengah-D di atas
    local hcx = math.floor(S / 2)
    local hcy = math.floor(S * 0.32)
    local hrx = math.floor(S * 0.18)
    local hry = math.floor(S * 0.16)
    local hth = math.max(2, math.floor(S * 0.06))

    -- Outline handle
    _fillCircle(p, hcx, hcy, hrx + 1, hry + 1, SHA.deep, 44)
    -- Body handle
    _fillCircle(p, hcx, hcy, hrx, hry, SHA.base, 45)
    -- Inner cutout (lubang handle)
    _fillCircle(p, hcx, hcy, hrx - hth + 1, hry - hth + 1, SHA.deep, 46)
    _fillCircle(p, hcx, hcy, hrx - hth, hry - hth, C.bg1, 47)
    -- Mask bottom dari handle
    _fillRect(p, hcx - hrx - 2, hcy + math.floor(hry*0.35), hrx * 2 + 4, hry + 6, C.bg1, 48)

    -- Body briefcase
    local bx = math.floor(S * 0.08)
    local by = math.floor(S * 0.44)
    local bw = math.ceil (S * 0.84)
    local bh = math.floor(S * 0.50)

    -- Outline body
    _fillRect(p, bx - 1, by - 1, bw + 2, bh + 2, SHA.deep, 49, 1)
    -- Body biru
    _fillRect(p, bx, by, bw, bh, SHA.base, 50, 1)
    -- Highlight 1px atas
    _fillRect(p, bx, by, bw, 1, SHA.lite, 51)
    _fillRect(p, bx, by, 1, bh, SHA.lite, 51)
    -- Engsel pemisah lid (garis horizontal)
    _fillRect(p, bx, by + math.floor(bh * 0.32), bw, 1, SHA.deep, 52)

    -- LATCH tengah (kotak terang dengan lubang)
    local lcw = math.floor(S * 0.22)
    local lch = math.floor(S * 0.16)
    local lcx = math.floor(S / 2 - lcw / 2)
    local lcy = by + math.floor(bh * 0.42)

    _fillRect(p, lcx - 1, lcy - 1, lcw + 2, lch + 2, SHA.deep, 53, 1)
    _fillRect(p, lcx, lcy, lcw, lch, SHA.lite, 54, 1)
    _fillRect(p, lcx, lcy, lcw, 1, Color3.fromRGB(255,255,255), 55)
    -- Lubang gembok
    _fillCircle(p, lcx + lcw/2, lcy + lch/2,
                math.max(1.5, S*0.04), math.max(1.5, S*0.04), SHA.deep, 56)
end


-- ══════════════════════════════════════════════
--  INJECT NATIVE REPLACE v3 — FULL TAKEOVER
--  Pakai nama PERSIS dari GuiCopy.txt:
--  MainBar > select / move / scale / rotate / play / toolbox
--  Semua visual asli di-blackout total, diganti icon kita
-- ══════════════════════════════════════════════
local NATIVE_MAP = {
    {name="select",  ico=icoNatSelect,  label="Select"},
    {name="move",    ico=icoNatMove,    label="Move"},
    {name="scale",   ico=icoNatScale,   label="Scale"},
    {name="rotate",  ico=icoNatRotate,  label="Rotate"},
    {name="play",    ico=icoNatPlay,    label="Play"},
    {name="toolbox", ico=icoNatToolbox, label="Toolbox"},
}

-- ══════════════════════════════════════════════
--  FULL TAKEOVER satu tombol bawaan Studio Lite
--  Dipanggil per-btn: bisa retry kapan saja (idempoten)
-- ══════════════════════════════════════════════
local function takeoverBtn(btn, def)
    if not btn or not btn.Parent then return end
    local ovName  = PFX.."OvIco_"..def.label
    local blkName = PFX.."OvBlk_"..def.label

    -- ── ① BLACKOUT semua visual asli (SETIAP descendant) ──────────────────
    -- Gunakan watcher persistent agar setiap perubahan dari Studio Lite
    -- langsung dibatalkan oleh kita
    local function blackoutDesc(d)
        if isOwn(d) then return end
        pcall(function()
            if d:IsA("ImageLabel") or d:IsA("ImageButton") then
                d.ImageTransparency    = 1
                d.BackgroundTransparency = 1
            end
            if d:IsA("TextLabel") or d:IsA("TextButton") then
                d.TextTransparency     = 1
                d.BackgroundTransparency = 1
            end
            if d:IsA("Frame") or d:IsA("ScrollingFrame") then
                d.BackgroundTransparency = 1
            end
        end)
    end
    for _, d in ipairs(btn:GetDescendants()) do blackoutDesc(d) end
    -- Blackout tombol itu sendiri (background-nya)
    pcall(function()
        btn.BackgroundTransparency = 1
        if btn:IsA("TextButton") or btn:IsA("TextLabel") then
            btn.TextTransparency = 1
        end
        if btn:IsA("ImageButton") or btn:IsA("ImageLabel") then
            btn.ImageTransparency = 1
        end
    end)
    -- Watcher: kalau Studio Lite restore visual asli → kita blackout lagi
    btn.DescendantAdded:Connect(function(d)
        task.defer(function() blackoutDesc(d) end)
    end)
    -- Watcher: kalau property berubah (mis. BackgroundTransparency di-reset)
    -- pasang listener di semua descendant yang ada sekarang
    for _, d in ipairs(btn:GetDescendants()) do
        if not isOwn(d) then
            pcall(function()
                if d:IsA("GuiObject") then
                    d:GetPropertyChangedSignal("BackgroundTransparency"):Connect(function()
                        task.defer(function()
                            pcall(function()
                                if not isOwn(d) then
                                    d.BackgroundTransparency = 1
                                end
                            end)
                        end)
                    end)
                end
                if d:IsA("ImageLabel") or d:IsA("ImageButton") then
                    d:GetPropertyChangedSignal("ImageTransparency"):Connect(function()
                        task.defer(function()
                            pcall(function()
                                if not isOwn(d) then d.ImageTransparency = 1 end
                            end)
                        end)
                    end)
                end
            end)
        end
    end

    -- ── ② BLOCKER FRAME — lapisan solid warna bg1 ukuran penuh ───────────
    --    Ini safety net: kalau ada visual asli yang lolos blackout,
    --    tertutup oleh blocker warna bg sebelum icon kita
    if not btn:FindFirstChild(blkName) then
        local H = btn.AbsoluteSize.Y; if H < 6 then H = 50 end
        local W = btn.AbsoluteSize.X; if W < 6 then W = 35 end
        local blk = Instance.new("Frame")
        blk.Name                 = blkName
        blk.Size                 = UDim2.new(1, 0, 1, 0)
        blk.Position             = UDim2.new(0, 0, 0, 0)
        blk.BackgroundColor3     = C.bg1          -- #242424 — sama dengan toolbar
        blk.BackgroundTransparency = 0
        blk.BorderSizePixel      = 0
        blk.ZIndex               = (btn.ZIndex or 5) + 2
        blk.Parent               = btn
    end

    -- ── ③ ICON OVERLAY kita ───────────────────────────────────────────────
    if btn:FindFirstChild(ovName) then return end  -- sudah ada, skip

    local H = btn.AbsoluteSize.Y; if H < 6 then H = 50 end
    local S = 20; local T = 2
    local padT = math.floor((H - S - 10) / 2)
    if padT < 2 then padT = 2 end
    local baseZ = (btn.ZIndex or 5) + 3

    local ov = Instance.new("Frame")
    ov.Name                   = ovName
    ov.Size                   = UDim2.new(0, S, 0, S)
    ov.Position               = UDim2.new(0.5, -S/2, 0, padT)
    ov.BackgroundTransparency = 1
    ov.ZIndex                 = baseZ
    ov.Parent                 = btn
    pcall(def.ico, ov, S, T)

    -- ── ④ LABEL OVERLAY ──────────────────────────────────────────────────
    local ovLbl = Instance.new("TextLabel")
    ovLbl.Name              = PFX.."OvLbl_"..def.label
    ovLbl.Size              = UDim2.new(1, 0, 0, 10)
    ovLbl.Position          = UDim2.new(0, 0, 0, padT + S + 2)
    ovLbl.BackgroundTransparency = 1
    ovLbl.Text              = def.label:upper()
    ovLbl.TextColor3        = (def.label == "Play") and C.green or C.txtD
    ovLbl.TextSize          = 7
    ovLbl.Font              = Enum.Font.GothamBold
    ovLbl.TextXAlignment    = Enum.TextXAlignment.Center
    ovLbl.ZIndex            = baseZ + 1
    ovLbl.Parent            = btn
end

-- ══════════════════════════════════════════════
--  INJECT NATIVE REPLACE v3 — FULL TAKEOVER
--  • Tidak pakai done-guard global (idempoten via FindFirstChild)
--  • Tangani tombol yang belum ada saat pertama run
--  • Watcher tb.ChildAdded agar tombol datang terlambat juga ditangkap
-- ══════════════════════════════════════════════
local nativeTBWatched = false  -- pastikan watcher toolbar hanya dipasang sekali

local function injectNativeReplace()
    local tb = findToolbar()
    if not tb then return end

    -- Pasang watcher sekali: kalau ada anak baru di toolbar, cek apakah
    -- itu tombol bawaan yang perlu di-takeover
    if not nativeTBWatched then
        nativeTBWatched = true
        tb.ChildAdded:Connect(function(ch)
            task.defer(function()
                for _, def in ipairs(NATIVE_MAP) do
                    if ch.Name:lower() == def.name then
                        task.wait(0.1)  -- beri sedikit waktu AbsoluteSize tersedia
                        pcall(takeoverBtn, ch, def)
                        break
                    end
                end
            end)
        end)
    end

    -- Proses semua tombol yang sudah ada di toolbar sekarang
    for _, def in ipairs(NATIVE_MAP) do
        local btn = nil
        for _, ch in ipairs(tb:GetChildren()) do
            if ch.Name:lower() == def.name then btn = ch; break end
        end
        -- fallback: cari di seluruh StudioGui
        if not btn then
            local found = StudioGui:FindFirstChild(def.name, true)
            if found and found.Parent == tb then btn = found end
        end
        if btn then
            pcall(takeoverBtn, btn, def)
        end
    end

end

