local injectTerrain,injectPlugin,injectToolbox=_SL.injectTerrain,_SL.injectPlugin,_SL.injectToolbox
local injectToolboxPC=_SL.injectToolboxPC
local injectNativeReplace=_SL.injectNativeReplace
