            if wt then wt.Text=msg; wt.Visible=true
                if dur then task.delay(dur, function() wt.Visible=false end) end
            end
        end)
    end

    -- ── Folder tunggal: PLUGIN MANEJEMEN ────────────────────────────────
    local DELTA_API_PATHS = {
        "/storage/emulated/0/Delta/Workspace/PLUGIN MANEJEMEN/api key voice.txt",
    }
    local function readDeltaApiKey()
        if type(readfile) == "function" then
            for _, path in ipairs(DELTA_API_PATHS) do
                local ok, content = pcall(readfile, path)
                if ok and content and #content > 10 then
                    local key = content:match("^%s*(.-)%s*$")
                    if key and #key > 10 then return key, path end
                end
            end
        end
        if type(isfile) == "function" and type(readfile) == "function" then
            for _, path in ipairs(DELTA_API_PATHS) do
                local ok1, exists = pcall(isfile, path)
                if ok1 and exists then
                    local ok2, content = pcall(readfile, path)
                    if ok2 and content and #content > 10 then
                        local key = content:match("^%s*(.-)%s*$")
                        if key and #key > 10 then return key, path end
                    end
                end
            end
        end
        return nil, nil
    end

    -- ── Baca .ROBLOSECURITY cookie dari file api key add place.txt ────────
    local COOKEY_PATHS = {
        "/storage/emulated/0/Delta/Workspace/PLUGIN MANEJEMEN/api key add place.txt",
    }
    local function readCookeyFile()
        if type(readfile) == "function" then
            for _, path in ipairs(COOKEY_PATHS) do
                local ok, content = pcall(readfile, path)
                if ok and content and #content > 20 then
                    local ck = content:match("^%s*(.-)%s*$")
                    -- Validasi: harus mengandung tanda khas ROBLOSECURITY
                    if ck and #ck > 20 then
                        return ck, path
                    end
                end
            end
        end
        if type(isfile) == "function" and type(readfile) == "function" then
            for _, path in ipairs(COOKEY_PATHS) do
                local ok1, exists = pcall(isfile, path)
                if ok1 and exists then
                    local ok2, content = pcall(readfile, path)
                    if ok2 and content and #content > 20 then
                        local ck = content:match("^%s*(.-)%s*$")
                        if ck and #ck > 20 then return ck, path end
                    end
                end
            end
        end
        return nil, nil
    end

    -- ══════════════════════════════════════════════════════════════════════
    -- ADD PLACE — STRATEGI FINAL (v3.1 — endpoint benar)
    --
    -- Endpoint resmi (dikonfirmasi Roblox staff Juli 2024):
    --   POST https://apis.roblox.com/universes/v1/user/universes/{universeId}/places
    --   Body: { "templatePlaceId": 95206881 }
    --   Auth: .ROBLOSECURITY cookie (x-csrf-token required)
    --
    -- CATATAN PENTING:
    --   • Open Cloud v2 cloud/v2/universes/{id}/places → TIDAK ADA endpoint CREATE
    --   • Satu-satunya cara create place dari luar Studio adalah endpoint di atas
    --   • Endpoint ini butuh Cookie + X-CSRF-Token, BUKAN API Key biasa
    --   • Di Studio Lite/Delta, cookie .ROBLOSECURITY bisa diambil via
    --     syn.request / request() yang sudah attach cookie otomatis
    --   • X-CSRF-Token diambil dulu via POST ke roblox.com (response header)
    -- ══════════════════════════════════════════════════════════════════════

    local HttpSvc2 = game:GetService("HttpService")

    -- Cari request function yang tersedia di eksekutor Delta/SL
    local function getReqFn()
        if type(syn) == "table" and type(syn.request) == "function" then return syn.request end
        if type(http) == "table" and type(http.request) == "function" then return http.request end
        if type(request) == "function" then return request end
        return function(opts)
            local ok2, res = pcall(function()
                return HttpSvc2:RequestAsync(opts)
            end)
            if ok2 then return res end
            return { StatusCode = 0, Body = tostring(res), Headers = {} }
        end
    end

    local function jsonDecode(str)
        local ok2, val = pcall(function() return HttpSvc2:JSONDecode(str) end)
        if ok2 then return val end
        return nil
    end

    -- Ambil X-CSRF-Token (wajib untuk semua POST ke Roblox)
    local _csrfCache = nil
    local function getCsrf()
        if _csrfCache then return _csrfCache end
        local fn = getReqFn()
        -- POST ke endpoint apapun yang minta CSRF → dapat token di header 403
        local ok2, res = pcall(fn, {
            Url    = "https://auth.roblox.com/v2/logout",
            Method = "POST",
            Headers = { ["Content-Type"] = "application/json" },
            Body   = "{}",
        })
        if ok2 and res and res.Headers then
            local tok = res.Headers["x-csrf-token"] or res.Headers["X-CSRF-Token"]
            if tok and #tok > 2 then
                _csrfCache = tok
                return tok
            end
        end
        return nil
    end

    -- ── slWarnAP: notifikasi layar via WarningText ──
    local function slWarnAP(msg, dur)
        pcall(function()
            local wt = LP.PlayerGui:WaitForChild("StudioGui",3):FindFirstChild("WarningText")
            if wt then
                wt.Text = msg; wt.Visible = true
                if dur then task.delay(dur, function() pcall(function() wt.Visible = false end) end) end
            end
        end)
    end

    -- ══════════════════════════════════════════════════════════════════════
    -- addPlace v4.0 — BUAT UNIVERSE BARU (muncul di Creations sebagai game baru)
    --
    -- PENYEBAB MASALAH LAMA:
    --   POST /universes/v1/user/universes/{uid}/places hanya menambah sub-place
    --   ke dalam universe yang sudah ada → TIDAK muncul sebagai game baru di Creations
    --
    -- SOLUSI BARU (cara kerja sama seperti Studio PC):
    --   [1] POST /universes/v1/user/universes  (tanpa UID) → buat universe baru
    --       Response: { "universeId": 123, "rootPlaceId": 456 }
    --   [2] PATCH nama universe via beberapa strategi
    --   [3] PATCH nama rootPlace
    --   Hasilnya: game baru muncul langsung di Creations akun kamu ✓
    -- ══════════════════════════════════════════════════════════════════════
    local function addPlace(apiKey, universeId, placeName, placeDesc, logCb, cookie)
        logCb = logCb or function() end

        local safeName = (placeName and placeName ~= "") and placeName or "New Game"
        local safeDesc = placeDesc or ""

        -- Log status cookie & apiKey
        if cookie and #cookie > 10 then
            logCb("> Cookie: " .. cookie:sub(1,12) .. "... OK", C.green)
        else
            logCb("> Cookie: kosong! Wajib ada untuk buat game baru.", C.red)
        end

        -- ── [1/3] Ambil X-CSRF-Token (force fresh) ──────────────────────────
        _csrfCache = nil
        logCb("> [1/3] Ambil X-CSRF-Token...", C.accA)
        local csrf = getCsrf()
        if not csrf or csrf == "" then
            -- Coba sekali lagi dengan endpoint berbeda
            local fn0 = getReqFn()
            local ok0, r0 = pcall(fn0, {
                Url = "https://www.roblox.com/authentication/signoutfromallsessionsandreauthenticate",
                Method = "POST",
                Headers = { ["Content-Type"] = "application/json" },
                Body = "{}",
            })
            if ok0 and r0 and r0.Headers then
                csrf = r0.Headers["x-csrf-token"] or r0.Headers["X-CSRF-Token"] or ""
                if csrf ~= "" then _csrfCache = csrf end
            end
        end
        if not csrf or csrf == "" then
            logCb("> CSRF tidak ditemukan, lanjut tanpa token...", C.txtD)
            csrf = ""
        else
            logCb("> CSRF OK: " .. csrf:sub(1,8) .. "...", C.txtD)
        end

        -- ── [2/3] POST buat UNIVERSE BARU ────────────────────────────────────
        -- Ini cara yang benar: POST ke /universes (tanpa UID) → universe baru di Creations
        logCb("> [2/3] POST buat universe baru...", C.accA)

        local fn = getReqFn()

        -- Header utama dengan cookie
        local hdrs = {
            ["Content-Type"] = "application/json",
            ["Accept"]       = "application/json",
        }
        if csrf ~= "" then hdrs["x-csrf-token"] = csrf end
        if cookie and #cookie > 10 then
            hdrs["Cookie"] = ".ROBLOSECURITY=" .. cookie:gsub(";$","") .. ";"
        end
        if apiKey and #apiKey > 8 then
            hdrs["x-api-key"] = apiKey
        end

        -- Body: templatePlaceId 95206881 = template baseplate kosong resmi Roblox
        local createBody = HttpSvc2:JSONEncode({ templatePlaceId = 95206881 })

        -- Endpoint baru: POST tanpa universeId → buat universe baru
        local createUrl = "https://apis.roblox.com/universes/v1/universes/create"

        local ok2, res = pcall(fn, {
            Url     = createUrl,
            Method  = "POST",
            Headers = hdrs,
            Body    = createBody,
        })

        if not ok2 then
            slWarnAP("Buat Universe GAGAL! Request error.", 3)
            return false, "Request error: " .. tostring(res):sub(1,80)
        end

        local code = res and res.StatusCode or 0
        logCb("> HTTP " .. tostring(code), (code == 200 or code == 201) and C.green or C.red)

        -- Jika 403 CSRF mismatch → ambil token baru dari response header lalu retry
        if code == 403 then
            local newCsrf = (res.Headers and (res.Headers["x-csrf-token"] or res.Headers["X-CSRF-Token"])) or ""
            if #newCsrf < 3 then
                _csrfCache = nil; newCsrf = getCsrf() or ""
            end
            if #newCsrf > 2 then
                logCb("> CSRF refresh, retry...", C.accA)
                csrf = newCsrf; _csrfCache = newCsrf
                hdrs["x-csrf-token"] = newCsrf
                ok2, res = pcall(fn, { Url=createUrl, Method="POST", Headers=hdrs, Body=createBody })
                code = (res and res.StatusCode) or 0
                logCb("> HTTP " .. tostring(code) .. " (retry)", (code==200 or code==201) and C.green or C.red)
            end
        end

        if code ~= 200 and code ~= 201 then
            local detail = (res and res.Body and res.Body:sub(1,160)) or "no body"
            slWarnAP("Buat Universe GAGAL! HTTP " .. tostring(code), 3)
            return false, "POST HTTP " .. code .. ": " .. detail
        end

        local data = jsonDecode(res and res.Body or "")
        if not data then
            slWarnAP("Parse response gagal.", 3)
            return false, "JSON decode gagal: " .. ((res and res.Body) or ""):sub(1,80)
        end

        -- Response dari /universes/v1/universes/create:
        -- { "universeId": 123456, "rootPlaceId": 789012 } (camelCase)
        local newUniverseId = tostring(data.universeId or data.id or "")
        local rootPlaceId   = tostring(data.rootPlaceId or data.rootPlace and data.rootPlace.id or "")

        if newUniverseId == "" then
            slWarnAP("Universe berhasil dibuat tapi ID tidak ada!", 3)
            return false, "universeId tidak ada di response: " .. (res.Body or ""):sub(1,100)
        end

        logCb("> Universe baru ID: " .. newUniverseId, C.green)
        if rootPlaceId ~= "" then
            logCb("> Root Place ID: " .. rootPlaceId, C.green)
        end

        -- ── [3/3] PATCH nama universe + rootPlace ────────────────────────────
        logCb("> [3/3] PATCH nama game...", C.accA)

        local patchDone = false

        -- [STRATEGY A] Open Cloud v2 PATCH universe name (pakai x-api-key)
        if not patchDone and apiKey and #apiKey > 8 then
            local urlA  = ("https://apis.roblox.com/cloud/v2/universes/%s?updateMask=displayName%%2Cdescription"):format(newUniverseId)
            local bodyA = HttpSvc2:JSONEncode({ displayName = safeName, description = safeDesc })
            local hdrsA = { ["Content-Type"]="application/json", ["Accept"]="application/json", ["x-api-key"]=apiKey }
            local okA, resA = pcall(fn, { Url=urlA, Method="PATCH", Headers=hdrsA, Body=bodyA })
            local cA = (okA and resA and resA.StatusCode) or 0
            logCb("> [A] cloud/v2 universe PATCH HTTP " .. tostring(cA), (cA==200 or cA==204) and C.green or C.txtD)
            if cA == 200 or cA == 204 then
                logCb("> Nama universe berhasil ✓", C.green); patchDone = true
            else
                logCb("> [A] " .. ((resA and resA.Body and resA.Body:sub(1,60)) or "no body"), C.txtD)
            end
        end

        -- [STRATEGY B] develop.roblox.com PATCH universe (cookie+csrf)
        if not patchDone then
            local urlB  = ("https://develop.roblox.com/v1/universes/%s"):format(newUniverseId)
            local hdrsB = { ["Content-Type"]="application/json", ["Accept"]="application/json" }
            if csrf ~= "" then hdrsB["x-csrf-token"] = csrf end
            if cookie and #cookie > 10 then hdrsB["Cookie"] = ".ROBLOSECURITY=" .. cookie:gsub(";$","") .. ";" end
            local bodyB = HttpSvc2:JSONEncode({ name=safeName, description=safeDesc })
            local okB, resB = pcall(fn, { Url=urlB, Method="PATCH", Headers=hdrsB, Body=bodyB })
            local cB = (okB and resB and resB.StatusCode) or 0
            logCb("> [B] develop/v1 universe PATCH HTTP " .. tostring(cB), (cB==200 or cB==204) and C.green or C.txtD)
            if cB == 200 or cB == 204 then
                logCb("> Nama universe berhasil via develop ✓", C.green); patchDone = true
            end
        end

        -- [STRATEGY C] places/v1 PATCH rootPlace name (cookie+csrf)
        if rootPlaceId ~= "" then
            local urlC  = ("https://places.roblox.com/v1/places/%s"):format(rootPlaceId)
            local hdrsC = { ["Content-Type"]="application/json", ["Accept"]="application/json" }
            if csrf ~= "" then hdrsC["x-csrf-token"] = csrf end
            if cookie and #cookie > 10 then hdrsC["Cookie"] = ".ROBLOSECURITY=" .. cookie:gsub(";$","") .. ";" end
            if apiKey and #apiKey > 8 then hdrsC["x-api-key"] = apiKey end
            local bodyC = HttpSvc2:JSONEncode({ name=safeName, description=safeDesc })
            local okC, resC = pcall(fn, { Url=urlC, Method="PATCH", Headers=hdrsC, Body=bodyC })
            local cC = (okC and resC and resC.StatusCode) or 0
            logCb("> [C] places/v1 rootPlace PATCH HTTP " .. tostring(cC), (cC==200 or cC==204) and C.green or C.txtD)
            if cC == 200 or cC == 204 then
                logCb("> Nama rootPlace berhasil ✓", C.green); patchDone = true
            end
        end

        if not patchDone then
            logCb("> ! Nama gagal di-set, game dibuat tapi nama masih default", C.red)
        end

        -- ── Sukses ──────────────────────────────────────────────────────────
        slWarnAP("Game '" .. safeName .. "' berhasil dibuat! Universe: " .. newUniverseId, 5)
        logCb("> BERHASIL! Universe ID: " .. newUniverseId, C.green)
        logCb("> Game sudah muncul di Creations akun kamu ✓", C.accA)

        -- Salin Universe ID ke clipboard
        pcall(function()
            if setclipboard then
                setclipboard(newUniverseId)
                task.delay(0.5, function()
                    logCb("> Universe ID disalin ke clipboard ✓", C.green)
                end)
            end
        end)

        -- Return rootPlaceId sebagai "result" agar kompatibel dengan kode lama
        local retId = (rootPlaceId ~= "") and rootPlaceId or newUniverseId
        return true, retId, newUniverseId
    end

