        local v2 = Instance.new("Frame")
        v2.Size=UDim2.new(0,2,0,14); v2.AnchorPoint=Vector2.new(0.5,0.5)
        v2.Position=UDim2.new(0,22,0.5,0); v2.BackgroundColor3=C.txtP; v2.BorderSizePixel=0; v2.ZIndex=14; v2.Parent=apCreateBtn
    end
    local apCreateLbl = Instance.new("TextLabel")
    apCreateLbl.Size = UDim2.new(1,-40,1,0); apCreateLbl.Position = UDim2.new(0,36,0,0)
    apCreateLbl.BackgroundTransparency = 1; apCreateLbl.Text = "Create Place"
    apCreateLbl.TextColor3 = C.txtP; apCreateLbl.Font = Enum.Font.GothamBold; apCreateLbl.TextSize = 13
    apCreateLbl.TextXAlignment = Enum.TextXAlignment.Left
