local D_E_X = CreateGui()
-- ════════════════════════════════════════════════════════════════════
-- ★ FIX PERSIST v2.0 — DEX & SEMUA panel embed (Toolbox / Plugin /
--   Terrain Brush / Settings / Remotes / SaveMap) TIDAK ikut hilang
--   saat user keluar dari Play mode → kembali ke Edit mode di MZYY.
--
--   ROOT CAUSE: PlayerGui dibersihkan oleh MZYY/Studio mobile saat
--   transisi Play→Edit (lebih dari sekedar respawn — character &
--   PlayerGui di-rebuild). Akibatnya GUI "Dex" (yang induk dari
--   semua panel embed) ikut dihapus.
--
--   SOLUSI: Parent ke CoreGui (yang persisten penuh, TIDAK dipengaruhi
--   transisi mode). Kode _findDexGui() di blok-blok bawah memang sudah
--   support cari "Dex" di CoreGui dulu, baru PlayerGui — jadi semua
--   panel embed tetap nemu DEX di lokasi baru.
--
--   Catatan: posisi & ukuran TIDAK diubah (tidak set IgnoreGuiInset
--   maupun ZIndexBehavior). MZYY tetap di posisi semula.
-- ════════════════════════════════════════════════════════════════════
pcall(function() D_E_X.ResetOnSpawn = false end)

local _dex_parent_target = game.Players.LocalPlayer:FindFirstChildOfClass("PlayerGui")
do
        local _ok, _cg = pcall(function() return game:GetService("CoreGui") end)
        if _ok and _cg then
                local _okWrite = pcall(function() D_E_X.Parent = _cg end)
                if _okWrite and D_E_X.Parent == _cg then
                        _dex_parent_target = _cg
                end
        end
end
if D_E_X.Parent == nil then
        D_E_X.Parent = game.Players.LocalPlayer.PlayerGui
        _dex_parent_target = game.Players.LocalPlayer.PlayerGui
end

-- Pengaman: kalau toh sampai di-unparent oleh sesuatu, tempelkan ulang
-- ke target yang sama (jangan rebuild — cukup re-parent supaya state
-- panel-panel embed tetap utuh).
pcall(function()
        D_E_X.AncestryChanged:Connect(function(_, parent)
                if parent == nil and _dex_parent_target then
                        pcall(function() D_E_X.Parent = _dex_parent_target end)
                end
        end)
end)
spawn(function()
        local Gui = D_E_X
        

local IntroFrame = Gui:WaitForChild("IntroFrame")

local SideMenu = Gui:WaitForChild("SideMenu")
local OpenToggleButton = Gui:WaitForChild("Toggle")
local CloseToggleButton = SideMenu:WaitForChild("Toggle")
local OpenScriptEditorButton = SideMenu:WaitForChild("OpenScriptEditor")

local ScriptEditor = Gui:WaitForChild("ScriptEditor")

local SlideOut = SideMenu:WaitForChild("SlideOut")
local SlideFrame = SlideOut:WaitForChild("SlideFrame")
local Slant = SideMenu:WaitForChild("Slant")

local ExplorerButton = SlideFrame:WaitForChild("Explorer")
local SettingsButton = SlideFrame:WaitForChild("Settings")

local SelectionBox = Instance.new("SelectionBox")
SelectionBox.Parent = Gui

local ExplorerPanel = Gui:WaitForChild("ExplorerPanel")
