-- v50 LAYOUT: rapihkan SettingList dgn UIGridLayout 2 kolom + UIPadding
-- → tombol tersusun jadi 2 kolom, mengisi ruang kosong di samping kanan
--   sehingga tidak ada tombol yang keluar dari panel.
do
    -- buang UIListLayout lama bila ada (untuk hindari konflik layout)
    local _old = SettingList:FindFirstChildOfClass("UIListLayout")
    if _old then pcall(function() _old:Destroy() end) end

    local _gl = SettingList:FindFirstChildOfClass("UIGridLayout") or Instance.new("UIGridLayout")
    _gl.CellSize             = UDim2.new(0.5, -10, 0, 60)
    _gl.CellPadding          = UDim2.new(0, 6, 0, 6)
    _gl.SortOrder            = Enum.SortOrder.LayoutOrder
    _gl.FillDirection        = Enum.FillDirection.Horizontal
    _gl.HorizontalAlignment  = Enum.HorizontalAlignment.Left
    _gl.VerticalAlignment    = Enum.VerticalAlignment.Top
    _gl.StartCorner          = Enum.StartCorner.TopLeft
    _gl.Parent               = SettingList

    local _pd = SettingList:FindFirstChildOfClass("UIPadding") or Instance.new("UIPadding")
    _pd.PaddingTop    = UDim.new(0, 8)
    _pd.PaddingBottom = UDim.new(0, 8)
    _pd.PaddingLeft   = UDim.new(0, 8)
    _pd.PaddingRight  = UDim.new(0, 8)
    _pd.Parent        = SettingList
end

-- v9 RESIZE: Settings panel disamakan ukurannya dgn ExplorerPanel
-- (compact, tidak panjang ke bawah) — auto-sync mengikuti explorer.
-- Jika item settings melebihi tinggi panel, ClipsDescendants false agar tidak terpotong visual,
-- tetapi tinggi panel mengikuti explorer secara konsisten.
do
    local _epRef = Gui:WaitForChild("ExplorerPanel")
    local function _syncSettingsSize()
        pcall(function()
            SettingsPanel.Size     = _epRef.Size
            SettingsPanel.Position = UDim2.new(0, -_epRef.Size.X.Offset, 0, 0)
        end)
    end
    _syncSettingsSize()
    pcall(function()
        _epRef:GetPropertyChangedSignal("Size"):Connect(_syncSettingsSize)
    end)
end

