do
    local function _showV9Notif()
        local notif = SaveMapWindow:FindFirstChild("__v9notif__")
        if not notif then
            notif = Instance.new("Frame")
            notif.Name = "__v9notif__"
            notif.Size = UDim2.new(1, 0, 0, 36)
            notif.Position = UDim2.new(0, 0, 1, -40)
            notif.BackgroundColor3 = Color3.fromRGB(20, 20, 20)
            notif.BorderSizePixel = 0
            notif.ZIndex = 10
            notif.Parent = SaveMapWindow
            local lbl = Instance.new("TextLabel")
            lbl.Size = UDim2.new(1, -8, 1, 0)
            lbl.Position = UDim2.new(0, 4, 0, 0)
            lbl.BackgroundTransparency = 1
            lbl.TextColor3 = Color3.fromRGB(255, 210, 60)
            lbl.Font = Enum.Font.GothamBold
            lbl.TextScaled = true
            lbl.Text = "FITUR INI AKAN TERSEDIA DI V9"
            lbl.ZIndex = 11
            lbl.Parent = notif
            Instance.new("UICorner", notif).CornerRadius = UDim.new(0, 4)
        end
        notif.Visible = true
        task.delay(3, function()
            if notif and notif.Parent then notif.Visible = false end
        end)
    end
    task.defer(function()
        if not SaveMapSettingFrame then return end
        for _, item in ipairs(SaveMapSettingFrame:GetChildren()) do
            local changeBtn = item:FindFirstChild("Change")
            if changeBtn then
                changeBtn.MouseButton1Click:Connect(function()
