local Windows = {
        Explorer = {
                ExplorerPanel,
                PropertiesFrame
        },
        Settings = {SettingsPanel},
        SaveMap = {SaveMapWindow},
        Remotes = {RemoteDebugWindow},
        About   = {AboutPanel}
}

function switchWindows(wName,over)
        if CurrentWindow == wName and not over then return end
        
        local count = 0
        
        for i,v in pairs(Windows) do
                count = 0
                if i ~= wName then
                        for _,c in pairs(v) do c:TweenPosition(UDim2.new(0, -330, count * 0.5, count * 36), "Out", "Quad", 0.5, true) count = count + 1 end
                end
        end
        
        count = 0
        
        if Windows[wName] then
                for _,c in pairs(Windows[wName]) do c:TweenPosition(UDim2.new(0, 0, count * 0.5, 20 + count * 36), "Out", "Quad", 0.5, true) count = count + 1 end
        end
        
        if wName ~= "Nothing c:" then
                CurrentWindow = wName
                for i,v in pairs(SlideFrame:GetChildren()) do
                        v.BackgroundTransparency = 1
                        v.Icon.ImageColor3 = Color3.new(70/255, 70/255, 70/255)
                end
                if SlideFrame:FindFirstChild(wName) then
                        SlideFrame[wName].BackgroundTransparency = 0.5
                        SlideFrame[wName].Icon.ImageColor3 = Color3.new(0,0,0)
                end
        end
end

function toggleDex(on)
        if on then
                SideMenu.Visible = true
                SideMenu:TweenPosition(UDim2.new(0, 300, 0, 20), "Out", "Quad", 0.5, true)
                OpenToggleButton:TweenPosition(UDim2.new(0,-30,0,0), "Out", "Quad", 0.5, true)
                switchWindows(CurrentWindow,true)
        else
                SideMenu:TweenPosition(UDim2.new(0, -30, 0, 20), "Out", "Quad", 0.5, true)
                OpenToggleButton:TweenPosition(UDim2.new(0,0,0,0), "Out", "Quad", 0.5, true)
                switchWindows("Nothing c:")
                wait(0.5)
                SideMenu.Visible = false
        end
end

