local Settings = {
        ClickSelect = false,
        SelBox = false,
        ClearProps = false,
        SelectUngrouped = false,
        SaveInstanceScripts = false
}

function ReturnSetting(set)
        if set == "ClearProps" then
                return Settings.ClearProps
        elseif set == "SelectUngrouped" then
                return Settings.SelectUngrouped
        end
end

