end


function createSetting(name,interName,defaultOn)
        local newSetting = SettingTemplate:Clone()
        -- v50: pakai LayoutOrder, posisi diatur otomatis oleh UIListLayout
        newSetting.LayoutOrder = #SettingList:GetChildren()
        newSetting.SName.Text = name

        local function toggle(on)
                if on then
                        newSetting.Change.Bar:TweenPosition(UDim2.new(0,32,0,-2),Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        newSetting.Change.OnBar:TweenSize(UDim2.new(0,34,0,15),Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        newSetting.Status.Text = "On"
                        Settings[interName] = true
                else
                        newSetting.Change.Bar:TweenPosition(UDim2.new(0,-2,0,-2),Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        newSetting.Change.OnBar:TweenSize(UDim2.new(0,0,0,15),Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        newSetting.Status.Text = "Off"
                        Settings[interName] = false
                end
        end

        newSetting.Change.MouseButton1Click:connect(function()
                toggle(not Settings[interName])
        end)

        newSetting.Visible = true
        newSetting.Parent = SettingList

        if defaultOn then
                toggle(true)
        end
end

-- ╔════════════════════════════════════════════════════════════════════╗
-- ║  PANEL EXCLUSION REGISTRY (v50)                                     ║
-- ║  Hanya satu panel boleh aktif sekaligus. Saat satu panel dinyalakan,║
-- ║  panel lain otomatis di-OFF (visual switch + destroy fungsi panel). ║
-- ║  Setting non-panel (mis. SaveInstance) tidak ikut grup ini.         ║
-- ╚════════════════════════════════════════════════════════════════════╝
local _PANEL_TOGGLES = {}

local function _setSettingVisualOff(setFrame, interName)
        pcall(function()
                if setFrame and setFrame:FindFirstChild("Change") then
                        setFrame.Change.Bar:TweenPosition(
                                UDim2.new(0,-2,0,-2),
                                Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        setFrame.Change.OnBar:TweenSize(
                                UDim2.new(0,0,0,15),
                                Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        if setFrame:FindFirstChild("Status") then
                                setFrame.Status.Text = "Off"
                        end
                end
                Settings[interName] = false
        end)
end

local function _registerPanelToggle(setFrame, interName, destroyFn)
        table.insert(_PANEL_TOGGLES, {
                frame = setFrame,
                name  = interName,
                off   = destroyFn,
        })
end

local function _turnOffOtherPanels(activeInterName)
        for _, t in ipairs(_PANEL_TOGGLES) do
                if t.name ~= activeInterName and Settings[t.name] then
                        _setSettingVisualOff(t.frame, t.name)
                        pcall(function()
                                if t.off then t.off() end
                        end)
                end
        end
end

local function _setSettingVisualOn(setFrame, interName)
        pcall(function()
                if setFrame and setFrame:FindFirstChild("Change") then
                        setFrame.Change.Bar:TweenPosition(
                                UDim2.new(0,32,0,-2),
                                Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        setFrame.Change.OnBar:TweenSize(
                                UDim2.new(0,34,0,15),
                                Enum.EasingDirection.Out,Enum.EasingStyle.Quart,0.25,true)
                        if setFrame:FindFirstChild("Status") then
                                setFrame.Status.Text = "On"
                        end
                end
                Settings[interName] = true
        end)
end

local function _isAnyOtherPanelActive(currentName)
        for _, t in ipairs(_PANEL_TOGGLES) do
                if t.name ~= currentName and Settings[t.name] then
                        return true
                end
        end
        return false
end

