-- ║  TERRAIN PANEL  (open tools terrain toggle)          ║
-- ╚══════════════════════════════════════════════════════╝
local _TERRAIN_GUI_NAME = "SygkmuniiBrushUI"

local function _destroyTerrainPanel()
        -- 1) Hapus ScreenGui utama di PlayerGui
        local lp = game:GetService("Players").LocalPlayer
        if lp then
                local pg = lp:FindFirstChildOfClass("PlayerGui")
                if pg then
                        local g = pg:FindFirstChild(_TERRAIN_GUI_NAME)
                        if g then pcall(function() g:Destroy() end) end
                end
        end

        -- 2) Hapus _TerrainScrollWrap (dan MainPanel di dalamnya) dari ExplorerPanel
        pcall(function()
                local sw = ExplorerPanel:FindFirstChild("_TerrainScrollWrap")
                if sw then sw:Destroy() end
                local mp = ExplorerPanel:FindFirstChild("MainPanel")
                if mp then mp:Destroy() end
        end)

        -- 3) Hapus _TerrainOnOff dan _TerrainSep dari SideMenu DEX
        pcall(function()
                local dexGui = nil
                for _, v in ipairs(game:GetService("CoreGui"):GetChildren()) do
                        if v.Name == "Dex" then dexGui = v; break end
                end
                if not dexGui then
                        local lp2 = game:GetService("Players").LocalPlayer
                        local pg2 = lp2 and lp2:FindFirstChildOfClass("PlayerGui")
                        if pg2 then
                                for _, v in ipairs(pg2:GetChildren()) do
                                        if v.Name == "Dex" then dexGui = v; break end
                                end
                        end
                end
                if dexGui then
                        local sideMenu = dexGui:FindFirstChild("SideMenu", true)
                        if sideMenu then
                                local onoff = sideMenu:FindFirstChild("_TerrainOnOff")
                                if onoff then onoff:Destroy() end
                                local sep = sideMenu:FindFirstChild("_TerrainSep")
                                if sep then sep:Destroy() end
                        end
                end
        end)
end

