-- =========================================================
-- HELPERS
-- =========================================================
local function mkCorner(r, p)
    local c = Instance.new("UICorner")
    c.CornerRadius = UDim.new(0, r)
    c.Parent = p
    return c
end
local function mkStroke(t, col, p)
    local s = Instance.new("UIStroke")
    s.Thickness = t
    s.Color = col
    s.Parent = p
    return s
end
local function mkPadding(top, bot, left, right, p)
    local pad = Instance.new("UIPadding")
    pad.PaddingTop    = UDim.new(0, top)
    pad.PaddingBottom = UDim.new(0, bot)
    pad.PaddingLeft   = UDim.new(0, left)
    pad.PaddingRight  = UDim.new(0, right)
    pad.Parent = p
    return pad
end

-- =========================================================
-- DRAGGABLE
-- =========================================================
local function makeDraggable(handle, target)
    target = target or handle
    local dragging, dragStart, startPos = false, nil, nil
    handle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then
            dragging  = true
            dragStart = input.Position
            startPos  = target.Position
            input.Changed:Connect(function()
                if input.UserInputState == Enum.UserInputState.End then
                    dragging = false
                end
            end)
        end
    end)
    handle.InputChanged:Connect(function(input)
        if dragging and (
            input.UserInputType == Enum.UserInputType.MouseMovement or
            input.UserInputType == Enum.UserInputType.Touch) then
            local d = input.Position - dragStart
            target.Position = UDim2.new(
                startPos.X.Scale, startPos.X.Offset + d.X,
                startPos.Y.Scale, startPos.Y.Offset + d.Y
            )
        end
    end)
end

local function connectBtn(btn, fn)
    btn.MouseButton1Click:Connect(fn)
end

-- =========================================================
-- VECTOR ICON LIBRARY
-- =========================================================
local VI = {}

function VI.dot(parent, color, size)
    size = size or 6
    local f = Instance.new("Frame")
    f.Size = UDim2.new(0, size, 0, size)
    f.BackgroundColor3 = color
    f.BorderSizePixel = 0
    f.Parent = parent
    mkCorner(math.floor(size/2), f)
    return f
end

function VI.pencil(parent, color)
    -- Pensil diagonal: badan panjang miring + tip lancip + ferrule band
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Badan pensil
    local body = Instance.new("Frame")
    body.Size = UDim2.new(0, 4, 0, 10)
    body.Position = UDim2.new(0.5, -2, 0, 1)
    body.BackgroundColor3 = color
    body.BorderSizePixel = 0
    body.Rotation = 35
    body.Parent = wrap
    mkCorner(1, body)
    -- Ferrule band (gelap)
    local ferrule = Instance.new("Frame")
    ferrule.Size = UDim2.new(0, 4, 0, 1)
    ferrule.Position = UDim2.new(0.5, -2, 0.5, 1)
    ferrule.BackgroundColor3 = color
    ferrule.BorderSizePixel = 0
    ferrule.Rotation = 35
    ferrule.Parent = wrap
    -- Tip kayu (segitiga via 2 diamond)
    local tip = Instance.new("Frame")
    tip.Size = UDim2.new(0, 3, 0, 3)
    tip.Position = UDim2.new(0.5, -1, 1, -4)
    tip.BackgroundColor3 = color
    tip.BorderSizePixel = 0
    tip.Rotation = 35
    tip.Parent = wrap
    mkCorner(1, tip)
    -- Garis goresan kecil (preview "menggambar")
    local mark = Instance.new("Frame")
    mark.Size = UDim2.new(0, 4, 0, 1)
    mark.Position = UDim2.new(1, -5, 1, -2)
    mark.BackgroundColor3 = color
    mark.BorderSizePixel = 0
    mark.Parent = wrap
    return wrap
end

function VI.eraser(parent, color)
    -- Penghapus 2 segmen + sweep stroke di bawah
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Body penghapus (miring)
    local body = Instance.new("Frame")
    body.Size = UDim2.new(0, 11, 0, 6)
    body.Position = UDim2.new(0.5, -5, 0, 3)
    body.BackgroundColor3 = color
    body.BorderSizePixel = 0
    body.Rotation = -20
    body.Parent = wrap
    mkCorner(2, body)
    -- Garis pemisah segmen tengah
    local seam = Instance.new("Frame")
    seam.Size = UDim2.new(0, 11, 0, 1)
    seam.Position = UDim2.new(0.5, -5, 0, 5)
    seam.BackgroundColor3 = color
    seam.BackgroundTransparency = 0.5
    seam.BorderSizePixel = 0
    seam.Rotation = -20
    seam.Parent = wrap
    -- Serpihan hapus (3 dot kecil)
    for i = 0, 2 do
        local dot = Instance.new("Frame")
        dot.Size = UDim2.new(0, 2, 0, 2)
        dot.Position = UDim2.new(0, 2 + i*4, 1, -3)
        dot.BackgroundColor3 = color
        dot.BackgroundTransparency = 0.3
        dot.BorderSizePixel = 0
        dot.Parent = wrap
        mkCorner(1, dot)
    end
    return wrap
end

function VI.paint(parent, color)
    -- Kuas cat: gagang miring + ferrule + bulu kuas + goresan cat
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Gagang kuas (miring)
    local handle = Instance.new("Frame")
    handle.Size = UDim2.new(0, 3, 0, 7)
    handle.Position = UDim2.new(1, -5, 0, 1)
    handle.BackgroundColor3 = color
    handle.BorderSizePixel = 0
    handle.Rotation = 35
    handle.Parent = wrap
    mkCorner(1, handle)
    -- Ferrule (band logam)
    local ferrule = Instance.new("Frame")
    ferrule.Size = UDim2.new(0, 6, 0, 2)
    ferrule.Position = UDim2.new(0, 4, 0, 6)
    ferrule.BackgroundColor3 = color
    ferrule.BorderSizePixel = 0
    ferrule.Rotation = 35
    ferrule.Parent = wrap
    mkCorner(1, ferrule)
    -- Bulu kuas (warna)
    local bristle = Instance.new("Frame")
    bristle.Size = UDim2.new(0, 7, 0, 4)
    bristle.Position = UDim2.new(0, 1, 0, 8)
    bristle.BackgroundColor3 = color
    bristle.BorderSizePixel = 0
    bristle.Rotation = 35
    bristle.Parent = wrap
    mkCorner(1, bristle)
    -- Goresan cat tebal di bawah
    local stroke1 = Instance.new("Frame")
    stroke1.Size = UDim2.new(0, 9, 0, 1)
    stroke1.Position = UDim2.new(0, 2, 1, -2)
    stroke1.BackgroundColor3 = color
    stroke1.BorderSizePixel = 0
    stroke1.Parent = wrap
    mkCorner(1, stroke1)
    -- Goresan cat tipis (echo)
    local stroke2 = Instance.new("Frame")
    stroke2.Size = UDim2.new(0, 6, 0, 1)
    stroke2.Position = UDim2.new(0, 2, 1, -1)
    stroke2.BackgroundColor3 = color
    stroke2.BackgroundTransparency = 0.5
    stroke2.BorderSizePixel = 0
    stroke2.Parent = wrap
    return wrap
end

function VI.convert(parent, color)
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 14, 0, 14)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    local top = Instance.new("Frame")
    top.Size = UDim2.new(0, 10, 0, 2)
    top.Position = UDim2.new(0, 1, 0, 3)
    top.BackgroundColor3 = color
    top.BorderSizePixel = 0
    top.Parent = wrap
    mkCorner(1, top)
    local arrowTop = Instance.new("Frame")
    arrowTop.Size = UDim2.new(0, 4, 0, 4)
    arrowTop.Position = UDim2.new(0, 7, 0, 1)
    arrowTop.BackgroundColor3 = color
    arrowTop.BorderSizePixel = 0
    arrowTop.Rotation = 45
    arrowTop.Parent = wrap
    local bot = Instance.new("Frame")
    bot.Size = UDim2.new(0, 10, 0, 2)
    bot.Position = UDim2.new(0, 2, 0, 8)
    bot.BackgroundColor3 = color
    bot.BorderSizePixel = 0
    bot.Parent = wrap
    mkCorner(1, bot)
    local arrowBot = Instance.new("Frame")
    arrowBot.Size = UDim2.new(0, 4, 0, 4)
    arrowBot.Position = UDim2.new(0, 2, 0, 7)
    arrowBot.BackgroundColor3 = color
    arrowBot.BorderSizePixel = 0
    arrowBot.Rotation = 225
    arrowBot.Parent = wrap
    return wrap
end

function VI.usap(parent, color)
    -- Sapu klasik V1: gagang miring + kepala sapu + bulu vertikal + jejak sapuan
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Gagang sapu (miring 25°)
    local stick = Instance.new("Frame")
    stick.Size = UDim2.new(0, 2, 0, 8)
    stick.Position = UDim2.new(0, 4, 0, 1)
    stick.BackgroundColor3 = color
    stick.BorderSizePixel = 0
    stick.Rotation = 25
    stick.Parent = wrap
    mkCorner(1, stick)
    -- Pengikat (band)
    local band = Instance.new("Frame")
    band.Size = UDim2.new(0, 9, 0, 2)
    band.Position = UDim2.new(0.5, -4, 0, 7)
    band.BackgroundColor3 = color
    band.BorderSizePixel = 0
    band.Parent = wrap
    mkCorner(1, band)
    -- Kepala sapu (lebar)
    local head = Instance.new("Frame")
    head.Size = UDim2.new(0, 11, 0, 4)
    head.Position = UDim2.new(0.5, -5, 0, 9)
    head.BackgroundColor3 = color
    head.BorderSizePixel = 0
    head.Parent = wrap
    mkCorner(1, head)
    -- Bulu sapu (3 strip vertikal kontras)
    for i = 0, 2 do
        local b = Instance.new("Frame")
        b.Size = UDim2.new(0, 1, 0, 4)
        b.Position = UDim2.new(0, 4 + i*3, 0, 9)
        b.BackgroundColor3 = color
        b.BackgroundTransparency = 0.4
        b.BorderSizePixel = 0
        b.Parent = wrap
    end
    -- Jejak sapuan tunggal di bawah
    local trail = Instance.new("Frame")
    trail.Size = UDim2.new(0, 13, 0, 1)
    trail.Position = UDim2.new(0, 1, 1, -1)
    trail.BackgroundColor3 = color
    trail.BackgroundTransparency = 0.3
    trail.BorderSizePixel = 0
    trail.Parent = wrap
    return wrap
end

function VI.usap2(parent, color)
    -- Sapu V2: identitas berbeda — sapu LEBIH RAMPING (blok tipis V2)
    -- + DUA jejak sapuan (mewakili "double precision sweep") + badge V2 di pojok
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Gagang sapu (miring lebih curam = "presisi")
    local stick = Instance.new("Frame")
    stick.Size = UDim2.new(0, 2, 0, 7)
    stick.Position = UDim2.new(0, 4, 0, 2)
    stick.BackgroundColor3 = color
    stick.BorderSizePixel = 0
    stick.Rotation = 30
    stick.Parent = wrap
    mkCorner(1, stick)
    -- Band pengikat
    local band = Instance.new("Frame")
    band.Size = UDim2.new(0, 9, 0, 2)
    band.Position = UDim2.new(0.5, -4, 0, 7)
    band.BackgroundColor3 = color
    band.BorderSizePixel = 0
    band.Parent = wrap
    mkCorner(1, band)
    -- Kepala sapu LEBIH TIPIS (V2 = blok 8 stud, lebih rendah)
    local head = Instance.new("Frame")
    head.Size = UDim2.new(0, 11, 0, 2)
    head.Position = UDim2.new(0.5, -5, 0, 9)
    head.BackgroundColor3 = color
    head.BorderSizePixel = 0
    head.Parent = wrap
    mkCorner(1, head)
    -- Bulu sapu (4 strip lebih rapat)
    for i = 0, 3 do
        local b = Instance.new("Frame")
        b.Size = UDim2.new(0, 1, 0, 2)
        b.Position = UDim2.new(0, 4 + i*2, 0, 9)
        b.BackgroundColor3 = color
        b.BackgroundTransparency = 0.4
        b.BorderSizePixel = 0
        b.Parent = wrap
    end
    -- DUA jejak sapuan paralel (ciri khas V2: konsisten lapisan)
    local trail1 = Instance.new("Frame")
    trail1.Size = UDim2.new(0, 13, 0, 1)
    trail1.Position = UDim2.new(0, 1, 1, -3)
    trail1.BackgroundColor3 = color
    trail1.BackgroundTransparency = 0.5
    trail1.BorderSizePixel = 0
    trail1.Parent = wrap
    local trail2 = Instance.new("Frame")
    trail2.Size = UDim2.new(0, 13, 0, 1)
    trail2.Position = UDim2.new(0, 1, 1, -1)
    trail2.BackgroundColor3 = color
    trail2.BorderSizePixel = 0
    trail2.Parent = wrap
    return wrap
end

function VI.cube(parent, color)
    -- Kubus isometrik: 3 sisi (front, top, side) untuk efek 3D solid
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Front face (kanan-bawah, paling terang)
    local front = Instance.new("Frame")
    front.Size = UDim2.new(0, 9, 0, 9)
    front.Position = UDim2.new(0, 1, 0, 6)
    front.BackgroundColor3 = color
    front.BorderSizePixel = 0
    front.Parent = wrap
    mkCorner(1, front)
    -- Side face (kanan, gelap)
    local side = Instance.new("Frame")
    side.Size = UDim2.new(0, 5, 0, 9)
    side.Position = UDim2.new(0, 10, 0, 4)
    side.BackgroundColor3 = color
    side.BackgroundTransparency = 0.45
    side.BorderSizePixel = 0
    side.Parent = wrap
    mkCorner(1, side)
    -- Top face (atas, sedang)
    local top2 = Instance.new("Frame")
    top2.Size = UDim2.new(0, 9, 0, 5)
    top2.Position = UDim2.new(0, 3, 0, 1)
    top2.BackgroundColor3 = color
    top2.BackgroundTransparency = 0.25
    top2.BorderSizePixel = 0
    top2.Parent = wrap
    mkCorner(1, top2)
    return wrap
end

function VI.cylinder(parent, color)
    -- Silinder: tabung tegak + 2 ellipse (top & bottom rim)
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Body silinder
    local body = Instance.new("Frame")
    body.Size = UDim2.new(0, 9, 0, 10)
    body.Position = UDim2.new(0.5, -4, 0, 3)
    body.BackgroundColor3 = color
    body.BorderSizePixel = 0
    body.Parent = wrap
    -- Highlight stripe vertikal (kiri, supaya terlihat melengkung)
    local hl = Instance.new("Frame")
    hl.Size = UDim2.new(0, 2, 0, 10)
    hl.Position = UDim2.new(0.5, -3, 0, 3)
    hl.BackgroundColor3 = color
    hl.BackgroundTransparency = 0.5
    hl.BorderSizePixel = 0
    hl.Parent = wrap
    -- Top ellipse (rim atas)
    local topRim = Instance.new("Frame")
    topRim.Size = UDim2.new(0, 9, 0, 4)
    topRim.Position = UDim2.new(0.5, -4, 0, 1)
    topRim.BackgroundColor3 = color
    topRim.BackgroundTransparency = 0.25
    topRim.BorderSizePixel = 0
    topRim.Parent = wrap
    mkCorner(2, topRim)
    -- Bottom curve (sedikit melengkung di bawah)
    local botRim = Instance.new("Frame")
    botRim.Size = UDim2.new(0, 9, 0, 3)
    botRim.Position = UDim2.new(0.5, -4, 0, 12)
    botRim.BackgroundColor3 = color
    botRim.BorderSizePixel = 0
    botRim.Parent = wrap
    mkCorner(2, botRim)
    return wrap
end

function VI.ball(parent, color)
    -- Bola dengan highlight + shadow ring untuk kesan 3D
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Body bola
    local circle = Instance.new("Frame")
    circle.Size = UDim2.new(0, 12, 0, 12)
    circle.Position = UDim2.new(0.5, -6, 0.5, -6)
    circle.BackgroundColor3 = color
    circle.BorderSizePixel = 0
    circle.Parent = wrap
    mkCorner(6, circle)
    -- Highlight specular (kiri-atas, kecil, bulat)
    local spec = Instance.new("Frame")
    spec.Size = UDim2.new(0, 4, 0, 4)
    spec.Position = UDim2.new(0.5, -4, 0.5, -4)
    spec.BackgroundColor3 = color
    spec.BackgroundTransparency = 0.4
    spec.BorderSizePixel = 0
    spec.Parent = wrap
    mkCorner(2, spec)
    -- Shadow crescent (kanan-bawah)
    local shadow = Instance.new("Frame")
    shadow.Size = UDim2.new(0, 6, 0, 3)
    shadow.Position = UDim2.new(0.5, 0, 0.5, 1)
    shadow.BackgroundColor3 = color
    shadow.BackgroundTransparency = 0.6
    shadow.BorderSizePixel = 0
    shadow.Parent = wrap
    mkCorner(3, shadow)
    return wrap
end

function VI.closeX(parent, color)
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 12, 0, 12)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    local line1 = Instance.new("Frame")
    line1.Size = UDim2.new(0, 2, 0, 12)
    line1.AnchorPoint = Vector2.new(0.5, 0.5)
    line1.Position = UDim2.new(0.5, 0, 0.5, 0)
    line1.BackgroundColor3 = color
    line1.BorderSizePixel = 0
    line1.Rotation = 45
    line1.Parent = wrap
    mkCorner(1, line1)
    local line2 = Instance.new("Frame")
    line2.Size = UDim2.new(0, 2, 0, 12)
    line2.AnchorPoint = Vector2.new(0.5, 0.5)
    line2.Position = UDim2.new(0.5, 0, 0.5, 0)
    line2.BackgroundColor3 = color
    line2.BorderSizePixel = 0
    line2.Rotation = -45
    line2.Parent = wrap
    mkCorner(1, line2)
    return wrap
end

function VI.arrow(parent, color, rotation)
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 12, 0, 12)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    local line = Instance.new("Frame")
    line.Size = UDim2.new(0, 2, 0, 9)
    line.AnchorPoint = Vector2.new(0.5, 0.5)
    line.Position = UDim2.new(0.5, 0, 0.5, 0)
    line.BackgroundColor3 = color
    line.BorderSizePixel = 0
    line.Rotation = rotation or 0
    line.Parent = wrap
    mkCorner(1, line)
    local head = Instance.new("Frame")
    head.Size = UDim2.new(0, 5, 0, 5)
    head.AnchorPoint = Vector2.new(0.5, 0.5)
    head.Position = UDim2.new(0.5, 0, 0, 3)
    head.BackgroundColor3 = color
    head.BorderSizePixel = 0
    head.Rotation = (rotation or 0) + 45
    head.Parent = wrap
    return wrap
end

function VI.power(parent, color)
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 14, 0, 14)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    local ring = Instance.new("Frame")
    ring.Size = UDim2.new(0, 10, 0, 10)
    ring.Position = UDim2.new(0.5, -5, 0.5, -4)
    ring.BackgroundTransparency = 1
    ring.BorderSizePixel = 0
    ring.Parent = wrap
    mkCorner(5, ring)
    mkStroke(2, color, ring)
    local gap = Instance.new("Frame")
    gap.Size = UDim2.new(0, 4, 0, 4)
    gap.Position = UDim2.new(0.5, -2, 0, 0)
    gap.BackgroundColor3 = C.BG
    gap.BorderSizePixel = 0
    gap.Parent = wrap
    local stem = Instance.new("Frame")
    stem.Size = UDim2.new(0, 2, 0, 5)
    stem.Position = UDim2.new(0.5, -1, 0, 0)
    stem.BackgroundColor3 = color
    stem.BorderSizePixel = 0
    stem.Parent = wrap
    mkCorner(1, stem)
    return wrap
end

