function VI.save(parent, color)
    -- Floppy disk klasik: body + label slip atas + label slip bawah + slot logam
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Body floppy
    local body = Instance.new("Frame")
    body.Size = UDim2.new(0, 14, 0, 14)
    body.Position = UDim2.new(0.5, -7, 0.5, -7)
    body.BackgroundColor3 = color
    body.BorderSizePixel = 0
    body.Parent = wrap
    mkCorner(2, body)
    -- Slot logam atas (lebih gelap, mewakili shutter)
    local shutter = Instance.new("Frame")
    shutter.Size = UDim2.new(0, 10, 0, 4)
    shutter.Position = UDim2.new(0.5, -5, 0.5, -7)
    shutter.BackgroundColor3 = color
    shutter.BackgroundTransparency = 0.55
    shutter.BorderSizePixel = 0
    shutter.Parent = wrap
    -- Lubang shutter
    local slot = Instance.new("Frame")
    slot.Size = UDim2.new(0, 1, 0, 3)
    slot.Position = UDim2.new(0.5, 2, 0.5, -7)
    slot.BackgroundColor3 = color
    slot.BackgroundTransparency = 0.85
    slot.BorderSizePixel = 0
    slot.Parent = wrap
    -- Label slip bawah (area tulis)
    local label = Instance.new("Frame")
    label.Size = UDim2.new(0, 10, 0, 6)
    label.Position = UDim2.new(0.5, -5, 0.5, 0)
    label.BackgroundColor3 = color
    label.BackgroundTransparency = 0.6
    label.BorderSizePixel = 0
    label.Parent = wrap
    mkCorner(1, label)
    -- 2 garis di label
    for i = 0, 1 do
        local ln = Instance.new("Frame")
        ln.Size = UDim2.new(0, 7, 0, 1)
        ln.Position = UDim2.new(0.5, -3, 0.5, 1 + i*2)
        ln.BackgroundColor3 = color
        ln.BorderSizePixel = 0
        ln.Parent = wrap
    end
    return wrap
end

function VI.folder(parent, color)
    -- Folder dengan tab dan flap atas (look 3D file folder)
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, 16, 0, 16)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- Tab folder (kecil di kiri-atas)
    local tab = Instance.new("Frame")
    tab.Size = UDim2.new(0, 6, 0, 3)
    tab.Position = UDim2.new(0, 1, 0, 3)
    tab.BackgroundColor3 = color
    tab.BackgroundTransparency = 0.3
    tab.BorderSizePixel = 0
    tab.Parent = wrap
    mkCorner(1, tab)
    -- Body folder (badan utama)
    local base = Instance.new("Frame")
    base.Size = UDim2.new(0, 14, 0, 9)
    base.Position = UDim2.new(0.5, -7, 0, 5)
    base.BackgroundColor3 = color
    base.BorderSizePixel = 0
    base.Parent = wrap
    mkCorner(2, base)
    -- Flap atas (penutup folder, lebih terang)
    local flap = Instance.new("Frame")
    flap.Size = UDim2.new(0, 14, 0, 2)
    flap.Position = UDim2.new(0.5, -7, 0, 5)
    flap.BackgroundColor3 = color
    flap.BackgroundTransparency = 0.4
    flap.BorderSizePixel = 0
    flap.Parent = wrap
    mkCorner(1, flap)
    return wrap
end

-- Ikon palu vektor (untuk logo badge)
function VI.hammer(parent, color, size)
    size = size or 20
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, size, 0, size)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent
    -- kepala palu (kotak lebar di atas kiri)
    local head = Instance.new("Frame")
    head.Size             = UDim2.new(0, math.floor(size*0.55), 0, math.floor(size*0.38))
    head.Position         = UDim2.new(0, 0, 0, 0)
    head.BackgroundColor3 = color
    head.BorderSizePixel  = 0
    head.Parent           = wrap
    mkCorner(math.floor(size*0.1), head)
    -- bagian depan kepala lebih gelap
    local headFace = Instance.new("Frame")
    headFace.Size             = UDim2.new(0, math.floor(size*0.14), 1, 0)
    headFace.Position         = UDim2.new(1, -math.floor(size*0.14), 0, 0)
    headFace.BackgroundColor3 = Color3.new(
        math.max(0, color.R - 0.15),
        math.max(0, color.G - 0.15),
        math.max(0, color.B - 0.15)
    )
    headFace.BorderSizePixel  = 0
    headFace.Parent           = head
    mkCorner(math.floor(size*0.08), headFace)
    -- gagang miring (Rectangle dirotasi)
    local handle = Instance.new("Frame")
    handle.Size             = UDim2.new(0, math.floor(size*0.22), 0, math.floor(size*0.65))
    handle.AnchorPoint      = Vector2.new(0.5, 0)
    handle.Position         = UDim2.new(0, math.floor(size*0.42), 0, math.floor(size*0.28))
    handle.BackgroundColor3 = Color3.new(
        math.min(1, color.R + 0.1),
        math.min(1, color.G - 0.05),
        math.min(1, color.B - 0.05)
    )
    handle.BorderSizePixel  = 0
    handle.Rotation         = 18
    handle.Parent           = wrap
    mkCorner(math.floor(size*0.1), handle)
    return wrap
end

-- Ikon gunung vektor (dua puncak, perspektif depan)
function VI.mountain(parent, color, size)
    size = size or 20
    local wrap = Instance.new("Frame")
    wrap.Size = UDim2.new(0, size, 0, size)
    wrap.BackgroundTransparency = 1
    wrap.Parent = parent

    -- Gunung kiri (lebih kecil/belakang) — puncak abu terang
    local ml_body = Instance.new("Frame")
    ml_body.Size             = UDim2.new(0, math.floor(size*0.55), 0, math.floor(size*0.55))
    ml_body.Position         = UDim2.new(0, 0, 1, -math.floor(size*0.55))
    ml_body.BackgroundColor3 = Color3.new(
        math.min(1, color.R + 0.18),
        math.min(1, color.G + 0.18),
        math.min(1, color.B + 0.18))
    ml_body.BorderSizePixel  = 0
    ml_body.Rotation         = 45
    ml_body.Parent           = wrap

    -- Gunung kanan (lebih besar/depan) — warna utama
    local mr_body = Instance.new("Frame")
    mr_body.Size             = UDim2.new(0, math.floor(size*0.72), 0, math.floor(size*0.72))
    mr_body.AnchorPoint      = Vector2.new(0.5, 1)
    mr_body.Position         = UDim2.new(0.62, 0, 1, 0)
    mr_body.BackgroundColor3 = color
    mr_body.BorderSizePixel  = 0
    mr_body.Rotation         = 45
    mr_body.Parent           = wrap

    -- Salju di puncak kanan (segitiga kecil putih)
    local snow = Instance.new("Frame")
    snow.Size             = UDim2.new(0, math.floor(size*0.22), 0, math.floor(size*0.22))
    snow.AnchorPoint      = Vector2.new(0.5, 1)
    snow.Position         = UDim2.new(0.62, 0, 0.36, 0)
    snow.BackgroundColor3 = Color3.fromRGB(230, 240, 255)
    snow.BorderSizePixel  = 0
    snow.Rotation         = 45
    snow.Parent           = wrap

    -- Dasar/tanah strip bawah
    local base = Instance.new("Frame")
    base.Size             = UDim2.new(1, 0, 0, math.floor(size*0.12))
    base.Position         = UDim2.new(0, 0, 1, -math.floor(size*0.12))
    base.BackgroundColor3 = Color3.new(
        math.min(1, color.R*0.6),
        math.min(1, color.G*0.7),
        math.min(1, color.B*0.5))
    base.BorderSizePixel  = 0
    base.Parent           = wrap
    mkCorner(1, base)
    return wrap
end

