-- Warna aksen per section
local SECTION_COLORS = {
    ["TERRAIN TYPE"] = C.BLUE,
    ["GRASS COLOR"]  = C.GREEN,
    ["GROUND COLOR"] = C.ORANGE,
    ["SHAPE"]        = C.CYAN,
    ["MODE"]         = C.PURPLE,
    ["BRUSH SIZE"]   = C.GOLD,
    ["ACTIONS"]      = C.RED,
    ["WIND"]         = C.CYAN,
    ["LOADER"]       = Color3.fromRGB(100, 160, 255),
    ["CONVERT"]      = C.GREEN,
}
-- Ikon vektor per section
local SECTION_ICONS = {
    ["TERRAIN TYPE"] = function(p) VI.cube(p, C.BLUE) end,
    ["GRASS COLOR"]  = function(p) VI.dot(p, C.GREEN, 8) end,
    ["GROUND COLOR"] = function(p) VI.dot(p, C.ORANGE, 8) end,
    ["SHAPE"]        = function(p) VI.ball(p, C.CYAN) end,
    ["MODE"]         = function(p) VI.pencil(p, C.PURPLE) end,
    ["BRUSH SIZE"]   = function(p) VI.minus(p, C.GOLD) end,
    ["ACTIONS"]      = function(p) VI.save(p, C.RED) end,
    ["WIND"]         = function(p) VI.arrow(p, C.CYAN, 0) end,
    ["LOADER"]       = function(p) VI.folder(p, Color3.fromRGB(100,160,255)) end,
    ["CONVERT"]      = function(p) VI.cube(p, C.GREEN) end,
}

local function secLabel(txt, lo)
    local accentCol = SECTION_COLORS[txt] or C.GOLD
    local wrap = Instance.new("Frame")
    wrap.Size               = UDim2.new(1, 0, 0, 22)
    wrap.BackgroundTransparency = 1
    wrap.LayoutOrder        = lo
    wrap.Parent             = body

    -- Pill background for label
    local pill = Instance.new("Frame")
    pill.Size             = UDim2.new(0, 0, 1, 0)
    pill.AutomaticSize    = Enum.AutomaticSize.X
    pill.BackgroundColor3 = Color3.new(accentCol.R*0.15, accentCol.G*0.15, accentCol.B*0.15)
    pill.BorderSizePixel  = 0
    pill.Parent           = wrap
    mkCorner(5, pill)
    mkPadding(0, 0, 6, 10, pill)

    local pillLL = Instance.new("UIListLayout")
    pillLL.FillDirection       = Enum.FillDirection.Horizontal
    pillLL.HorizontalAlignment = Enum.HorizontalAlignment.Left
    pillLL.VerticalAlignment   = Enum.VerticalAlignment.Center
    pillLL.Padding             = UDim.new(0, 5)
    pillLL.Parent              = pill

    -- Accent bar
    local bar = Instance.new("Frame")
    bar.Size             = UDim2.new(0, 3, 1, -4)
    bar.BackgroundColor3 = accentCol
    bar.BorderSizePixel  = 0
    bar.Parent           = pill
    mkCorner(2, bar)

    -- Icon
    if SECTION_ICONS[txt] then
        local iconH = Instance.new("Frame")
        iconH.Size               = UDim2.new(0, 12, 0, 12)
        iconH.BackgroundTransparency = 1
        iconH.Parent             = pill
        SECTION_ICONS[txt](iconH)
    end

    -- Label text
    local lbl = Instance.new("TextLabel")
    lbl.Size               = UDim2.new(0, 0, 1, 0)
    lbl.AutomaticSize      = Enum.AutomaticSize.X
    lbl.BackgroundTransparency = 1
    lbl.Text               = txt
    lbl.TextColor3         = accentCol
    lbl.TextSize           = 8
    lbl.Font               = Enum.Font.GothamBlack
    lbl.TextXAlignment     = Enum.TextXAlignment.Left
    lbl.Parent             = pill
    return wrap
end

