    -- Indicator dot pojok kanan-atas (visible saat selected)
    local selDot = Instance.new("Frame")
    selDot.Size              = UDim2.new(0, 7, 0, 7)
    selDot.Position          = UDim2.new(1, -10, 0, 3)
    selDot.BackgroundColor3  = C.GOLD
    selDot.BorderSizePixel   = 0
    selDot.Visible           = false
    selDot.ZIndex            = 3
    selDot.Parent            = btn
    mkCorner(4, selDot)

    local s = mkStroke(1, C.BORDER, btn)
    terrainBtns[t.name] = { btn=btn, stroke=s, lbl=lbl, mat=t.mat, dot=selDot }

    connectBtn(btn, function()
        selectedTerrain = t.mat
        for _, e in pairs(terrainBtns) do
            e.stroke.Color     = C.BORDER
            e.stroke.Thickness = 1
            e.lbl.TextColor3   = C.SUBTEXT
            e.btn.BackgroundColor3 = C.CARD
            e.dot.Visible      = false
        end
        s.Color               = C.GOLD
        s.Thickness           = 1.5
        lbl.TextColor3        = C.TEXT
        btn.BackgroundColor3  = C.CARD2
        selDot.Visible        = true
    end)
end
