    gTitle.Font               = Enum.Font.GothamBlack
    gTitle.TextXAlignment     = Enum.TextXAlignment.Left
    gTitle.Parent             = gHeader

    -- Preview warna aktif
    local gActiveDot = Instance.new("Frame")
    gActiveDot.Size             = UDim2.new(0, 18, 0, 18)
    gActiveDot.Position         = UDim2.new(1, -72, 0.5, -9)
    gActiveDot.BackgroundColor3 = activeGrassColor
    gActiveDot.BorderSizePixel  = 0
    gActiveDot.Parent           = gHeader
    mkCorner(4, gActiveDot)
    mkStroke(1, C.BORDER, gActiveDot)

    local gActiveName = Instance.new("TextLabel")
    gActiveName.Size               = UDim2.new(0, 50, 1, 0)
    gActiveName.Position           = UDim2.new(1, -52, 0, 0)
    gActiveName.BackgroundTransparency = 1
    gActiveName.Text               = "Grass"
    gActiveName.TextColor3         = C.TEXT
    gActiveName.TextSize           = 8
    gActiveName.Font               = Enum.Font.Gotham
    gActiveName.TextXAlignment     = Enum.TextXAlignment.Right
    gActiveName.Parent             = gHeader

    -- Separator
    local gSep = Instance.new("Frame")
    gSep.Size             = UDim2.new(1, 0, 0, 1)
    gSep.BackgroundColor3 = C.BORDER
    gSep.BorderSizePixel  = 0
    gSep.Parent           = grassSection

    -- Swatch grid container
    local gGrid = Instance.new("Frame")
    gGrid.Size               = UDim2.new(1, 0, 0, 0)
    gGrid.AutomaticSize      = Enum.AutomaticSize.Y
    gGrid.BackgroundTransparency = 1
    gGrid.Parent             = grassSection

    local gLayout = Instance.new("UIGridLayout")
    gLayout.CellSize       = UDim2.new(0, 28, 0, 28)
    gLayout.CellPadding    = UDim2.new(0, 4, 0, 4)
    gLayout.FillDirection  = Enum.FillDirection.Horizontal
    gLayout.HorizontalAlignment = Enum.HorizontalAlignment.Left
    gLayout.SortOrder      = Enum.SortOrder.LayoutOrder
    gLayout.Parent         = gGrid

    local gListLayout = Instance.new("UIListLayout")
    gListLayout.Padding   = UDim.new(0, 6)
    gListLayout.SortOrder = Enum.SortOrder.LayoutOrder
    gListLayout.Parent    = grassSection

    local grassActiveSwatch = nil

    local function selectGrassColor(swFrame, col, name)
        -- Reset semua swatch sebelumnya
        if grassActiveSwatch and grassActiveSwatch ~= swFrame then
            pcall(function()
                grassActiveSwatch:FindFirstChildOfClass("UIStroke").Color = C.BORDER
                grassActiveSwatch:FindFirstChildOfClass("UIStroke").Thickness = 1
            end)
        end
        grassActiveSwatch = swFrame
        local st = swFrame:FindFirstChildOfClass("UIStroke")
        if st then st.Color = C.GREEN; st.Thickness = 2 end
        gActiveDot.BackgroundColor3 = col
        gActiveName.Text = name
        activeGrassColor = col
        -- Apply ke terrain
        local T = workspace:FindFirstChild("Terrain")
        if T then
            for _, mat in ipairs(GRASS_MATERIALS) do
                pcall(function() T:SetMaterialColor(mat, col) end)
            end
        end
    end

    for i, gc in ipairs(GRASS_COLORS) do
        local sw = Instance.new("Frame")
        sw.Name             = "ColorSwatch_"..gc.name
        sw.Size             = UDim2.new(0, 28, 0, 28)
        sw.BackgroundColor3 = gc.color
        sw.BorderSizePixel  = 0
        sw.LayoutOrder      = i
        sw.Parent           = gGrid
        mkCorner(5, sw)
        local swSt = mkStroke(1, C.BORDER, sw)

        -- Tooltip label (nama warna, muncul saat hover)
        local tooltip = Instance.new("TextLabel")
        tooltip.Size               = UDim2.new(0, 48, 0, 14)
        tooltip.Position           = UDim2.new(0.5, -24, -0.6, 0)
        tooltip.BackgroundColor3   = Color3.fromRGB(20,20,20)
        tooltip.BackgroundTransparency = 0.2
        tooltip.Text               = gc.name
        tooltip.TextColor3         = C.TEXT
        tooltip.TextSize           = 7
        tooltip.Font               = Enum.Font.GothamBold
        tooltip.TextXAlignment     = Enum.TextXAlignment.Center
        tooltip.Visible            = false
        tooltip.ZIndex             = 10
        tooltip.BorderSizePixel    = 0
        tooltip.Parent             = sw
        mkCorner(3, tooltip)

        local btn = Instance.new("TextButton")
        btn.Size             = UDim2.new(1, 0, 1, 0)
        btn.BackgroundTransparency = 1
        btn.Text             = ""
        btn.ZIndex           = 5
        btn.Parent           = sw

        local capSw = sw
        local capGc = gc
        btn.MouseEnter:Connect(function() tooltip.Visible = true end)
        btn.MouseLeave:Connect(function() tooltip.Visible = false end)
        btn.MouseButton1Click:Connect(function()
            selectGrassColor(capSw, capGc.color, capGc.name)
        end)

        -- Mark active jika warna default
        if i == 9 then  -- index 9 = "Grass" (default)
            grassActiveSwatch = sw
            swSt.Color = C.GREEN; swSt.Thickness = 2
        end
    end
end

