    iconHolder.Parent             = inner
    -- Ikon selalu pakai warna mode-nya supaya jelas terlihat (tidak abu-abu)
    VI[m.icon](iconHolder, m.col)

    local lbl = Instance.new("TextLabel")
    lbl.Size               = UDim2.new(1, -2, 0, 11)
    lbl.BackgroundTransparency = 1
    lbl.Text               = m.label
    lbl.TextColor3         = C.SUBTEXT
    lbl.TextSize           = 8
