    local s = mkStroke(1, C.BORDER, btn)
    modeBtns[m.name] = { btn=btn, stroke=s, icon=iconHolder, lbl=lbl, col=m.col }

    connectBtn(btn, function()
        brushMode = m.name
        for _, e in pairs(modeBtns) do
            e.stroke.Color         = C.BORDER
            e.stroke.Thickness     = 1
            e.lbl.TextColor3       = C.SUBTEXT
            e.btn.BackgroundColor3 = C.CARD
        end
        s.Color               = m.col
        s.Thickness           = 1.8
        lbl.TextColor3        = C.TEXT
        btn.BackgroundColor3  = C.CARD2
        if brushIndicator then
            brushIndicator:Destroy()
            brushIndicator = nil
        end
    end)
