local function updateSizeSlider(val)
    currentSize = math.clamp(math.round(val), 1, 64)
    local t = (currentSize - 1) / 63
    sizeFill.Size     = UDim2.new(t, 0, 1, 0)
    sizeThumb.Position = UDim2.new(t, 0, 0.5, 0)
    sizeDisplay.Text  = "SIZE: " .. tostring(currentSize)
end

local sizeDragging = false
sizeDragBtn.InputBegan:Connect(function(inp)
    if inp.UserInputType == Enum.UserInputType.MouseButton1
    or inp.UserInputType == Enum.UserInputType.Touch then
        sizeDragging = true
        local rel = inp.Position.X - sizeTrack.AbsolutePosition.X
        local pct = math.clamp(rel / sizeTrack.AbsoluteSize.X, 0, 1)
        updateSizeSlider(1 + pct * 63)
    end
end)
sizeDragBtn.InputEnded:Connect(function(inp)
    if inp.UserInputType == Enum.UserInputType.MouseButton1
    or inp.UserInputType == Enum.UserInputType.Touch then
        sizeDragging = false
    end
end)
sizeDragBtn.InputChanged:Connect(function(inp)
    if sizeDragging and (
        inp.UserInputType == Enum.UserInputType.MouseMovement or
        inp.UserInputType == Enum.UserInputType.Touch) then
        local rel = inp.Position.X - sizeTrack.AbsolutePosition.X
        local pct = math.clamp(rel / sizeTrack.AbsoluteSize.X, 0, 1)
        updateSizeSlider(1 + pct * 63)
    end
end)

