-- Helper: nama material pendek untuk subtitle
local function matName(m)
    return tostring(m):gsub("Enum%.Material%.", "")
end

-- Helper: sinkronkan chip warna + label material dari TERRAIN TYPE
local function syncConvertMaterialUI()
    local mat = selectedTerrain or Enum.Material.Grass
    convSubtitle.Text = "MATERIAL: " .. string.upper(matName(mat))
    -- Cari warna swatch dari terrainTypes biar chip cocok
    for _, t in ipairs(terrainTypes) do
        if t.mat == mat then
            convMatChip.BackgroundColor3 = t.color
            break
        end
    end
end

-- Update chip secara live (cek selectedTerrain tiap 0.25 dtk).
-- Ringan dan menjamin chip selalu sinkron walau user pindah material.
task.spawn(function()
    local lastMat = nil
    while convertSection.Parent do
        if selectedTerrain ~= lastMat then
            lastMat = selectedTerrain
            pcall(syncConvertMaterialUI)
        end
        task.wait(0.25)
    end
end)
syncConvertMaterialUI()

local function convertOneFolder(folderName, mat)
    local folder = Workspace:FindFirstChild(folderName)
    if not folder or not folder:IsA("Folder") then return 0 end
    local count = 0
    for _, part in ipairs(folder:GetChildren()) do
        if part:IsA("BasePart") then
            -- Tentukan kode shape utk dicatat di timeline
            -- 1=Block, 2=Ball, 3=Cylinder(part), 4=Wedge, 5=CornerWedge
            local shapeNum = 1
            if part:IsA("WedgePart") then shapeNum = 4
            elseif part:IsA("CornerWedgePart") then shapeNum = 5
            elseif part.Shape == Enum.PartType.Ball then shapeNum = 2
            elseif part.Shape == Enum.PartType.Cylinder then shapeNum = 3
            end

            local ok = pcall(function()
                if shapeNum == 4 or shapeNum == 5 then
                    Terrain:FillWedge(part.CFrame, part.Size, mat)
                elseif shapeNum == 2 then
                    Terrain:FillBall(part.Position, part.Size.X * 0.5, mat)
                elseif shapeNum == 3 then
                    -- ★ CYLINDER: tetap pakai FillCylinder (bentuk
                    --   silinder utuh), tetapi:
                    --   • height & radius dipadding sedikit (≥ 1 voxel
                    --     = 4 stud) supaya permukaannya rata sempurna,
                    --     tidak ada seam / cacat di pinggir akibat
                    --     pembulatan voxel terrain (resolusi 4 stud).
                    --   • Cylinder Part sumbu X → CFrame dirotasi 90°
                    --     pada Z agar sumbu Y FillCylinder sejajar.
                    local VOX = 4 -- ukuran voxel terrain Roblox
                    local h   = part.Size.X + VOX
                    local r   = math.max(part.Size.Y, part.Size.Z) * 0.5 + (VOX * 0.5)
                    Terrain:FillCylinder(
                        part.CFrame * CFrame.Angles(0, 0, math.rad(90)),
                        h, r, mat
                    )
                else
                    -- ★ BALOK: voksel kecil-kecil di lokal space CFrame (support rotasi, seperti silinder)
                    local VOX2 = 4
                    local ps2  = part.Size
                    local cf2  = part.CFrame
                    local hsx2, hsy2, hsz2 = ps2.X/2, ps2.Y/2, ps2.Z/2
                    local function sn2(v) return math.floor(v/VOX2)*VOX2 end
                    local vSz2 = Vector3.new(VOX2, VOX2, VOX2)
                    local cnt2 = 0
                    for lx2 = sn2(-hsx2), sn2(hsx2), VOX2 do
                        for ly2 = sn2(-hsy2), sn2(hsy2), VOX2 do
                            for lz2 = sn2(-hsz2), sn2(hsz2), VOX2 do
                                local wp2 = cf2 * Vector3.new(lx2+VOX2*0.5, ly2+VOX2*0.5, lz2+VOX2*0.5)
                                Terrain:FillBlock(CFrame.new(wp2), vSz2, mat)
                                cnt2 = cnt2+1
                                if cnt2%200 == 0 then task.wait() end
                            end
                        end
                    end
                end
            end)
            if ok then
                -- ★ Catat ke timeline supaya ikut export WS dan
                --   bisa di-load ulang lewat server script.
                local ori = part.Orientation
                local entry = {
                    type      = "partfill",
                    pos       = part.Position,
                    size      = math.max(part.Size.X, part.Size.Y, part.Size.Z),
                    size3     = part.Size,
                    rx        = ori.X,
                    ry        = ori.Y,
                    rz        = ori.Z,
                    material  = mat,
                    shape     = "Block",
                    shapeNum  = shapeNum,
                }
                table.insert(terrainData, entry)
                table.insert(allOps,      entry)

                part:Destroy()
                count = count + 1
            end
        end
    end
    -- Hapus folder kalau sudah kosong
    if #folder:GetChildren() == 0 then
        folder:Destroy()
    end
    return count
end

local convertBusy = false
convertBtn.MouseButton1Click:Connect(function()
    if convertBusy then return end
    convertBusy = true
    convertBtn.BackgroundColor3 = CONV_BUSY
    convGrad.Color = ColorSequence.new(
        Color3.fromRGB(255, 210, 80),
        Color3.fromRGB(220, 150, 20)
    )
    convertStatus.Text = "..."
    local mat = selectedTerrain or Enum.Material.Grass
    task.spawn(function()
        local total = 0
        for _, fn in ipairs(CONVERT_FOLDERS) do
            local n = convertOneFolder(fn, mat)
            total = total + n
            if n > 0 then task.wait() end
        end
        -- Sinkronkan counter STROKE setelah convert
        pcall(updateCounter)
        if total > 0 then
            convertBtn.BackgroundColor3 = CONV_DONE
            convGrad.Color = ColorSequence.new(CONV_GREEN_TOP, CONV_GREEN_BOT)
            convertStatus.Text = total .. " OK"
        else
            convertBtn.BackgroundColor3 = CONV_FAIL
            convGrad.Color = ColorSequence.new(
                Color3.fromRGB(240, 90, 80),
                Color3.fromRGB(200, 50, 45)
            )
            convertStatus.Text = "EMPTY"
        end
        task.wait(1.2)
        convertBtn.BackgroundColor3 = CONV_GREEN_TOP
        convGrad.Color = ColorSequence.new(CONV_GREEN_TOP, CONV_GREEN_BOT)
        convertStatus.Text = "READY"
        convertBusy = false
    end)
end)

