-- =========================================================
-- SERVER SCRIPT SOURCE
-- =========================================================
local SERVER_SCRIPT_SOURCE = [==[
-- ============================================================
--  TERRAIN AUTO-LOADER v19 by SYGKMUNII
--  Taruh di ServerScriptService. Tanpa loadstring manual.
--  Format chunk baru: D={t,x,y,z,s,m,sh}  P={x,y,z,s,m}
-- ============================================================
local WS       = game:GetService("Workspace")
local FOLDER   = "__SL_TerrainExports__"
local V        = 4
local THROTTLE = 60
local M        = Enum.Material
local V3       = Vector3.new
local CF       = CFrame.new

local T = WS:FindFirstChildOfClass("Terrain") or WS:WaitForChild("Terrain", 30)
if not T then warn("[SL-Loader] Terrain not found") return end

-- Fungsi applyPaint (paint mode)
local function apP(c, bs, tm)
    local function snap(v) return math.floor(v/V)*V end
    local h  = math.max(bs, V)
    local mn = V3(snap(c.X-h), snap(c.Y-h), snap(c.Z-h))
    local mx = V3(snap(c.X+h)+V, snap(c.Y+h)+V, snap(c.Z+h)+V)
    local reg = Region3.new(mn, mx):ExpandToGrid(V)
    local ok, mats, occs = pcall(T.ReadVoxels, T, reg, V)
    if not ok then return end
    local sx,sy,sz = mats.Size.X, mats.Size.Y, mats.Size.Z
    local nm, no = {}, {}
    for x = 1, sx do
        nm[x] = {} no[x] = {}
        for y = 1, sy do
            nm[x][y] = {} no[x][y] = {}
            for z = 1, sz do
                local m2, o2 = mats[x][y][z], occs[x][y][z]
                if o2 > 0 and m2 ~= M.Air then
                    nm[x][y][z] = tm; no[x][y][z] = o2
                else
                    nm[x][y][z] = m2; no[x][y][z] = o2
                end
            end
        end
    end
    pcall(T.WriteVoxels, T, reg, V, nm, no)
end

-- Eksekusi satu StringValue chunk
-- Format baru: script Lua yang langsung jalan (berisi local D={} dan loop)
-- Format lama: berisi local drawData / local paintData (fallback parser)
local function restoreEntry(sv)
    if not sv:IsA("StringValue") then return end
    local tries = 0
    repeat
        if sv.Value ~= "" then break end
        task.wait(0.1)
        tries = tries + 1
    until tries >= 100
    if sv.Value == "" then
        warn("[SL-Loader] Kosong, skip: " .. sv.Name)
        return
    end

    -- Parse langsung tanpa loadstring (tidak perlu LoadStringEnabled)
    local src = sv.Value

    -- Restore warna material dari header chunk (SetMaterialColor lines)
    for matName, r, g, b in src:gmatch(
        "T:SetMaterialColor%(Enum%.Material%.(%w+),%s*Color3%.fromRGB%((%d+),(%d+),(%d+)%)%)") do
        pcall(function()
            T:SetMaterialColor(M[matName], Color3.fromRGB(tonumber(r), tonumber(g), tonumber(b)))
        end)
    end

    -- Restore wind dari header chunk
    local wx, wz = src:match("GlobalWind=Vector3%.new%(([%-%.%d]+),0,([%-%.%d]+)%)")
    if wx and wz then
        pcall(function()
            workspace.GlobalWind = Vector3.new(tonumber(wx), 0, tonumber(wz))
        end)
    end

    local MAT = {
        [1]=M.Grass,[2]=M.Rock,[3]=M.Water,[4]=M.Ground,
        [5]=M.Sand,[6]=M.Snow,[7]=M.Ice,[8]=M.Mud,
        [9]=M.Sandstone,[10]=M.Limestone,[11]=M.Cobblestone,[12]=M.Basalt,
        [13]=M.Concrete,[14]=M.Salt,[15]=M.LeafyGrass,[16]=M.Pavement,
    }
    local drawN  = 0
    local paintN = 0

    -- ── Format baru: {t=N,x=N,y=N,z=N,s=N,m=N,sh=N}        (terrainData) ──
    -- ── Format baru: {x=N,y=N,z=N,s=N,m=N}                  (paintData)   ──
    -- ── Format baru: {t=6,x,y,z,s,sx,sy,sz,rx,ry,rz,m,sh}   (Part→Terrain)──
    -- Deteksi format: format baru punya "local D={" atau entry {t=N,
    local isNewFormat = src:find("local D={", 1, true)
        or src:find("local D = {", 1, true)
        or src:find("{t=1,", 1, true)
        or src:find("{t=2,", 1, true)
        or src:find("{t=3,", 1, true)
        or src:find("{t=4,", 1, true)
        or src:find("{t=6,", 1, true)
        or src:find("\n    {t=", 1, true)
        or src:find(",t=", 1, true)

    if isNewFormat then
        -- Parse format baru D={...} dan P={...}
        -- Terrain entries: t=1 draw, t=2 erase, t=3 usap, t=4 rata
        for entry in src:gmatch("{([^}]+)}") do
            -- Gunakan pattern yang hati-hati agar s= tidak match sh=
            local t  = tonumber(entry:match("^t=([%-%.%d]+)") or entry:match("[^s]t=([%-%.%d]+)") or entry:match(",t=([%-%.%d]+)"))
            local x  = tonumber(entry:match("[,{]?x=([%-%.%d]+)"))
            local y  = tonumber(entry:match("[,{]?y=([%-%.%d]+)"))
            local z  = tonumber(entry:match("[,{]?z=([%-%.%d]+)"))
            -- s= harus tidak diikuti 'h' (bukan sh=)
            local s  = tonumber(entry:match(",s=([%-%.%d]+)") or entry:match("^s=([%-%.%d]+)"))
            local m  = tonumber(entry:match("[,{]?m=([%d]+)"))
            local sh = tonumber(entry:match("[,{]?sh=([%d]+)")) or 1

            if t and x and y and z and s then
                local pos = V3(x, y, z)
                local mat = MAT[m] or M.Grass
                if t == 1 then
                    -- draw
                    if sh == 2 then pcall(T.FillBall, T, pos, s/2, mat)
                    elseif sh == 3 then pcall(T.FillCylinder, T, CF(pos), s/2, s, mat)
                    else pcall(T.FillBlock, T, CF(pos), V3(s,s,s), mat) end
                    drawN = drawN + 1
                elseif t == 2 then
                    -- erase
                    if sh == 2 then pcall(T.FillBall, T, pos, s/2, M.Air)
                    elseif sh == 3 then pcall(T.FillCylinder, T, CF(pos), s/2, s, M.Air)
                    else pcall(T.FillBlock, T, CF(pos), V3(s,s,s), M.Air) end
                    drawN = drawN + 1
                elseif t == 3 then
                    -- usap (V1 & V2): FillBlock di posisi yang sudah di-offset saat brush.
                    -- sH default = 8 stud (USAP V2 thin), atau nilai tersimpan (V1 lama).
                    local sH = tonumber(entry:match(",sH=([%-%.%d]+)") or entry:match("^sH=([%-%.%d]+)"))
                        or 8
                    local sw = s or 8
                    pcall(T.FillBlock, T, CF(pos), V3(sw, sH, sw), mat)
                    drawN = drawN + 1
                elseif t == 4 then
                    -- rata: flat fill
                    local sy2 = math.floor(y/4)*4
                    pcall(T.FillBlock, T, CF(V3(x, sy2+2, z)), V3(s+4,500,s+4), M.Air)
                    pcall(T.FillBlock, T, CF(V3(x, sy2+2, z)), V3(s,4,s), mat)
                    drawN = drawN + 1
                elseif t == 5 then
                    -- paint: ubah material voxel existing saja (tidak fill kosong)
                    pcall(apP, V3(x,y,z), s, mat)
                    paintN = paintN + 1
                elseif t == 6 then
                    -- Part → Terrain (size penuh + rotasi)
                    local sx2 = tonumber(entry:match(",sx=([%-%.%d]+)")) or s
                    local sy2 = tonumber(entry:match(",sy=([%-%.%d]+)")) or s
                    local sz2 = tonumber(entry:match(",sz=([%-%.%d]+)")) or s
                    local rx2 = tonumber(entry:match(",rx=([%-%.%d]+)")) or 0
                    local ry2 = tonumber(entry:match(",ry=([%-%.%d]+)")) or 0
                    local rz2 = tonumber(entry:match(",rz=([%-%.%d]+)")) or 0
                    local cf  = CF(pos) * CFrame.fromOrientation(
                        math.rad(rx2), math.rad(ry2), math.rad(rz2))
                    local sz3 = V3(sx2, sy2, sz2)
                    if sh == 2 then
                        pcall(T.FillBall, T, pos, math.max(sx2,sy2,sz2)/2, mat)
                    elseif sh == 3 then
                        -- ★ padding 1 voxel (4 stud) supaya permukaan
                        --   silinder rata sempurna, tanpa seam.
                        pcall(T.FillCylinder, T,
                            cf * CFrame.Angles(0,0,math.rad(90)),
                            sx2 + 4, math.max(sy2,sz2)/2 + 2, mat)
                    elseif sh == 4 or sh == 5 then
                        pcall(T.FillWedge, T, cf, sz3, mat)
                    else
                        pcall(T.FillBlock, T, cf, sz3, mat)
                    end
                    drawN = drawN + 1
                end
                if drawN > 0 and (drawN + paintN) % THROTTLE == 0 then task.wait() end
            elseif x and y and z and s and m and not t then
                -- paint entry (P={x,y,z,s,m} tanpa t=)
                local pos = V3(x, y, z)
                local mat = MAT[m] or M.Grass
                pcall(apP, pos, s, mat)
                paintN = paintN + 1
                if paintN > 0 and (drawN + paintN) % THROTTLE == 0 then task.wait() end
            end
        end
        print(string.format("[SL-Loader] %s => draw/erase=%d paint=%d smooth=%d (native-new)", sv.Name, drawN, paintN, drawN))
    else
        -- Fallback: parse format lama drawData/paintData
        local inDraw  = false
        local inPaint = false
        for rawline in (src .. "\n"):gmatch("([^\n]*)\n") do
            local line = rawline
            if string.find(line, "local drawData", 1, true) and string.find(line, "=", 1, true) then
                inDraw = true; inPaint = false
            elseif string.find(line, "local paintData", 1, true) and string.find(line, "=", 1, true) then
                inPaint = true; inDraw = false
            elseif string.sub(line, 1, 1) == "}" then
                inDraw = false; inPaint = false
            elseif inDraw then
                local x,y,z = string.match(line, "Vector3%.new%(([%-%.%d]+),([%-%.%d]+),([%-%.%d]+)%)")
                local sz = string.match(line, "size=([%-%.%d]+)")
                local mt = string.match(line, "mat=(%d+)")
                local sh = string.match(line, "shape=(%d+)")
                if x and sz and mt then
                    local pos  = V3(tonumber(x), tonumber(y), tonumber(z))
                    local size = tonumber(sz)
                    local mat  = MAT[tonumber(mt)] or M.Grass
                    local shp  = tonumber(sh) or 1
                    pcall(function()
                        if shp == 2 then T:FillBall(pos, size/2, mat)
                        elseif shp == 3 then T:FillCylinder(CF(pos), size/2, size, mat)
                        else T:FillBlock(CF(pos), V3(size,size,size), mat) end
                    end)
                    drawN = drawN + 1
                    if drawN % THROTTLE == 0 then task.wait() end
                end
            elseif inPaint then
                local x,y,z = string.match(line, "Vector3%.new%(([%-%.%d]+),([%-%.%d]+),([%-%.%d]+)%)")
                local sz = string.match(line, "size=([%-%.%d]+)")
                local mt = string.match(line, "mat=(%d+)")
                if x and sz and mt then
                    local pos = V3(tonumber(x), tonumber(y), tonumber(z))
                    local mat = MAT[tonumber(mt)] or M.Grass
                    pcall(apP, pos, tonumber(sz), mat)
                    paintN = paintN + 1
                    if paintN % THROTTLE == 0 then task.wait() end
                end
            end
        end
        print(string.format("[SL-Loader] %s => draw=%d paint=%d (native-legacy)", sv.Name, drawN, paintN))
    end
end

local function scanFolder(folder)
    -- Sort nama supaya chunk C1, C2, C3 diproses berurutan
    local children = folder:GetChildren()
    table.sort(children, function(a, b) return a.Name < b.Name end)
    local count = 0
    for _, child in ipairs(children) do
        if child:IsA("StringValue") then
            restoreEntry(child)  -- sequential: tunggu selesai sebelum lanjut
            count = count + 1
        end
    end
    print(string.format("[SL-Loader] Startup: %d chunk dari %s", count, FOLDER))
    folder.ChildAdded:Connect(function(child)
        task.wait(0.3)
        if child:IsA("StringValue") then
            restoreEntry(child)
        end
    end)
end

local folder = WS:FindFirstChild(FOLDER)
if not folder then
    local t0 = tick()
    repeat task.wait(0.5); folder = WS:FindFirstChild(FOLDER)
    until folder or (tick()-t0) > 30
end

if folder then
    scanFolder(folder)
else
    warn("[SL-Loader] Folder tidak ditemukan: " .. FOLDER)
    WS.ChildAdded:Connect(function(child)
        if child.Name == FOLDER then
            task.wait(0.2); scanFolder(child)
        end
    end)
end
]==]

