-- =========================================================
-- PANEL OPEN/CLOSE
-- =========================================================
local panelOpen = false

local function openPanel(frame, w, h)
    frame.Visible = true
    TweenService:Create(frame,
        TweenInfo.new(0.22, Enum.EasingStyle.Back, Enum.EasingDirection.Out),
        {Size = UDim2.new(0, w, 0, h)}):Play()
end

local function closePanel(frame, cb)
    local t = TweenService:Create(frame,
        TweenInfo.new(0.16, Enum.EasingStyle.Quad, Enum.EasingDirection.In),
        {Size = UDim2.new(0, 0, 0, 0)})
    t:Play()
    t.Completed:Connect(function()
        frame.Visible = false
        if cb then cb() end
    end)
end

connectBtn(floatBtn, function()
    panelOpen = not panelOpen
    if panelOpen then
        openPanel(mainPanel, PANEL_W, PANEL_H)
    else
        closePanel(mainPanel)
    end
end)

