-- =========================================================
-- EXPORT TO WORKSPACE FOLDER
-- Sistem chunk: setiap chunk max 2.000.000 voksel.
-- Kalau data melebihi batas, otomatis buat chunk baru.
-- =========================================================
local CHUNK_LIMIT = 2000000

-- Konversi material ke number, robust
local function matToNum(mat)
    local n = materialToNumber[mat]
    if n then return n end
    local ms = tostring(mat)
    for m2, num in pairs(materialToNumber) do
        if tostring(m2) == ms then return num end
    end
    return 1
end

-- Header standar yang dipakai semua chunk
-- isFirst: jika true, sisipkan SetMaterialColor untuk restore warna grass dan ground
local function chunkHeader(isFirst)
    local lines = {
        "local T=workspace.Terrain",
        "local V=4",
        "local M={",
        "    [1]=Enum.Material.Grass,       [2]=Enum.Material.Rock,",
        "    [3]=Enum.Material.Water,       [4]=Enum.Material.Ground,",
        "    [5]=Enum.Material.Sand,        [6]=Enum.Material.Snow,",
        "    [7]=Enum.Material.Ice,         [8]=Enum.Material.Mud,",
        "    [9]=Enum.Material.Sandstone,   [10]=Enum.Material.Limestone,",
        "    [11]=Enum.Material.Cobblestone,[12]=Enum.Material.Basalt,",
        "    [13]=Enum.Material.Concrete,   [14]=Enum.Material.Salt,",
        "    [15]=Enum.Material.LeafyGrass, [16]=Enum.Material.Pavement,",
        "}",
        "local CF=CFrame.new local V3=Vector3.new",
    }
    if isFirst then
        local function c3str(c)
            return string.format("Color3.fromRGB(%d,%d,%d)",
                math.floor(c.R*255+0.5), math.floor(c.G*255+0.5), math.floor(c.B*255+0.5))
        end
        local gc = activeGrassColor
        local gn = activeGroundColor
        table.insert(lines, "-- Restore warna material")
        table.insert(lines, "pcall(function() T:SetMaterialColor(Enum.Material.Grass,"      .. c3str(gc) .. ") end)")
        table.insert(lines, "pcall(function() T:SetMaterialColor(Enum.Material.LeafyGrass," .. c3str(gc) .. ") end)")
        table.insert(lines, "pcall(function() T:SetMaterialColor(Enum.Material.Ground,"     .. c3str(gn) .. ") end)")
        table.insert(lines, "pcall(function() T:SetMaterialColor(Enum.Material.Mud,"        .. c3str(gn) .. ") end)")
        table.insert(lines, "pcall(function() T:SetMaterialColor(Enum.Material.Sand,"       .. c3str(gn) .. ") end)")
        -- Restore wind (selalu export jika strength > 0)
        if activeWindStrength > 0 then
            local wrad = math.rad(activeWindAngle)
            local wx   = string.format("%.4f", math.sin(wrad) * activeWindStrength)
            local wz   = string.format("%.4f", math.cos(wrad) * activeWindStrength)
            table.insert(lines, "-- Restore wind")
            table.insert(lines, string.format("pcall(function() workspace.GlobalWind=Vector3.new(%s,0,%s) end)", wx, wz))
        end
    end
    table.insert(lines, "")
    return table.concat(lines, "\n")
end

-- Buat baris entry berdasarkan type
local function entryLine(e, comma)
    local t = e.type or "draw"
    local x, y, z = string.format("%.2f", e.pos.X), string.format("%.2f", e.pos.Y), string.format("%.2f", e.pos.Z)
    local s = string.format("%.2f", e.size)
    if t == "draw" then
        local sn = 1
        if e.shape == "Ball"     then sn = 2 end
        if e.shape == "Cylinder" then sn = 3 end
        return string.format("    {t=1,x=%s,y=%s,z=%s,s=%s,m=%d,sh=%d}%s", x,y,z,s, matToNum(e.material), sn, comma)
    elseif t == "erase" then
        local sn = 1
        if e.shape == "Ball"     then sn = 2 end
        if e.shape == "Cylinder" then sn = 3 end
        return string.format("    {t=2,x=%s,y=%s,z=%s,s=%s,sh=%d}%s", x,y,z,s, sn, comma)
    elseif t == "usap" then
        -- USAP V1 & V2 keduanya tersimpan sebagai t=3 (format identik).
        -- Field `sH` menyimpan tinggi blok tipis (V2 = 8, V1 = max(8, size*0.5)).
        local sH = string.format("%.2f", e.sH or 8)
        return string.format("    {t=3,x=%s,y=%s,z=%s,s=%s,sH=%s,m=%d}%s", x,y,z,s,sH, matToNum(e.material or Enum.Material.Grass), comma)
    elseif t == "rata" then
        return string.format("    {t=4,x=%s,y=%s,z=%s,s=%s,m=%d}%s", x,y,z,s, matToNum(e.material), comma)
    elseif t == "paint" then
        -- t=5: paint (ubah material voxel existing, tidak fill kosong)
        return string.format("    {t=5,x=%s,y=%s,z=%s,s=%s,m=%d}%s", x,y,z,s, matToNum(e.material), comma)
    elseif t == "partfill" then
        -- t=6: convert Part → Terrain (size penuh + rotasi).
        -- sh: 1=Block, 2=Ball, 3=Cylinder(part), 4=Wedge, 5=CornerWedge
        local sx = string.format("%.2f", (e.size3 and e.size3.X) or e.size or 4)
        local sy = string.format("%.2f", (e.size3 and e.size3.Y) or e.size or 4)
        local sz2= string.format("%.2f", (e.size3 and e.size3.Z) or e.size or 4)
        local rx = string.format("%.2f", e.rx or 0)
        local ry = string.format("%.2f", e.ry or 0)
        local rz = string.format("%.2f", e.rz or 0)
        local sn = e.shapeNum or 1
        return string.format(
            "    {t=6,x=%s,y=%s,z=%s,s=%s,sx=%s,sy=%s,sz=%s,rx=%s,ry=%s,rz=%s,m=%d,sh=%d}%s",
            x,y,z,s, sx,sy,sz2, rx,ry,rz, matToNum(e.material), sn, comma)
    end
    return ""
end

-- Replay loop unified: semua ops t=1..5 dalam urutan chronologis
local REPLAY_DRAW = table.concat({
    "local function apP(c,bs,tm)",
    "    local function snap(v) return math.floor(v/V)*V end",
    "    local h=math.max(bs,V)",
    "    local mn=V3(snap(c.X-h),snap(c.Y-h),snap(c.Z-h))",
    "    local mx=V3(snap(c.X+h)+V,snap(c.Y+h)+V,snap(c.Z+h)+V)",
    "    local reg=Region3.new(mn,mx):ExpandToGrid(V)",
    "    local ok,mt,oc=pcall(T.ReadVoxels,T,reg,V)",
    "    if not ok then return end",
    "    local sx,sy,sz=mt.Size.X,mt.Size.Y,mt.Size.Z",
    "    local nm,no={},{}",
    "    for x=1,sx do nm[x]={} no[x]={}",
    "        for y=1,sy do nm[x][y]={} no[x][y]={}",
    "            for z=1,sz do",
    "                local m2,o2=mt[x][y][z],oc[x][y][z]",
    "                if o2>0 and m2~=Enum.Material.Air then nm[x][y][z]=tm no[x][y][z]=o2",
    "                else nm[x][y][z]=m2 no[x][y][z]=o2 end",
    "            end end end",
    "    pcall(T.WriteVoxels,T,reg,V,nm,no)",
    "end",
    "",
    "for i,d in ipairs(D) do",
    "    local p=V3(d.x,d.y,d.z)",
    "    if d.t==1 then",
    "        local m=M[d.m] or Enum.Material.Grass",
    "        if d.sh==2 then T:FillBall(p,d.s/2,m)",
    "        elseif d.sh==3 then T:FillCylinder(CF(p),d.s/2,d.s,m)",
    "        else T:FillBlock(CF(p),V3(d.s,d.s,d.s),m) end",
    "    elseif d.t==2 then",
    "        if d.sh==2 then T:FillBall(p,d.s/2,Enum.Material.Air)",
    "        elseif d.sh==3 then T:FillCylinder(CF(p),d.s/2,d.s,Enum.Material.Air)",
    "        else T:FillBlock(CF(p),V3(d.s,d.s,d.s),Enum.Material.Air) end",
    "    elseif d.t==3 then",
    "        -- USAP (V1 & V2) — thin block sweep. Posisi 'p' SUDAH di-offset",
    "        -- saat brush (fP = pos.Y - sH/2), jadi langsung FillBlock di p.",
    "        -- sH default 8 stud (USAP V2), atau nilai tersimpan (USAP V1 lama).",
    "        local m=M[d.m] or Enum.Material.Grass",
    "        local sH=d.sH or 8",
    "        local sw=d.s or 8",
    "        T:FillBlock(CF(p),V3(sw,sH,sw),m)",
    "    elseif d.t==4 then",
    "        local m=M[d.m] or Enum.Material.Grass",
    "        local sy=math.floor(d.y/4)*4",
    "        T:FillBlock(CF(V3(d.x,sy+2,d.z)),V3(d.s+4,500,d.s+4),Enum.Material.Air)",
    "        T:FillBlock(CF(V3(d.x,sy+2,d.z)),V3(d.s,4,d.s),m)",
    "    elseif d.t==5 then",
    "        local m=M[d.m] or Enum.Material.Grass",
    "        apP(p,d.s,m)",
    "    elseif d.t==6 then",
    "        -- Part → Terrain (size penuh + rotasi)",
    "        local m=M[d.m] or Enum.Material.Grass",
    "        local sx,sy,sz=d.sx or d.s,d.sy or d.s,d.sz or d.s",
    "        local cf=CF(p)*CFrame.fromOrientation(math.rad(d.rx or 0),math.rad(d.ry or 0),math.rad(d.rz or 0))",
    "        if d.sh==2 then T:FillBall(p,math.max(sx,sy,sz)/2,m)",
    "        elseif d.sh==3 then T:FillCylinder(cf*CFrame.Angles(0,0,math.rad(90)),sx+4,math.max(sy,sz)/2+2,m)",
    "        elseif d.sh==4 or d.sh==5 then pcall(T.FillWedge,T,cf,V3(sx,sy,sz),m)",
    "        else",
    "            -- Balok: voksel kecil di lokal space (support rotasi, seperti silinder)",
    "            local V2=4",
    "            local function sn2(v) return math.floor(v/V2)*V2 end",
    "            local hsx2,hsy2,hsz2=sx/2,sy/2,sz/2",
    "            local cnt2=0",
    "            for lx2=sn2(-hsx2),sn2(hsx2),V2 do",
    "                for ly2=sn2(-hsy2),sn2(hsy2),V2 do",
    "                    for lz2=sn2(-hsz2),sn2(hsz2),V2 do",
    "                        local wp2=cf*V3(lx2+V2*0.5,ly2+V2*0.5,lz2+V2*0.5)",
    "                        T:FillBlock(CF(wp2),V3(V2,V2,V2),m)",
    "                        cnt2=cnt2+1 if cnt2%200==0 then task.wait() end",
    "                    end end end",
    "        end",
    "    end",
    "    if i%20==0 then task.wait() end",
    "end",
}, "\n")

local function generateChunks()
    -- Encode allOps sebagai satu timeline chronologis ke chunks D={}
    -- Semua t=1..5 dalam urutan asli editing
    -- Setiap chunk maksimal CHUNK_LIMIT (2.000.000) voksel
    local chunks = {}

    local header  = chunkHeader(true)
    local replayD = REPLAY_DRAW

    local function flushChunk(lines)
        table.insert(chunks, table.concat(lines, "\n"))
    end

    local currentLines    = { header }
    local currentSize     = #header
    local currentVoxCount = 0  -- jumlah voksel di chunk aktif
    local inData          = false

    local function startDataBlock()
        table.insert(currentLines, "local D={")
        currentSize = currentSize + 10
        inData = true
    end

    local function closeDataBlock()
        table.insert(currentLines, "}")
        table.insert(currentLines, replayD)
        currentSize = currentSize + #replayD + 2
        inData = false
    end

    local function newChunk()
        if inData then closeDataBlock() end
        flushChunk(currentLines)
        local nextHeader = chunkHeader(false)
        currentLines    = { nextHeader }
        currentSize     = #nextHeader
        currentVoxCount = 0  -- reset counter voksel untuk chunk baru
        startDataBlock()
    end

    startDataBlock()

    local ops = allOps
    -- Kalau allOps kosong (misal script lama sebelum V21), fallback ke terrainData+paintData
    if #ops == 0 then
        for _, e in ipairs(terrainData) do table.insert(ops, e) end
        for _, e in ipairs(paintData)   do table.insert(ops, e) end
    end

    for i, e in ipairs(ops) do
        local comma = i < #ops and "," or ""
        local line  = entryLine(e, comma)
        if #line == 0 then continue end
        -- Buat chunk baru jika sudah mencapai batas 2.000.000 voksel
        if currentVoxCount >= CHUNK_LIMIT then
            newChunk()
        end
        table.insert(currentLines, line)
        currentSize     = currentSize + #line + 1
        currentVoxCount = currentVoxCount + 1
    end

    if inData then closeDataBlock() end
    flushChunk(currentLines)

    return chunks
end

local function getSLExportFolder()
    local folder = workspace:FindFirstChild(SL_EXPORT_FOLDER)
    if not folder then
        pcall(function()
            folder        = Instance.new("Folder")
            folder.Name   = SL_EXPORT_FOLDER
            folder.Parent = workspace
        end)
        folder = workspace:FindFirstChild(SL_EXPORT_FOLDER)
    end
    return folder
end

connectBtn(slExportBtn, function()
    if #terrainData == 0 and #paintData == 0 then
        slLabel.Text               = "KOSONG"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(170, 40, 40)
        task.wait(1.5)
        slLabel.Text               = "EXPORT WS"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(20, 148, 90)
        return
    end

    slLabel.Text               = "..."
    slExportBtn.BackgroundColor3 = Color3.fromRGB(180, 130, 20)
    task.wait(0.1)

    local chunks = generateChunks()
    if not chunks or #chunks == 0 then
        slLabel.Text               = "ERR"
        slExportBtn.BackgroundColor3 = C.RED
        task.wait(2)
        slLabel.Text               = "EXPORT WS"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(20, 148, 90)
        return
    end

    local timestamp = os.date and os.date("%H%M%S") or tostring(os.time())

    -- Backup ke file executor
    pcall(function()
        if not isfolder("BRUSH_SL_EXPORTS") then makefolder("BRUSH_SL_EXPORTS") end
        for ci, src in ipairs(chunks) do
            local fname = "BRUSH_SL_EXPORTS/TR_" .. timestamp .. "_C" .. ci .. ".lua"
            writefile(fname, src)
        end
    end)

    local folder = getSLExportFolder()
    if not folder then
        slLabel.Text               = "ERR"
        slExportBtn.BackgroundColor3 = C.RED
        task.wait(2)
        slLabel.Text               = "EXPORT WS"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(20, 148, 90)
        return
    end

    local savedCount = 0
    for ci, src in ipairs(chunks) do
        local svName = "TerrainRestore_" .. timestamp .. "_C" .. ci
        local existing = folder:FindFirstChild(svName)
        if existing then pcall(function() existing:Destroy() end) end
        local ok = pcall(function()
            local sv  = Instance.new("StringValue")
            sv.Name   = svName
            sv.Value  = src
            sv.Parent = folder
        end)
        if ok then savedCount = savedCount + 1 end
        task.wait(0.05)
    end

    if savedCount > 0 then
        slLabel.Text               = savedCount > 1 and (savedCount.."CK!") or "SAVED!"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(28, 200, 100)
        task.wait(2)
        slLabel.Text               = "EXPORT WS"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(20, 148, 90)
    else
        slLabel.Text               = "ERR"
        slExportBtn.BackgroundColor3 = C.RED
        task.wait(2)
        slLabel.Text               = "EXPORT WS"
        slExportBtn.BackgroundColor3 = Color3.fromRGB(20, 148, 90)
    end
end)

