        popup:Destroy()
        materialPopup = nil
    end)

    materialPopup = popup
end

-- =========================================================
-- PART TO TERRAIN CONVERSION
-- =========================================================
local VOXEL_RES = 4

local function convertPartToTerrain(part, targetMaterial)
    if not part or not part:IsA("BasePart") then return false end
    local cframe = part.CFrame
    local rawSize = part.Size
    local size = Vector3.new(
        math.min(rawSize.X, 128),
        math.min(rawSize.Y, 128),
        math.min(rawSize.Z, 128)
    )
    local function snap(v) return math.floor(v / VOXEL_RES) * VOXEL_RES end
    local pos = cframe.Position
    local region = Region3.new(
        Vector3.new(snap(pos.X-size.X/2), snap(pos.Y-size.Y/2), snap(pos.Z-size.Z/2)),
        Vector3.new(snap(pos.X+size.X/2)+VOXEL_RES, snap(pos.Y+size.Y/2)+VOXEL_RES, snap(pos.Z+size.Z/2)+VOXEL_RES)
    )
    local mats, occs = Terrain:ReadVoxels(region, VOXEL_RES)
    local sx, sy, sz = mats.Size.X, mats.Size.Y, mats.Size.Z
    local newMats, newOccs = {}, {}
    for x = 1, sx do
        newMats[x] = {} newOccs[x] = {}
        for y = 1, sy do
            newMats[x][y] = {} newOccs[x][y] = {}
            for z = 1, sz do
                local worldPos = region.Min + Vector3.new((x-0.5)*VOXEL_RES,(y-0.5)*VOXEL_RES,(z-0.5)*VOXEL_RES)
                local localPos = cframe:PointToObjectSpace(worldPos)
                if math.abs(localPos.X) <= size.X/2 and
                   math.abs(localPos.Y) <= size.Y/2 and
                   math.abs(localPos.Z) <= size.Z/2 then
                    newMats[x][y][z] = targetMaterial
                    newOccs[x][y][z] = 1
                else
                    newMats[x][y][z] = mats[x][y][z]
                    newOccs[x][y][z] = occs[x][y][z]
                end
            end
        end
    end
    Terrain:WriteVoxels(region, VOXEL_RES, newMats, newOccs)
    local entry = { type="draw", pos=pos, size=math.max(size.X,size.Y,size.Z), material=targetMaterial, shape="Block" }
    table.insert(terrainData, entry)
    table.insert(allOps, entry)
    updateCounter()
    part:Destroy()
    return true
end

-- =========================================================
-- BRUSH HELPERS
-- =========================================================
local function eraseNearby(pos, radius)
    for i = #terrainData, 1, -1 do
        local e = terrainData[i]
        if (e.pos - pos).Magnitude <= radius then
            table.remove(terrainData, i)
        end
    end
end

local function paintTerrain(centerPos, brushSize, targetMat)
    local function snap(v) return math.floor(v/VOXEL_RES)*VOXEL_RES end
    local half = math.clamp(math.max(brushSize, VOXEL_RES), VOXEL_RES, 32)
    local minP = Vector3.new(snap(centerPos.X-half),snap(centerPos.Y-half),snap(centerPos.Z-half))
    local maxP = Vector3.new(snap(centerPos.X+half)+VOXEL_RES,snap(centerPos.Y+half)+VOXEL_RES,snap(centerPos.Z+half)+VOXEL_RES)
    local region = Region3.new(minP, maxP):ExpandToGrid(VOXEL_RES)
    local mats, occs = Terrain:ReadVoxels(region, VOXEL_RES)
    local sx, sy, sz = mats.Size.X, mats.Size.Y, mats.Size.Z
    local newMats, newOccs = {}, {}
    for x=1,sx do
        newMats[x]={} newOccs[x]={}
        for y=1,sy do
            newMats[x][y]={} newOccs[x][y]={}
            for z=1,sz do
                local m, o = mats[x][y][z], occs[x][y][z]
                if o > 0 and m ~= Enum.Material.Air then
                    newMats[x][y][z] = targetMat
                    newOccs[x][y][z] = o
                else
                    newMats[x][y][z] = m
                    newOccs[x][y][z] = o
                end
            end
        end
    end
    Terrain:WriteVoxels(region, VOXEL_RES, newMats, newOccs)
end

local function flattenTerrain(centerPos, brushSize)
    local VOXEL    = 4
    local function snap(v) return math.floor(v/VOXEL)*VOXEL end
    local w        = math.clamp(brushSize, VOXEL, 128)
    local snappedY = snap(centerPos.Y)
    local eraseH   = 500
    local eraseBot = snappedY + VOXEL
    local eraseC   = Vector3.new(centerPos.X, eraseBot + eraseH*0.5, centerPos.Z)
    pcall(function()
        Terrain:FillBlock(CFrame.new(eraseC), Vector3.new(w, eraseH, w), Enum.Material.Air)
    end)
end

local lockedFlatY = nil

local function drawFlat(centerPos, brushSize, material, flatY)
    local VOXEL    = 4
    local function snap(v) return math.floor(v/VOXEL)*VOXEL end
    local snappedY = snap(flatY)
    local w        = math.clamp(brushSize, VOXEL, 128)
    local eraseH   = 500
    local eraseC   = Vector3.new(centerPos.X, (snappedY+VOXEL)+eraseH*0.5, centerPos.Z)
    pcall(function()
        Terrain:FillBlock(CFrame.new(eraseC), Vector3.new(w+4, eraseH, w+4), Enum.Material.Air)
    end)
    pcall(function()
        Terrain:FillBlock(CFrame.new(centerPos.X, snappedY+VOXEL*0.5, centerPos.Z),
            Vector3.new(w, VOXEL, w), material)
    end)
end

-- =========================================================
-- RAYCAST / HIT
-- =========================================================
local camera = workspace.CurrentCamera
local lastTouchPos = nil

local raycastParams = RaycastParams.new()
raycastParams.FilterType = Enum.RaycastFilterType.Exclude
raycastParams.FilterDescendantsInstances = { player.Character or workspace }

local function getBrushHitPos(screenPos)
    if player.Character then
        raycastParams.FilterDescendantsInstances = { player.Character }
    end
    local unitRay = camera:ScreenPointToRay(screenPos.X, screenPos.Y)
    local result  = workspace:Raycast(unitRay.Origin, unitRay.Direction * 2000, raycastParams)
    if result then return result.Position, result.Instance end
    if mouse.Hit then return mouse.Hit.Position, mouse.Target end
    return nil, nil
end

-- =========================================================
-- BRUSH INDICATOR
-- =========================================================
local brushIndicator = nil

local function updateBrushIndicator(pos, size, shape, mode)
    if brushIndicator then brushIndicator:Destroy(); brushIndicator = nil end
    if not brushEnabled or not pos then return end
    local col
    if mode == "Draw"    then col = Color3.fromRGB(80,180,80)
    elseif mode == "Erase"   then col = Color3.fromRGB(220,60,60)
    elseif mode == "Paint"   then col = Color3.fromRGB(160,80,220)
    elseif mode == "Convert" then col = Color3.fromRGB(220,140,40)
    elseif mode == "Usap"    then col = Color3.fromRGB(38,198,218)
    elseif mode == "UsapV2"  then col = Color3.fromRGB(170,100,220)
    elseif mode == "Rata"    then col = Color3.fromRGB(80,200,80)
    else col = Color3.fromRGB(80,180,80) end

    if shape == "Ball" then
        local a = Instance.new("SphereHandleAdornment")
        a.Adornee = workspace.Terrain; a.Radius = size/2
        a.Color3 = col; a.AlwaysOnTop = false
        a.Transparency = 0.55; a.ZIndex = 5
        a.CFrame = CFrame.new(pos); a.Parent = workspace
        brushIndicator = a
    else
        local a = Instance.new("BoxHandleAdornment")
        a.Adornee = workspace.Terrain; a.Size = Vector3.new(size,size,size)
        a.Color3 = col; a.AlwaysOnTop = false
        a.Transparency = 0.55; a.ZIndex = 5
        a.CFrame = CFrame.new(pos); a.Parent = workspace
        brushIndicator = a
    end
end

RunService.RenderStepped:Connect(function()
    if not brushEnabled then
        if brushIndicator then brushIndicator:Destroy(); brushIndicator = nil end
        return
    end
    local screenPos
    if lastTouchPos then
        screenPos = Vector2.new(lastTouchPos.X, lastTouchPos.Y)
    elseif mouse then
        screenPos = Vector2.new(mouse.X, mouse.Y)
    else return end
    local pos = getBrushHitPos(screenPos)
    if pos then
        local size = math.clamp(currentSize, 1, 64)
        if brushIndicator and brushIndicator.Parent then
            brushIndicator.CFrame = CFrame.new(pos)
            if brushIndicator:IsA("SphereHandleAdornment") then
                brushIndicator.Radius = size/2
            else
                brushIndicator.Size = Vector3.new(size,size,size)
            end
        else
            updateBrushIndicator(pos, size, selectedShape, brushMode)
        end
    else
        if brushIndicator then brushIndicator:Destroy(); brushIndicator = nil end
    end
end)

