-- =========================================================
-- MODE USAP  (sapuan datar ke bawah — FillBlock lapisan)
-- =========================================================
local usapLastT   = 0
local usapLastPos = nil

local function doUsap(pos)
    if not pos then return end
    local t = tick()
    -- throttle 50ms
    if t - usapLastT < 0.05 then return end
    -- skip jika terlalu dekat posisi terakhir
    local sz = math.clamp(currentSize, 1, 64)
    if usapLastPos and (pos - usapLastPos).Magnitude < sz * 0.4 then return end
    usapLastT = t; usapLastPos = pos

    local T = workspace:FindFirstChild("Terrain")
    if not T then return end

    -- Tinggi lapisan: minimal 8 stud, atau setengah ukuran brush
    local sH  = math.max(8, math.floor(sz * 0.5))
    local sSz = Vector3.new(sz, sH, sz)
    -- Posisi tengah geser ke bawah supaya "menutup permukaan"
    local fP  = Vector3.new(pos.X, pos.Y - sH * 0.5, pos.Z)

    local ok = pcall(function()
        T:FillBlock(CFrame.new(fP), sSz, selectedTerrain)
    end)

    if ok then
        local entry = {
            type="usap", pos=fP, size=sz, sH=sH,
            material=selectedTerrain, shape="Block"
        }
        table.insert(terrainData, entry)
        table.insert(allOps, entry)
        updateCounter()
    end
end

-- =========================================================
-- MODE USAP V2 (port 1:1 PLUGIN_V1 bSw — thin block sweep brush)
-- Karakteristik V1 asli (line 1136 PLUGIN_V1):
--   - throttle 50ms (lSBT < 0.05)
--   - jarak skip = min(W,H,D) * 0.4
--   - sH = max(CBS.Y, 8)  ⇒ blok TIPIS (CBS.Y default kecil ~4-8)
--   - sSz = (CBS.X, sH, CBS.Z) — datar/tipis, bukan kubus
--   - Y offset = -sH/2 supaya menempel permukaan
-- Adaptasi MZYV (currentSize tunggal):
--   - sH dipatok 8 stud (mengikuti minimum V1, BLOK TIPIS)
--   - jarak skip pakai bidang horizontal XZ saja, supaya saat mouse
--     bergerak naik-turun ke ketinggian berbeda tidak menumpuk vertikal
--   - Y di-snap ke kelipatan 4 stud (voxel grid Roblox) supaya
--     sapuan tetap rapi di satu lapisan
-- =========================================================
local usapV2LastT   = 0
local usapV2LastPos = nil

local function doUsapV2(pos)
    if not pos then return end
    local t = tick()
    if t - usapV2LastT < 0.05 then return end

    local sz = math.clamp(currentSize, 1, 64)

    -- Jarak skip = HORIZONTAL (XZ) saja; abaikan komponen Y
    if usapV2LastPos then
        local dx = pos.X - usapV2LastPos.X
        local dz = pos.Z - usapV2LastPos.Z
        local minStep = math.min(sz, 8) * 0.4   -- mirror V1: min(W,H,D)*0.4
        if (dx*dx + dz*dz) < (minStep * minStep) then return end
    end
    usapV2LastT = t; usapV2LastPos = pos

    local T = workspace:FindFirstChild("Terrain")
    if not T then return end

    -- sH tetap 8 stud (= V1 max(CBS.Y, 8) saat CBS.Y kecil) ⇒ BLOK TIPIS
    local sH    = 8
    -- Snap Y ke voxel grid 4 stud supaya sweep selalu di lapisan rapi
    local snapY = math.floor(pos.Y / 4 + 0.5) * 4
    local sSz   = Vector3.new(sz, sH, sz)
    local fP    = Vector3.new(pos.X, snapY - sH * 0.5, pos.Z)

    local ok = pcall(function()
        T:FillBlock(CFrame.new(fP), sSz, selectedTerrain)
    end)

    if ok then
        local entry = {
            type="usap", pos=fP, size=sz, sH=sH,
            material=selectedTerrain, shape="Block"
        }
        table.insert(terrainData, entry)
        table.insert(allOps, entry)
        updateCounter()
    end
end

RunService.Heartbeat:Connect(function()
    if not painting or not brushEnabled then return end
    if (tick() - lastPaint) < DELAY then return end

    local screenPos
    if lastTouchPos then
        screenPos = Vector2.new(lastTouchPos.X, lastTouchPos.Y)
    else
        screenPos = Vector2.new(mouse.X, mouse.Y)
    end

    local pos, hitInstance = getBrushHitPos(screenPos)
    if not pos then return end

    local size = math.clamp(currentSize, 1, 64)

    if brushMode == "Draw" then
        local ok = pcall(function()
            if selectedShape == "Ball" then
                Terrain:FillBall(pos, size/2, selectedTerrain)
            elseif selectedShape == "Cylinder" then
                Terrain:FillCylinder(CFrame.new(pos), size/2, size, selectedTerrain)
            else
                Terrain:FillBlock(CFrame.new(pos), Vector3.new(size,size,size), selectedTerrain)
            end
        end)
        if ok then
            local entry = {
                type="draw", pos=pos, size=size,
                material=selectedTerrain, shape=selectedShape
            }
            table.insert(terrainData, entry)
            table.insert(allOps, entry)
            updateCounter()
        end

    elseif brushMode == "Erase" then
        local ok = pcall(function()
            if selectedShape == "Ball" then
                Terrain:FillBall(pos, size/2, Enum.Material.Air)
            elseif selectedShape == "Cylinder" then
                Terrain:FillCylinder(CFrame.new(pos), size/2, size, Enum.Material.Air)
            else
                Terrain:FillBlock(CFrame.new(pos), Vector3.new(size,size,size), Enum.Material.Air)
            end
        end)
        if ok then
            -- catat erase sebagai entry khusus
            local entry = {
                type="erase", pos=pos, size=size, shape=selectedShape
            }
            table.insert(terrainData, entry)
            table.insert(allOps, entry)
            eraseNearby(pos, size)
            updateCounter()
        end

    elseif brushMode == "Paint" then
        local ok = pcall(function() paintTerrain(pos, size, selectedTerrain) end)
        if ok then
            local entry = {type="paint", pos=pos, size=size, material=selectedTerrain}
            table.insert(paintData, entry)
            table.insert(allOps, entry)
            updateCounter()
        end

    elseif brushMode == "Usap" then
        doUsap(pos)

    elseif brushMode == "UsapV2" then
        doUsapV2(pos)
    end

    lastPaint = tick()
end)
