local function _launchTerrainPanel()
        _destroyTerrainPanel()
        local ok, err = pcall(function() loadstring(_TERRAIN_SRC)() end)
        if not ok then warn("[DEX] Terrain panel error: " .. tostring(err)) end

        -- ╔══════════════════════════════════════════════════════════════╗
        -- ║  DEX EXPLORER EMBED (v1.0)                                   ║
        -- ║  Pindahkan MainPanel TERRAIN BRUSH ke dalam ExplorerPanel    ║
        -- ║  DEX (kotak putih). Logika internal panel TIDAK diubah —     ║
        -- ║  hanya parent / posisi / ukuran / visibilitas.               ║
        -- ╚══════════════════════════════════════════════════════════════╝
        task.spawn(function()
                local lp = game:GetService("Players").LocalPlayer
                if not lp then return end
                local pg = lp:FindFirstChildOfClass("PlayerGui")
                        or lp:WaitForChild("PlayerGui", 10)
                if not pg then return end

                -- Tunggu ScreenGui terrain muncul setelah loadstring
                local tgui
                local t0 = tick()
                while tick() - t0 < 10 do
                        tgui = pg:FindFirstChild(_TERRAIN_GUI_NAME)
                        if tgui then break end
                        task.wait(0.05)
                end
                if not tgui then return end

                local mainPanel = tgui:WaitForChild("MainPanel", 10)
                if not mainPanel then return end

                -- Cari DEX ExplorerPanel (kotak putih)
                -- ★ FIX PERSIST v2.0: cek CoreGui dulu (lokasi baru, persisten),
                --   baru fallback ke PlayerGui.
                local dex = nil
                pcall(function()
                        local _cg = game:GetService("CoreGui")
                        for _, v in ipairs(_cg:GetChildren()) do
                                if v.Name == "Dex" then dex = v; break end
                        end
                end)
                if not dex then dex = pg:FindFirstChild("Dex") end
                local explorerPanel = dex and dex:WaitForChild("ExplorerPanel", 10) or nil
                if not explorerPanel then
                        -- DEX belum siap → biarkan panel floating sebagai fallback,
                        -- tetap aktifkan visibility supaya tidak hilang
                        pcall(function()
                                mainPanel.Visible = true
                                mainPanel.Size    = UDim2.new(0, 380, 0, 480)
                        end)
                        return
                end

                -- Floating elemen di tgui:
                --  • floatBtn  (Position Y.Offset = 80)  → SEMBUNYIKAN (panel sudah embed)
                --  • onoffBtn  (Position Y.Offset = 132) → REPARENT ke SideMenu DEX
                --                                          sejajar vertikal dengan tombol Explorer/Settings/Remotes/About
                --                                          CATATAN: tidak dimasukkan ke SlideFrame karena loop DEX
                --                                          (switchWindows) akses v.Icon langsung tanpa pcall → crash.
                --                                          Solusi: taruh di SideMenu (parent SlideOut) dengan posisi
                --                                          absolut sejajar, dan sertakan ImageLabel "Icon" dummy.
                for _, c in ipairs(tgui:GetChildren()) do
                        if c ~= mainPanel and c:IsA("GuiObject") and c.Visible then
                                local isOnoff = (c:IsA("TextButton") or c:IsA("ImageButton"))
                                        and c.Position == UDim2.new(0, 16, 0, 132)
                                if isOnoff then
                                        pcall(function()
                                                -- Cari SideMenu DEX
                                                local dexGui = nil
                                                for _, v in ipairs(game:GetService("CoreGui"):GetChildren()) do
                                                        if v.Name == "Dex" then dexGui = v; break end
                                                end
                                                if not dexGui then
                                                        local lp2 = game:GetService("Players").LocalPlayer
                                                        local pg2 = lp2 and lp2:FindFirstChildOfClass("PlayerGui")
                                                        if pg2 then
                                                                for _, v in ipairs(pg2:GetChildren()) do
                                                                        if v.Name == "Dex" then dexGui = v; break end
                                                                end
                                                        end
                                                end

                                                local sideMenu = dexGui and dexGui:FindFirstChild("SideMenu", true)

                                                if sideMenu then
                                                        -- Hitung posisi Y otomatis:
                                                        -- SideMenu diperbesar ke 228px untuk beri ruang tombol ON/OFF
                                                        -- SlideOut ada di Y=30, tinggi 150 → berakhir di Y=180
                                                        -- Tombol ON/OFF kita di Y=180..228 (48px)
