                                                                        ustr.Color              = Color3.fromRGB(60, 210, 100)
                                                                        ustr.Transparency       = 0.2
                                                                        icoLbl.TextColor3       = Color3.fromRGB(80, 255, 130)
                                                                        lbl.Text                = "ON"
                                                                        lbl.TextColor3          = Color3.fromRGB(130, 255, 160)
                                                                else
                                                                        c.BackgroundColor3      = _offColor
                                                                        ustr.Color              = Color3.fromRGB(220, 60, 60)
                                                                        ustr.Transparency       = 0.3
                                                                        icoLbl.TextColor3       = Color3.fromRGB(255, 100, 100)
                                                                        lbl.Text                = "OFF"
                                                                        lbl.TextColor3          = Color3.fromRGB(255, 160, 160)
                                                                end
                                                        end

                                                        c.MouseEnter:Connect(function()
                                                                c.BackgroundTransparency = 0.3
                                                        end)
                                                        c.MouseLeave:Connect(function()
                                                                c.BackgroundTransparency = 0
                                                        end)

                                                        -- Pantau perubahan warna background dari logika brush
                                                        -- (logika lama set BackgroundColor3 merah/hijau di quickDisableBtn)
                                                        -- → kita sinkronkan ke _isOn
                                                        c:GetPropertyChangedSignal("BackgroundColor3"):Connect(function()
                                                                pcall(function()
                                                                        local col = c.BackgroundColor3
                                                                        -- Hijau = ON (R rendah, G tinggi)
                                                                        local wasOn = _isOn
                                                                        _isOn = (col.G > col.R + 0.1)
                                                                        if _isOn ~= wasOn then _refreshColor() end
                                                                end)
                                                        end)

                                                        c.Parent = wrapper

                                                        -- Auto-sync posisi wrapper saat SideMenu resize
                                                        pcall(function()
                                                                sideMenu:GetPropertyChangedSignal("Size"):Connect(function()
                                                                        pcall(function()
                                                                                local newH = sideMenu.Size.Y.Offset
                                                                                sep.Position     = UDim2.new(0, 3, 0, newH - 1)
                                                                                wrapper.Position = UDim2.new(0, 0, 0, newH + 2)
                                                                        end)
                                                                end)
                                                        end)
                                                else
                                                        -- Fallback jika SideMenu tidak ditemukan
                                                        c.AnchorPoint = Vector2.new(1, 0)
                                                        c.Position    = UDim2.new(1, -4, 0, 4)
                                                        c.Size        = UDim2.new(0, 38, 0, 28)
                                                        c.ZIndex      = 200
                                                        c.Parent      = explorerPanel
                                                end
                                        end)
                                else
                                        pcall(function() c.Visible = false end)
                                end
                        end
                end
                -- Konstanta layout
                -- NATIVE_W disamakan dgn PW asli MainPanel (300) supaya skala
                -- 1:1 dgn lebar konten asli — tidak ada lagi mismatch 380 vs 300
                -- yg bikin fitur kelihatan kekecilan.
                local NATIVE_W       = 300
                local NATIVE_H       = 1600  -- tinggi cukup untuk semua section (full scroll)
                -- SHRINK_FACTOR=1 → panel mengisi penuh lebar ExplorerPanel
                -- (sebelumnya 0.78 menyusutkan tambahan 22% → ini biang
                -- "fitur terrain kekecilan").
                local SHRINK_FACTOR  = 1.00

                -- ScrollingFrame wrapper di dalam ExplorerPanel
                local scrollWrap
                pcall(function()
                        scrollWrap = explorerPanel:FindFirstChild("_TerrainScrollWrap")
                        if not scrollWrap then
                                scrollWrap = Instance.new("ScrollingFrame")
                                scrollWrap.Name                   = "_TerrainScrollWrap"
                                scrollWrap.Size                   = UDim2.new(1, 0, 1, 0)
                                scrollWrap.Position               = UDim2.new(0, 0, 0, 0)
                                scrollWrap.BackgroundTransparency = 1
                                scrollWrap.BorderSizePixel        = 0
                                scrollWrap.ScrollingDirection     = Enum.ScrollingDirection.Y
                                scrollWrap.ScrollBarThickness     = 6
                                scrollWrap.ClipsDescendants       = true
                                scrollWrap.ZIndex                 = 5
                                scrollWrap.Parent                 = explorerPanel
                        end
                end)

                -- Reparent MainPanel ke ScrollingFrame, ukuran 380×NATIVE_H
                pcall(function()
                        mainPanel.AnchorPoint      = Vector2.new(0, 0)
                        mainPanel.Position         = UDim2.new(0, 0, 0, 0)
                        mainPanel.Size             = UDim2.new(0, NATIVE_W, 0, NATIVE_H)
                        mainPanel.ClipsDescendants = false
                        mainPanel.Visible          = true
                        mainPanel.Parent           = scrollWrap or explorerPanel
                end)

                -- UIScale: kecilkan seluruh fitur supaya muat lebar ExplorerPanel
                -- × faktor SHRINK_FACTOR ekstra agar lebih lega & tidak overlay.
                local uiScale
                pcall(function()
                        uiScale = mainPanel:FindFirstChild("_TerrainAutoScale")
                        if not uiScale then
                                uiScale = Instance.new("UIScale")
                                uiScale.Name   = "_TerrainAutoScale"
                                uiScale.Parent = mainPanel
                        end
                        local function updScale()
                                local w = explorerPanel.AbsoluteSize.X
                                if w and w > 0 then
                                        -- Skala dibebaskan untuk naik di atas 1
                                        -- supaya panel benar2 ngepas dengan
                                        -- lebar ExplorerPanel (sebelumnya
                                        -- di-cap di 1 → panel tidak pernah
                                        -- mengisi penuh kalau Explorer >300px).
                                        -- Batas atas 1.6 utk jaga2 layout tdk
                                        -- pecah di Explorer ekstra lebar.
                                        local s = math.clamp(w / NATIVE_W, 0.5, 1.6) * SHRINK_FACTOR
                                        uiScale.Scale = s
                                        if scrollWrap then
                                                scrollWrap.CanvasSize =
                                                        UDim2.new(0, 0, 0, math.ceil(NATIVE_H * s) + 8)
                                        end
                                end
                        end
                        updScale()
                        explorerPanel:GetPropertyChangedSignal("AbsoluteSize"):Connect(updScale)
                end)

                -- Hilangkan rounded-corner & stroke MainPanel supaya menyatu
                pcall(function()
                        for _, child in ipairs(mainPanel:GetChildren()) do
                                if child:IsA("UICorner") or child:IsA("UIStroke") then
                                        pcall(function() child:Destroy() end)
                                end
                        end
                end)

                -- Samakan warna ExplorerPanel dengan panel terrain
                pcall(function()
                        explorerPanel.BackgroundColor3       = mainPanel.BackgroundColor3
                        explorerPanel.BackgroundTransparency = 0
                        explorerPanel.BorderSizePixel        = 0
                        explorerPanel.ClipsDescendants       = true
                end)

                -- Naikkan ZIndex descendant agar tampil di atas isi DEX
                pcall(function()
                        for _, d in ipairs(mainPanel:GetDescendants()) do
                                if d:IsA("GuiObject") then
                                        pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                                end
                        end
                        mainPanel.DescendantAdded:Connect(function(d)
                                if d:IsA("GuiObject") then
                                        task.defer(function()
                                                pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                                        end)
                                end
                        end)
                end)

                -- Sinkronkan visibility panel ↔ ExplorerPanel
                pcall(function()
                        explorerPanel:GetPropertyChangedSignal("Visible"):Connect(function()
                                pcall(function() mainPanel.Visible = explorerPanel.Visible end)
                        end)
                end)

                -- Auto re-parent kalau panel dipindah oleh logika internal
                pcall(function()
                        mainPanel.AncestryChanged:Connect(function(_, parent)
                                local target = scrollWrap or explorerPanel
                                if parent ~= target and explorerPanel.Parent then
                                        pcall(function()
                                                mainPanel.Parent      = target
                                                mainPanel.AnchorPoint = Vector2.new(0, 0)
                                                mainPanel.Position    = UDim2.new(0, 0, 0, 0)
                                                mainPanel.Size        = UDim2.new(0, NATIVE_W, 0, NATIVE_H)
                                                mainPanel.Visible     = true
                                        end)
                                end
                        end)
                end)
        end)
end

