-- ══════════════════════════════════════════════════════════════════════
--  TOOLBOX PC — DEX EXPLORER INTEGRATION (v2.0 — pola identik TERRAIN)
--  Toggle ON  → rebuild panel + embed ke ExplorerPanel DEX (full size 1,0,1,0)
--  Toggle OFF → destroy panel + bersihkan SideMenu DEX
--  Ukuran panel mengisi penuh ExplorerPanel — sama persis seperti panel terrain.
-- ══════════════════════════════════════════════════════════════════════
local _TOOLBOXPC_GUI_PREFIX = "SLv50_ToolboxPCGui"

-- Helper: cari DEX ScreenGui di CoreGui atau PlayerGui
local function _findDexGui()
    local cg = game:GetService("CoreGui")
    for _, v in ipairs(cg:GetChildren()) do
        if v.Name == "Dex" then return v end
    end
    local lp = game:GetService("Players").LocalPlayer
    local pg = lp and lp:FindFirstChildOfClass("PlayerGui")
    if pg then
        for _, v in ipairs(pg:GetChildren()) do
            if v.Name == "Dex" then return v end
        end
    end
    return nil
end

local function _destroyToolboxPCPanel()
    -- 1) Hapus ScreenGui toolbox dari CoreGui
    pcall(function()
        local cg = game:GetService("CoreGui")
        for _, v in ipairs(cg:GetChildren()) do
            if v.Name:sub(1, #_TOOLBOXPC_GUI_PREFIX) == _TOOLBOXPC_GUI_PREFIX then
                v:Destroy()
            end
        end
    end)
    -- 2) Hapus ScreenGui toolbox dari PlayerGui
    pcall(function()
        local lp = game:GetService("Players").LocalPlayer
        local pg = lp and lp:FindFirstChildOfClass("PlayerGui")
        if pg then
            for _, v in ipairs(pg:GetChildren()) do
                if v.Name:sub(1, #_TOOLBOXPC_GUI_PREFIX) == _TOOLBOXPC_GUI_PREFIX then
                    v:Destroy()
                end
            end
        end
    end)
    -- 3) Hapus _ToolboxPCScrollWrap (dan panel di dalamnya) di ExplorerPanel
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local ep = dexGui:FindFirstChild("ExplorerPanel", true)
            if ep then
                local sw = ep:FindFirstChild("_ToolboxPCScrollWrap")
                if sw then sw:Destroy() end
                local p2 = ep:FindFirstChild("ToolboxPCPanel")
                if p2 then p2:Destroy() end
            end
        end
    end)
    -- 4) Hapus _ToolboxPCOnOff & _ToolboxPCSep dari SideMenu DEX
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local sm = dexGui:FindFirstChild("SideMenu", true)
            if sm then
                for _, c in ipairs(sm:GetChildren()) do
                    if c.Name == "_ToolboxPCSep" or c.Name == "_ToolboxPCOnOff" then
                        c:Destroy()
                    end
                end
            end
        end
    end)
    -- Reset referensi
    pcall(function()
        if _SL then _SL.toolboxPCPanel = nil end
    end)
end

local function _launchToolboxPCPanel()
    _destroyToolboxPCPanel()

    -- ── 1) Rebuild panel via referensi _SL ────────────────────────────
    local okBuild, errBuild = pcall(function()
        if _SL and _SL.buildToolboxPCPanel then
            _SL.buildToolboxPCPanel()
        end
    end)
    if not okBuild then
        warn("[ToolboxPC DEX] build error: " .. tostring(errBuild))
    end

    -- ── 2) Embed panel ke ExplorerPanel DEX (async) ───────────────────
    task.spawn(function()
        local lp = game:GetService("Players").LocalPlayer
        if not lp then return end

        -- Tunggu panel siap di _SL.toolboxPCPanel (max 5 detik)
        local panel
        local t0 = tick()
        while tick() - t0 < 5 do
            panel = _SL and _SL.toolboxPCPanel
            if panel and panel.Parent then break end
            task.wait(0.05)
        end
        if not panel or not panel.Parent then
            warn("[ToolboxPC DEX] Panel belum siap setelah build")
            return
        end

        -- Cari DEX ExplorerPanel
        local dexGui = _findDexGui()
        local explorerPanel = dexGui and dexGui:WaitForChild("ExplorerPanel", 10) or nil

        if not explorerPanel then
            -- Fallback: panel floating sebagai ScreenGui asli
            pcall(function()
                panel.Visible  = true
                panel.Position = UDim2.new(0, 12, 0, 60)
                panel.Size     = UDim2.new(0, 260, 0, 530)
            end)
            return
        end

        -- ── 3) Bangun ScrollingFrame wrapper di ExplorerPanel ─────────
        local scrollWrap
        pcall(function()
            scrollWrap = explorerPanel:FindFirstChild("_ToolboxPCScrollWrap")
            if not scrollWrap then
                scrollWrap = Instance.new("ScrollingFrame")
                scrollWrap.Name                   = "_ToolboxPCScrollWrap"
                scrollWrap.Size                   = UDim2.new(1, 0, 1, 0)
                scrollWrap.Position               = UDim2.new(0, 0, 0, 0)
                scrollWrap.BackgroundTransparency = 1
                scrollWrap.BorderSizePixel        = 0
                scrollWrap.ScrollingDirection     = Enum.ScrollingDirection.Y
                scrollWrap.ScrollBarThickness     = 0
                scrollWrap.CanvasSize             = UDim2.new(0, 0, 0, 0)
                scrollWrap.ClipsDescendants       = true
                scrollWrap.ZIndex                 = 5
                scrollWrap.Parent                 = explorerPanel
            end
        end)

        -- ── 4) Reparent panel toolbox ke wrapper, isi penuh 1:1 ───────
        pcall(function()
            panel.Name              = "ToolboxPCPanel"
            panel.AnchorPoint       = Vector2.new(0, 0)
            panel.Position          = UDim2.new(0, 0, 0, 0)
            panel.Size              = UDim2.new(1, 0, 1, 0)
            panel.ClipsDescendants  = true
            panel.Visible           = true
            panel.Parent            = scrollWrap or explorerPanel
        end)

        -- Hilangkan rounded-corner & stroke supaya menyatu dgn ExplorerPanel
        pcall(function()
            for _, child in ipairs(panel:GetChildren()) do
                if child:IsA("UICorner") or child:IsA("UIStroke") then
                    pcall(function() child:Destroy() end)
                end
            end
        end)

        -- Samakan warna ExplorerPanel dgn panel toolbox
        pcall(function()
            explorerPanel.BackgroundColor3       = panel.BackgroundColor3
            explorerPanel.BackgroundTransparency = 0
            explorerPanel.BorderSizePixel        = 0
            explorerPanel.ClipsDescendants       = true
        end)

        -- Naikkan ZIndex semua descendant agar tampil di atas isi DEX
        pcall(function()
            for _, d in ipairs(panel:GetDescendants()) do
                if d:IsA("GuiObject") then
                    pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                end
            end
            panel.DescendantAdded:Connect(function(d)
                if d:IsA("GuiObject") then
                    task.defer(function()
                        pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                    end)
                end
            end)
        end)

        -- Sinkronkan visibility panel ↔ ExplorerPanel
        pcall(function()
            explorerPanel:GetPropertyChangedSignal("Visible"):Connect(function()
                pcall(function() panel.Visible = explorerPanel.Visible end)
            end)
        end)

        -- Auto re-parent jika panel dipindah oleh logika internal
        pcall(function()
            panel.AncestryChanged:Connect(function(_, parent)
                local target = scrollWrap or explorerPanel
                if parent ~= target and explorerPanel.Parent then
                    pcall(function()
                        panel.Parent      = target
                        panel.AnchorPoint = Vector2.new(0, 0)
                        panel.Position    = UDim2.new(0, 0, 0, 0)
                        panel.Size        = UDim2.new(1, 0, 1, 0)
                        panel.Visible     = true
                    end)
                end
            end)
        end)

    end)
end

createSetting("Aktifkan toolbox pc","SelBox",false)
-- Hook toggle "Aktifkan toolbox pc" → launch/destroy panel di DEX
do
    local _ch = SettingList:GetChildren()
    local _s  = _ch[#_ch]
    _registerPanelToggle(_s, "SelBox", _destroyToolboxPCPanel)
    if _s and _s:FindFirstChild("Change") then
        _s.Change.MouseButton1Click:connect(function()
            task.defer(function()
                if Settings.SelBox then
                    _turnOffOtherPanels("SelBox")
                    _launchToolboxPCPanel()
                else
                    if not _isAnyOtherPanelActive("SelBox") then
                        _setSettingVisualOn(_s, "SelBox")
                    else
                        _destroyToolboxPCPanel()
                    end
                end
            end)
        end)
    end
end
-- ── END TOOLBOX PC DEX INTEGRATION ────────────────────────────────────────

-- ══════════════════════════════════════════════════════════════════════
--  PLUGIN PANEL — DEX EXPLORER INTEGRATION (pola identik TERRAIN/TOOLBOX PC)
--  Toggle ON  → embed pl_MF (TPv11_Main) ke ExplorerPanel DEX (size 1,0,1,0)
--  Toggle OFF → restore pl_MF ke ScreenGui asli, bersihkan SideMenu DEX
-- ══════════════════════════════════════════════════════════════════════
local _PLUGIN_ORIG_PARENT = nil
local _PLUGIN_ORIG_SIZE   = nil
local _PLUGIN_ORIG_POS    = nil
local _PLUGIN_ORIG_BG_TR  = nil
local _PLUGIN_ORIG_VIS    = nil

local function _destroyPluginPanel()
    -- 1) Hapus _PluginScrollWrap di ExplorerPanel
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local ep = dexGui:FindFirstChild("ExplorerPanel", true)
            if ep then
                local sw = ep:FindFirstChild("_PluginScrollWrap")
                if sw then sw:Destroy() end
            end
        end
    end)
    -- 2) Hapus _PluginOnOff & _PluginSep dari SideMenu DEX
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local sm = dexGui:FindFirstChild("SideMenu", true)
            if sm then
                for _, c in ipairs(sm:GetChildren()) do
                    if c.Name == "_PluginSep" or c.Name == "_PluginOnOff" then
                        c:Destroy()
                    end
                end
            end
        end
    end)
    -- 3) Restore pl_MF ke parent asli + size/position/visibility
    pcall(function()
        local panel = _SL and _SL.pluginPanel
        if panel and _PLUGIN_ORIG_PARENT and _PLUGIN_ORIG_PARENT.Parent then
            panel.Parent                = _PLUGIN_ORIG_PARENT
            if _PLUGIN_ORIG_SIZE   then panel.Size                  = _PLUGIN_ORIG_SIZE   end
            if _PLUGIN_ORIG_POS    then panel.Position              = _PLUGIN_ORIG_POS    end
            if _PLUGIN_ORIG_BG_TR  then panel.BackgroundTransparency = _PLUGIN_ORIG_BG_TR  end
            panel.Visible = (_PLUGIN_ORIG_VIS == true)
        end
    end)
end

local function _launchPluginPanel()
    -- Bersihkan state lama dulu (mengikuti pola _launchToolboxPCPanel)
    _destroyPluginPanel()

    -- ── 1) Build plugin panel via _SL.injectPlugin (kalau belum dibuild) ──
    local okBuild, errBuild = pcall(function()
        if _SL and _SL.injectPlugin then
            _SL.injectPlugin()
        end
    end)
    if not okBuild then
        warn("[Plugin DEX] build error: " .. tostring(errBuild))
    end

    -- ── 2) Embed panel ke ExplorerPanel DEX (async) ───────────────────
    task.spawn(function()
        local lp = game:GetService("Players").LocalPlayer
        if not lp then return end

        -- Tunggu panel siap di _SL.pluginPanel (max 5 detik) — pola identik ToolboxPC
        local panel
        local t0 = tick()
        while tick() - t0 < 5 do
            panel = _SL and _SL.pluginPanel
            if panel and panel.Parent then break end
            task.wait(0.05)
        end
        if not panel or not panel.Parent then
            warn("[Plugin DEX] Panel belum siap setelah build")
            return
        end

        -- Simpan state asli (sekali saja, biar restore bisa balik ke kondisi awal)
        if not _PLUGIN_ORIG_PARENT then
            pcall(function()
                _PLUGIN_ORIG_PARENT = panel.Parent
                _PLUGIN_ORIG_SIZE   = panel.Size
                _PLUGIN_ORIG_POS    = panel.Position
                _PLUGIN_ORIG_BG_TR  = panel.BackgroundTransparency
                _PLUGIN_ORIG_VIS    = panel.Visible
            end)
        end

        -- Cari DEX ExplorerPanel
        local dexGui = _findDexGui()
        local explorerPanel = dexGui and dexGui:WaitForChild("ExplorerPanel", 10) or nil

        if not explorerPanel then
            -- Fallback: tampilkan floating saja
            pcall(function() panel.Visible = true end)
            return
        end

        -- ── Buat ScrollingFrame wrapper di ExplorerPanel ──────────────
        local scrollWrap
        pcall(function()
            scrollWrap = explorerPanel:FindFirstChild("_PluginScrollWrap")
            if not scrollWrap then
                scrollWrap = Instance.new("ScrollingFrame")
                scrollWrap.Name                   = "_PluginScrollWrap"
                scrollWrap.Size                   = UDim2.new(1, 0, 1, 0)
                scrollWrap.Position               = UDim2.new(0, 0, 0, 0)
                scrollWrap.BackgroundTransparency = 1
                scrollWrap.BorderSizePixel        = 0
                scrollWrap.ScrollingDirection     = Enum.ScrollingDirection.Y
                scrollWrap.ScrollBarThickness     = 0
                scrollWrap.CanvasSize             = UDim2.new(0, 0, 0, 0)
                scrollWrap.ClipsDescendants       = true
                scrollWrap.ZIndex                 = 5
                scrollWrap.Parent                 = explorerPanel
            end
        end)

        -- Native size pl_MF (PW=252, PH=430) — supaya semua dekorasi
        -- (mkLine corner accents, header, tabs, dll) tetap proporsional.
        local PW_NATIVE = 252
        local PH_NATIVE = 430

        -- ── Reparent pl_MF ke wrapper, pakai native size ───────────────
        pcall(function()
            panel.AnchorPoint            = Vector2.new(0, 0)
            panel.Position               = UDim2.new(0, 0, 0, 0)
            panel.Size                   = UDim2.new(0, PW_NATIVE, 0, PH_NATIVE)
            panel.BackgroundTransparency = 0  -- non-transparan saat embed
            panel.ClipsDescendants       = false
            panel.Visible                = true
            panel.Parent                 = scrollWrap or explorerPanel
        end)

        -- Sembunyikan glow ring (tidak relevan saat embed)
        pcall(function()
            local glow = _SL and _SL.pluginGlow
            if glow then glow.Visible = false end
        end)

        -- ── UIScale otomatis: scale panel sesuai lebar ExplorerPanel ──
        pcall(function()
            local uiScale = panel:FindFirstChild("_PluginAutoScale")
            if not uiScale then
                uiScale = Instance.new("UIScale")
                uiScale.Name   = "_PluginAutoScale"
                uiScale.Parent = panel
            end
            local function updScale()
                local w = explorerPanel.AbsoluteSize.X
                if w and w > 0 then
                    -- Skala bebas naik di atas 1 supaya panel mengisi penuh
                    -- lebar ExplorerPanel; cap 1.6 untuk jaga2 di Explorer ekstra lebar.
                    local s = math.clamp(w / PW_NATIVE, 0.5, 1.6)
                    uiScale.Scale = s
                    if scrollWrap then
                        scrollWrap.CanvasSize =
                            UDim2.new(0, 0, 0, math.ceil(PH_NATIVE * s) + 8)
                    end
                end
            end
            updScale()
            explorerPanel:GetPropertyChangedSignal("AbsoluteSize"):Connect(updScale)
        end)

        -- Samakan warna ExplorerPanel dgn panel plugin
        pcall(function()
            explorerPanel.BackgroundColor3       = panel.BackgroundColor3
            explorerPanel.BackgroundTransparency = 0
            explorerPanel.BorderSizePixel        = 0
            explorerPanel.ClipsDescendants       = true
        end)

        -- Naikkan ZIndex semua descendant
        pcall(function()
            for _, d in ipairs(panel:GetDescendants()) do
                if d:IsA("GuiObject") then
                    pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                end
            end
            panel.DescendantAdded:Connect(function(d)
                if d:IsA("GuiObject") then
                    task.defer(function()
                        pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                    end)
                end
            end)
        end)

        -- Sinkronkan visibility panel ↔ ExplorerPanel
        pcall(function()
            explorerPanel:GetPropertyChangedSignal("Visible"):Connect(function()
                pcall(function() panel.Visible = explorerPanel.Visible end)
            end)
        end)

        -- Auto re-parent jika panel pindah
        pcall(function()
            panel.AncestryChanged:Connect(function(_, parent)
                local target = scrollWrap or explorerPanel
                if Settings and Settings.ClearProps and parent ~= target and explorerPanel.Parent then
                    pcall(function()
                        panel.Parent      = target
                        panel.AnchorPoint = Vector2.new(0, 0)
                        panel.Position    = UDim2.new(0, 0, 0, 0)
                        panel.Size        = UDim2.new(0, PW_NATIVE, 0, PH_NATIVE)
                        panel.Visible     = true
                    end)
                end
            end)
        end)

    end)
end

createSetting("open tools plugin","ClearProps",false)
-- Hook toggle "open tools plugin" → launch/destroy panel di DEX
do
    local _ch = SettingList:GetChildren()
    local _s  = _ch[#_ch]
    _registerPanelToggle(_s, "ClearProps", _destroyPluginPanel)
    if _s and _s:FindFirstChild("Change") then
        _s.Change.MouseButton1Click:connect(function()
            task.defer(function()
                if Settings.ClearProps then
                    _turnOffOtherPanels("ClearProps")
                    _launchPluginPanel()
                else
                    if not _isAnyOtherPanelActive("ClearProps") then
                        _setSettingVisualOn(_s, "ClearProps")
                    else
                        _destroyPluginPanel()
                    end
                end
            end)
        end)
    end
end
-- ── END PLUGIN DEX INTEGRATION ────────────────────────────────────────────

-- ══════════════════════════════════════════════════════════════════════
--  VOICE PANEL — DEX EXPLORER INTEGRATION (pola identik PLUGIN/TOOLBOX PC)
--  Toggle ON  → build voice panel + embed Frame nya ke ExplorerPanel DEX
--  Toggle OFF → destroy voice panel + bersihkan SideMenu DEX
--  Tombol toggle: "open auto clone" (Settings.SelectUngrouped)
-- ══════════════════════════════════════════════════════════════════════
local _VOICE_GUI_NAME = "SLv50_VoicePanel"

local function _findVoicePanel()
    local lp = game:GetService("Players").LocalPlayer
    local pg = lp and lp:FindFirstChildOfClass("PlayerGui")
    if not pg then return nil, nil end
    local sg = pg:FindFirstChild(_VOICE_GUI_NAME)
    if not sg then return nil, nil end
    -- Frame pertama di dalam ScreenGui = panel utama (310×420)
    for _, c in ipairs(sg:GetChildren()) do
        if c:IsA("Frame") then
            return sg, c
        end
    end
    return sg, nil
end

local function _destroyVoicePanel()
    -- 1) Hapus _VoiceScrollWrap di ExplorerPanel
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local ep = dexGui:FindFirstChild("ExplorerPanel", true)
            if ep then
                local sw = ep:FindFirstChild("_VoiceScrollWrap")
                if sw then sw:Destroy() end
            end
        end
    end)
    -- 2) Hapus _VoiceOnOff & _VoiceSep dari SideMenu DEX
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local sm = dexGui:FindFirstChild("SideMenu", true)
            if sm then
                for _, c in ipairs(sm:GetChildren()) do
                    if c.Name == "_VoiceSep" or c.Name == "_VoiceOnOff" then
                        c:Destroy()
                    end
                end
            end
        end
    end)
    -- 3) Hapus ScreenGui voice (panel embed ikut hilang krn child dari sg)
    pcall(function()
        local lp = game:GetService("Players").LocalPlayer
        local pg = lp and lp:FindFirstChildOfClass("PlayerGui")
        if pg then
            local sg = pg:FindFirstChild(_VOICE_GUI_NAME)
            if sg then sg:Destroy() end
        end
    end)
end

local function _launchVoicePanel()
    _destroyVoicePanel()

    -- Build voice panel via _SL.openVoicePanel
    local okBuild, errBuild = pcall(function()
        if _SL and _SL.openVoicePanel then
            _SL.openVoicePanel()
        end
    end)
    if not okBuild then
        warn("[Voice DEX] build error: " .. tostring(errBuild))
    end

    task.spawn(function()
        local lp = game:GetService("Players").LocalPlayer
        if not lp then return end

        -- Tunggu voice panel terbentuk (max 5 detik)
        local sg, panel
        local t0 = tick()
        while tick() - t0 < 5 do
            sg, panel = _findVoicePanel()
            if sg and panel and panel.Parent then break end
            task.wait(0.05)
        end
        if not panel or not panel.Parent then
            warn("[Voice DEX] Panel belum siap setelah build")
            return
        end

        -- Cari DEX ExplorerPanel
        local dexGui = _findDexGui()
        local explorerPanel = dexGui and dexGui:WaitForChild("ExplorerPanel", 10) or nil

        if not explorerPanel then
            -- Fallback: tetap floating
            return
        end

        -- ── ScrollingFrame wrapper di ExplorerPanel ────────────────────
        local scrollWrap
        pcall(function()
            scrollWrap = explorerPanel:FindFirstChild("_VoiceScrollWrap")
            if not scrollWrap then
                scrollWrap = Instance.new("ScrollingFrame")
                scrollWrap.Name                   = "_VoiceScrollWrap"
                scrollWrap.Size                   = UDim2.new(1, 0, 1, 0)
                scrollWrap.Position               = UDim2.new(0, 0, 0, 0)
                scrollWrap.BackgroundTransparency = 1
                scrollWrap.BorderSizePixel        = 0
                scrollWrap.ScrollingDirection     = Enum.ScrollingDirection.Y
                scrollWrap.ScrollBarThickness     = 0
                scrollWrap.CanvasSize             = UDim2.new(0, 0, 0, 0)
                scrollWrap.ClipsDescendants       = true
                scrollWrap.ZIndex                 = 5
                scrollWrap.Parent                 = explorerPanel
            end
        end)

        -- Native size voice panel (PW5=310, PH5=420)
        local PW_NATIVE = 310
        local PH_NATIVE = 420

        -- ── Reparent panel ke wrapper, native size, anchor 0,0 ─────────
        -- LOGIKA ASLI DIPERTAHANKAN: ClipsDescendants=true (default voice panel),
        -- UICorner & UIStroke TIDAK dihapus supaya tampilan voice persis aslinya
        pcall(function()
            panel.AnchorPoint            = Vector2.new(0, 0)
            panel.Position               = UDim2.new(0, 0, 0, 0)
            panel.Size                   = UDim2.new(0, PW_NATIVE, 0, PH_NATIVE)
            panel.ClipsDescendants       = true
            panel.Active                 = true   -- preserve drag/input handler asli
            panel.Visible                = true
            panel.Parent                 = scrollWrap or explorerPanel
        end)

        -- ── UIScale otomatis ──────────────────────────────────────────
        pcall(function()
            local uiScale = panel:FindFirstChild("_VoiceAutoScale")
            if not uiScale then
                uiScale = Instance.new("UIScale")
                uiScale.Name   = "_VoiceAutoScale"
                uiScale.Parent = panel
            end
            local function updScale()
                local w = explorerPanel.AbsoluteSize.X
                if w and w > 0 then
                    local s = math.clamp(w / PW_NATIVE, 0.5, 1.6)
                    uiScale.Scale = s
                    if scrollWrap then
                        scrollWrap.CanvasSize =
                            UDim2.new(0, 0, 0, math.ceil(PH_NATIVE * s) + 8)
                    end
                end
            end
            updScale()
            explorerPanel:GetPropertyChangedSignal("AbsoluteSize"):Connect(updScale)
        end)

        -- Samakan warna ExplorerPanel dgn panel voice
        pcall(function()
            explorerPanel.BackgroundColor3       = panel.BackgroundColor3
            explorerPanel.BackgroundTransparency = 0
            explorerPanel.BorderSizePixel        = 0
            explorerPanel.ClipsDescendants       = true
        end)

        -- Naikkan ZIndex semua descendant
        pcall(function()
            for _, d in ipairs(panel:GetDescendants()) do
                if d:IsA("GuiObject") then
                    pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                end
            end
            panel.DescendantAdded:Connect(function(d)
                if d:IsA("GuiObject") then
                    task.defer(function()
                        pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                    end)
                end
            end)
        end)

        -- Sinkronkan visibility panel ↔ ExplorerPanel
        pcall(function()
            explorerPanel:GetPropertyChangedSignal("Visible"):Connect(function()
                pcall(function() panel.Visible = explorerPanel.Visible end)
            end)
        end)

        -- Auto re-parent jika panel pindah
        pcall(function()
            panel.AncestryChanged:Connect(function(_, parent)
                local target = scrollWrap or explorerPanel
                if Settings and Settings.SelectUngrouped and parent ~= target and explorerPanel.Parent then
                    pcall(function()
                        panel.Parent      = target
                        panel.AnchorPoint = Vector2.new(0, 0)
                        panel.Position    = UDim2.new(0, 0, 0, 0)
                        panel.Size        = UDim2.new(0, PW_NATIVE, 0, PH_NATIVE)
                        panel.Visible     = true
                    end)
                end
            end)
        end)

    end)
end

createSetting("voice/addplace","SelectUngrouped",false)
-- Hook toggle "open auto clone" → launch/destroy voice panel di DEX
do
    local _ch = SettingList:GetChildren()
    local _s  = _ch[#_ch]
    _registerPanelToggle(_s, "SelectUngrouped", _destroyVoicePanel)
    if _s and _s:FindFirstChild("Change") then
        _s.Change.MouseButton1Click:connect(function()
            task.defer(function()
                if Settings.SelectUngrouped then
                    _turnOffOtherPanels("SelectUngrouped")
                    _launchVoicePanel()
                else
                    if not _isAnyOtherPanelActive("SelectUngrouped") then
                        _setSettingVisualOn(_s, "SelectUngrouped")
                    else
                        _destroyVoicePanel()
                    end
                end
            end)
        end)
    end
end
-- ── END VOICE DEX INTEGRATION ─────────────────────────────────────────────

-- ══════════════════════════════════════════════════════════════════════
--  CLOUD MODE PANEL — SL SAVE PANEL + DEX EXPLORER INTEGRATION
--  Toggle ON  → launch SL Save Panel + embed ke ExplorerPanel DEX
--  Toggle OFF → destroy panel + bersihkan ExplorerPanel DEX
--  Ukuran panel mengisi penuh ExplorerPanel — sama seperti panel lain.
-- ══════════════════════════════════════════════════════════════════════
local function _destroyCloudPanel()
    -- 1) Hapus _CloudScrollWrap dari ExplorerPanel DEX
    pcall(function()
        local dexGui = _findDexGui()
        if dexGui then
            local ep = dexGui:FindFirstChild("ExplorerPanel", true)
            if ep then
                local sw = ep:FindFirstChild("_CloudScrollWrap")
                if sw then sw:Destroy() end
            end
        end
    end)
    -- 2) Hapus ScreenGui SL_Panel dari PlayerGui
    pcall(function()
        local lp = game:GetService("Players").LocalPlayer
        local pg = lp and lp:FindFirstChildOfClass("PlayerGui")
        if pg then
            for _, gname in ipairs({"SL_Panel_v8","SL_Panel_v9"}) do
                local old = pg:FindFirstChild(gname)
                if old then old:Destroy() end
            end
        end
    end)
end

local function _launchCloudPanel()
    _destroyCloudPanel()

    -- ── 1) Build SL Save Panel ─────────────────────────────────────────
    pcall(function()
        -- ============================================================
        -- SL SAVE PANEL BY SYGKMUNII V8 — FULL OFFLINE MODE + PUBLISH FROM HP
        -- Delta Executor (Android) | by SYGKMUNII
        -- Fixed & Enhanced by Agent — v9.22 / UI V8
        -- ============================================================

        local BACKUP_FOLDER = "SL_BACKUP/"
        local VERSION       = "BY SYGKMUNII V8"

        -- ── Services ─────────────────────────────────────────────────
        local Players   = game:GetService("Players")
        local player    = Players.LocalPlayer
        local playerGui = player:WaitForChild("PlayerGui")
        local hs        = game:GetService("HttpService")
        local uis       = game:GetService("UserInputService")
        local rs        = game:GetService("ReplicatedStorage")

        -- Bersihkan panel lama
        for _, g in ipairs({"SL_Panel_v8","SL_Panel_v9"}) do
            local old = playerGui:FindFirstChild(g)
            if old then old:Destroy() end
        end

        -- ── State ────────────────────────────────────────────────────
        local saveMode       = "ponsel"
        local interceptCount = 0
        local openCount      = 0
        local publishCount   = 0
        local hookActive     = false
        local panelEnabled   = false   -- START: OFF
        local bypassHook     = false
        local origNamecall   = nil
        local SLFolder       = nil
        local ServerFunctions= nil
        local MainConvert    = nil
        local chunkBuffer    = {}
        local monConnection  = nil
        local pendingGameName= nil
        local gameNumToInfo  = {}
        local notifConn      = nil
        local dialogModeConn = nil

        local currentActiveGame  = nil
        local lastKnownSLSlot    = nil

        local setStatusFunc = nil
        local reloadFunc    = nil

        -- ── File util ────────────────────────────────────────────────
        local function ensureFolder()
            pcall(function()
                if not isfolder(BACKUP_FOLDER) then makefolder(BACKUP_FOLDER) end
            end)
        end

        local function formatTimestamp(ts)
            local t = tonumber(ts) or 0
            if t <= 0 then return "?" end
            local ok, s = pcall(os.date, "%d %b %Y %H:%M", t)
            return ok and s or ("ts:"..tostring(ts))
        end

        local function projFolderName(gameName)
            return (gameName or "project"):gsub("[^%w%-]","_"):sub(1,28)
        end

        local function normalizePath(p)
            if not p then return p end
            local idx = p:find("SL_BACKUP/", 1, true)
            if idx then return p:sub(idx) end
            return p
        end

        local function safeRead(p)
            if not p then return nil end
            local ok, d = pcall(readfile, p)
            if ok and d and #d > 0 then return d end
            local rel = normalizePath(p)
            if rel ~= p then
                ok, d = pcall(readfile, rel)
                if ok and d and #d > 0 then return d end
            end
            return nil
        end

        local function safeWrite(p, d)  return pcall(writefile, p, d) end
        local function safeList(p)      local ok, f = pcall(listfiles, p); return ok and f or {} end
        local function safeDelete(p)    pcall(delfile, p) end
        local function fileName(p)      return (p:match("([^/\\]+)$") or p) end
        local function fileExt(p)       return (p:match("(%.[^%.]+)$") or "") end
        ensureFolder()

        -- ── Status ────────────────────────────────────────────────────
        local function setStatus(msg, col)
            if setStatusFunc then setStatusFunc(msg, col) end
        end
        local function triggerReload()
            if reloadFunc then spawn(function() wait(0.3); reloadFunc() end) end
        end

        -- ── Simpan JSON ke HP + auto-backup versi lama ke subfolder ──
        local function saveToPhone(jsonStr, gameNum, gameName)
            if not jsonStr or #jsonStr < 4 then return nil end
            ensureFolder()
            local ts   = tostring(os.time())
            local gn   = tostring(gameNum or "0")
            local name = projFolderName(gameName)

            local existing_files = safeList(BACKUP_FOLDER)
            for _, fp in ipairs(existing_files) do
                local fn = fileName(fp)
                if fileExt(fn):lower() == ".json" then
                    local rawN = fn:match("^gamenum%d+_(.+)_%d+%.json$") or ""
                    if rawN:lower() == name:lower() then
                        local bDir = BACKUP_FOLDER..name.."/"
                        pcall(function() if not isfolder(bDir) then makefolder(bDir) end end)
                        local normalFp = normalizePath(fp)
                        local oldData = safeRead(normalFp)
                        if oldData then
                            pcall(function() safeWrite(bDir..fn, oldData) end)
                            pcall(function() safeDelete(normalFp) end)
                            local oldGn = fn:match("^gamenum(%d+)_") or gn
                            gameNumToInfo[oldGn] = nil
                        end
                        break
                    end
                end
            end

            local fname = "gamenum"..gn.."_"..name.."_"..ts..".json"
            local fpath = BACKUP_FOLDER..fname
            local ok    = safeWrite(fpath, jsonStr)
            if ok then
                interceptCount = interceptCount + 1
                gameNumToInfo[gn] = {filepath=fpath, gameName=gameName or "project"}
                setStatus("💾 #"..interceptCount.." → "..fname:sub(1,38), Color3.fromRGB(80,230,110))
                triggerReload()
                return fpath
            end
            return nil
        end

        -- ── Cari file untuk gameNum ───────────────────────────────────
        local function findFileForGameNum(gameNum)
            local gn = tostring(gameNum)
            if gameNumToInfo[gn] then return gameNumToInfo[gn] end
            local pattern = "gamenum"..gn.."_"
            local files   = safeList(BACKUP_FOLDER)
            table.sort(files, function(a,b) return a > b end)
            for _, fp in ipairs(files) do
                local fn = fileName(fp)
                if fileExt(fn):lower() == ".json" and fn:find(pattern, 1, true) then
                    local rawName  = fn:match("^gamenum%d+_(.+)_%d+%.json$") or "project"
                    local gname    = rawName:gsub("_", " ")
                    local normalFp = normalizePath(fp)
                    local info = {filepath=normalFp, gameName=gname}
                    gameNumToInfo[gn] = info
                    return info
                end
            end
            return nil
        end

        -- ── Cari file berdasarkan NAMA game ──────────────────────────
        local function findFileForGameName(name)
            if not name or name == "" then return nil end
            local nameNorm  = name:gsub("%s+", "_"):lower()
            local namePlain = name:lower()
            local files     = safeList(BACKUP_FOLDER)
            table.sort(files, function(a,b) return a > b end)
            for _, fp in ipairs(files) do
                local fn = fileName(fp)
                if fileExt(fn):lower() == ".json" then
                    local rawName = fn:match("^gamenum%d+_(.+)_%d+%.json$") or ""
                    if rawName:lower() == nameNorm or rawName:gsub("_"," "):lower() == namePlain then
                        local gn    = fn:match("^gamenum(%d+)_") or "0"
                        local gname = rawName:gsub("_"," ")
                        return {filepath=normalizePath(fp), gn=gn, gameName=gname}
                    end
                end
            end
            for _, fp in ipairs(files) do
                local fn = fileName(fp)
                if fileExt(fn):lower() == ".json" then
                    local rawName = fn:match("^gamenum%d+_(.+)_%d+%.json$") or ""
                    if rawName:lower():find(nameNorm, 1, true)
                    or rawName:gsub("_"," "):lower():find(namePlain, 1, true) then
                        local gn    = fn:match("^gamenum(%d+)_") or "0"
                        local gname = rawName:gsub("_"," ")
                        return {filepath=normalizePath(fp), gn=gn, gameName=gname}
                    end
                end
            end
            return nil
        end

        -- ── Semua file HP (sorted newest first) ──────────────────────
        local function getAllPhoneFiles()
            local files = safeList(BACKUP_FOLDER)
            table.sort(files, function(a,b) return a > b end)
            local result = {}
            local seen   = {}
            for _, fp in ipairs(files) do
                local fn = fileName(fp)
                if fileExt(fn):lower() == ".json" then
                    local gn = fn:match("^gamenum(%d+)_")
                    if gn and not seen[gn] then
                        seen[gn] = true
                        local rawName = fn:match("^gamenum%d+_(.+)_%d+%.json$") or "project"
                        local gname   = (gameNumToInfo[gn] and gameNumToInfo[gn].gameName)
                                     or rawName:gsub("_", " ")
                        table.insert(result, {gn=gn, filepath=normalizePath(fp), gameName=gname})
                    end
                end
            end
            return result
        end

        -- ── Semua projects (satu per nama project, terbaru dulu) ─────
        local function getAllProjects()
            local files = safeList(BACKUP_FOLDER)
            table.sort(files, function(a,b) return a > b end)
            local result, seen = {}, {}
            for _, fp in ipairs(files) do
                local fn = fileName(fp)
                if fileExt(fn):lower() == ".json" then
                    local gn      = fn:match("^gamenum(%d+)_") or "0"
                    local rawName = fn:match("^gamenum%d+_(.+)_%d+%.json$") or fn:gsub("%.json$","")
                    local ts      = fn:match("_(%d+)%.json$") or "0"
                    local key     = rawName:lower()
                    if not seen[key] then
                        seen[key] = true
                        local gname = (gameNumToInfo[gn] and gameNumToInfo[gn].gameName)
                                   or rawName:gsub("_"," ")
                        local bCount = 0
                        pcall(function()
                            local bDir = BACKUP_FOLDER..rawName.."/"
                            if isfolder(bDir) then
                                for _, bf in ipairs(safeList(bDir)) do
                                    if fileExt(fileName(bf)):lower()==".json" then bCount=bCount+1 end
                                end
                            end
                        end)
                        table.insert(result,{
                            gn=gn, filepath=normalizePath(fp),
                            gameName=gname, rawName=rawName,
                            timestamp=tonumber(ts) or 0, backupCount=bCount,
                        })
                    end
                end
            end
            return result
        end

        -- ── Daftar file backup untuk satu project ────────────────────
        local function getProjectBackups(rawName)
            local bDir = BACKUP_FOLDER..rawName.."/"
            local result = {}
            pcall(function()
                local files = safeList(bDir)
                table.sort(files, function(a,b) return a > b end)
                for _, fp in ipairs(files) do
                    local fn = fileName(fp)
                    if fileExt(fn):lower()==".json" then
                        local ts = fn:match("_(%d+)%.json$") or "0"
                        table.insert(result,{filepath=fp, filename=fn, timestamp=tonumber(ts) or 0})
                    end
                end
            end)
            return result
        end

        -- ── Baca nama game dari SL Save UI ───────────────────────────
        local function readSaveGameNameFromUI()
            local ok, name = pcall(function()
                local sg  = playerGui:FindFirstChild("StudioGui")
                if not sg then return nil end
                local tb  = sg:FindFirstChild("TopBar")
                local sdf = tb and tb:FindFirstChild("SaveDetailsFrame")
                local box = sdf and sdf:FindFirstChild("GameNameTextBox")
                return box and box.Text ~= "" and box.Text or nil
            end)
            return ok and name or nil
        end

        -- ── Baca nama game dari slot di OpenSaveFrame ─────────────────
        local function getGameNameFromOpenFrame(gameNum)
            local ok, name = pcall(function()
                local sg = playerGui:FindFirstChild("StudioGui")
                if not sg then return nil end
                local osf = sg:FindFirstChild("OpenSaveFrame")
                if not osf then return nil end
                local containers = {osf}
                local sf = osf:FindFirstChild("ScrollingFrame")
                if sf then table.insert(containers, sf) end
                for _, cont in ipairs(containers) do
                    for _, child in ipairs(cont:GetChildren()) do
                        local _, num = child.Name:match("^(%a+)(%d+)$")
                        if num and tostring(num) == tostring(gameNum) then
                            local f1  = child:FindFirstChild("Frame1")
                            local lbl = f1 and f1:FindFirstChild("GameTitleTextLabel")
                            if lbl and lbl.Text and lbl.Text ~= "" and lbl.Text ~= "GameTitle" then
                                return lbl.Text
                            end
                        end
                    end
                end
                return nil
            end)
            return ok and name or nil
        end

        -- ── Ambil MainConvertModule ────────────────────────────────────
        local function getMainConvert()
            if MainConvert then return MainConvert end
            if not SLFolder then return nil end
            local ok, m = pcall(function()
                return require(SLFolder:WaitForChild("MainConvertModule", 5))
            end)
            if ok and m then MainConvert = m end
            return MainConvert
        end

        -- ══════════════════════════════════════════════════════════════
        -- INJECT file HP ke OpenSaveFrame SL
        -- ══════════════════════════════════════════════════════════════
        local function injectPhoneSavesIntoOpenDialog()
            local ok, err = pcall(function()
                local sg = playerGui:FindFirstChild("StudioGui")
                if not sg then return end
                local osf = sg:FindFirstChild("OpenSaveFrame")
                if not osf then return end
                local sf = osf:FindFirstChild("ScrollingFrame")
                if not sf then return end

                local template = sf:FindFirstChild("OpenSaveTemplate")
                              or osf:FindFirstChild("OpenSaveTemplate")
                if not template then
                    setStatus("⚠ OpenSaveTemplate tidak ditemukan", Color3.fromRGB(255,180,60))
                    return
                end

                local phoneFiles = getAllPhoneFiles()
                if #phoneFiles == 0 then return end

                local injectedCount = 0
                for _, info in ipairs(phoneFiles) do
                    local gn       = info.gn
                    local gameName = info.gameName
                    local slotName = "Game"..gn

                    local existingHP = sf:FindFirstChild(slotName.."|HP")
                    if existingHP then existingHP:Destroy() end

                    local existing = sf:FindFirstChild(slotName)
                    if existing then
                        local f1  = existing:FindFirstChild("Frame1")
                        local lbl = f1 and f1:FindFirstChild("GameTitleTextLabel")
                        if lbl and (lbl.Text == "" or lbl.Text == "GameTitle") then
                            lbl.Text = gameName
                            existing.Visible = true
                        end
                    else
                        local clone = template:Clone()
                        clone.Name    = slotName
                        clone.Visible = true
                        if clone.Active == false then clone.Active = true end

                        local f1  = clone:FindFirstChild("Frame1")
                        local lbl = f1 and f1:FindFirstChild("GameTitleTextLabel")
                        if lbl then lbl.Text = gameName end

                        local openBtn = f1 and f1:FindFirstChild("OpenSaveButton")
                        if openBtn then
                            openBtn.Visible = true
                            openBtn.Active  = true
                        end

                        local tag = Instance.new("BoolValue")
                        tag.Name  = "_HPInjected"
                        tag.Value = true
                        tag.Parent = clone

                        clone.Parent = sf
                        injectedCount = injectedCount + 1

                        if not gameNumToInfo[gn] then
                            gameNumToInfo[gn] = {filepath=info.filepath, gameName=gameName}
                        end
                    end
                end

                if injectedCount > 0 then
                    setStatus("📂 "..injectedCount.." project HP tampil di Open dialog ✓",
                        Color3.fromRGB(80,200,255))
                else
                    setStatus("📂 Slot HP sudah ada di dialog", Color3.fromRGB(150,200,150))
                end
            end)
            if not ok then
                setStatus("⚠ Inject dialog error: "..tostring(err):sub(1,60),
                    Color3.fromRGB(255,80,80))
            end
        end

        -- ── Sinkronkan teks tombol HP ke mode dialog ──────────────────
        local function syncHPButtonsToDialogMode()
            pcall(function()
                local sg = playerGui:FindFirstChild("StudioGui")
                if not sg then return end
                local osf = sg:FindFirstChild("OpenSaveFrame")
                if not osf or not osf.Visible then return end
                local sf = osf:FindFirstChild("ScrollingFrame")
                if not sf then return end
                local modeText = nil
                for _, child in ipairs(sf:GetChildren()) do
                    local isHP = child:FindFirstChild("_HPInjected")
                    if not isHP and child.Name ~= "OpenSaveTemplate"
                       and (child:IsA("Frame") or child:IsA("ScrollingFrame")) then
                        local f1  = child:FindFirstChild("Frame1")
                        local btn = f1 and f1:FindFirstChild("OpenSaveButton")
                        if btn and (btn.Text == "Save" or btn.Text == "Open" or btn.Text == "Load") then
                            modeText = btn.Text
                            break
                        end
                    end
                end
                if not modeText then return end
                for _, child in ipairs(sf:GetChildren()) do
                    if child:FindFirstChild("_HPInjected") then
                        local f1  = child:FindFirstChild("Frame1")
                        local btn = f1 and f1:FindFirstChild("OpenSaveButton")
                        if btn then btn.Text = modeText end
                    end
                end
            end)
        end

        local function watchOpenSaveFrameMode()
            if dialogModeConn then
                pcall(function() dialogModeConn:Disconnect() end)
                dialogModeConn = nil
            end
            spawn(function()
                pcall(function()
                    local sg  = playerGui:WaitForChild("StudioGui", 15)
                    if not sg then return end
                    local osf = sg:WaitForChild("OpenSaveFrame", 15)
                    if not osf then return end
                    dialogModeConn = osf:GetPropertyChangedSignal("Visible"):Connect(function()
                        if not osf.Visible then return end
                        wait(0.2)
                        syncHPButtonsToDialogMode()
                    end)
                end)
            end)
        end

        -- ── Override notifikasi SL ────────────────────────────────────
        local function startNotifOverride()
            if notifConn then pcall(function() notifConn:Disconnect() end) end
            local ok, wt = pcall(function()
                local sg = playerGui:WaitForChild("StudioGui", 10)
                if not sg then return nil end
                return sg:WaitForChild("WarningText", 5)
            end)
            if not ok or not wt then return end
            notifConn = wt:GetPropertyChangedSignal("Text"):Connect(function()
                local txt = wt.Text
                if txt:find("PONSEL") or txt:find("HP") then return end
                if txt:match("^Saving ") or txt == "Saving..." then
                    wt.Text = "💾 SAVE KE PONSEL CUSTOM"
                elseif txt:match("^Loading ") or txt == "Loading..." then
                    wt.Text = "📂 OPEN PROJECT DARI PONSEL"
                elseif txt == "Saved"  then wt.Text = "✅ TERSIMPAN DI HP"
                elseif txt == "Ready"  then wt.Text = "✅ DIMUAT DARI HP"
                elseif txt == "Publish..." then wt.Text = "⬆ PUBLISH (RELAY V8)"
                end
            end)
        end

        -- ── Snapshot workspace SL saat ini → simpan ke project HP ──
        local function saveCurrentToProject(gn, gameName)
            setStatus("⏳ Snapshot workspace...", Color3.fromRGB(200,200,80))
            wait()
            local SLFolderRS = rs:FindFirstChild("StudioLiteFolder")
            if not SLFolderRS then
                setStatus("⚠ StudioLiteFolder tidak ada — buka SL dulu", Color3.fromRGB(255,80,80)); return
            end
            local sg = playerGui:FindFirstChild("StudioGui")
            if not sg then
                setStatus("⚠ StudioGui tidak ada", Color3.fromRGB(255,80,80)); return
            end
            local mc = getMainConvert()
            if not mc then
                setStatus("⚠ MainConvertModule belum ready — tekan 🔎 Hubungkan", Color3.fromRGB(255,80,80)); return
            end
            local okM, cloneMod = pcall(function()
                return require(sg:WaitForChild("CloneLocalWorkspaceToReplicatedStorageModule", 5))
            end)
            if not okM or type(cloneMod) ~= "table" then
                setStatus("⚠ CloneLocalMod: "..tostring(cloneMod):sub(1,40), Color3.fromRGB(255,80,80)); return
            end
            for i = 1, 5 do
                if not SLFolderRS:FindFirstChild("SLPanel_Snap") then break end
                pcall(function() SLFolderRS.SLPanel_Snap:Destroy() end)
                wait(0.1)
            end
            local settings = {
                PrintCompletionTime=false, PrintObjectVariableErrors=false,
                PrintDataStoreApproximateSize=true, ExcludedProperties={"BrickColor"},
                ShowHTTPWarning=false
            }
            local ok1, cFolder = pcall(function() return cloneMod:CloneLocal("SLPanel_Snap") end)
            if not ok1 or not cFolder then
                setStatus("⚠ CloneLocal gagal: "..tostring(cFolder):sub(1,40), Color3.fromRGB(255,80,80)); return
            end
            local ok2, gtable = pcall(function() return mc:Convert(cFolder, settings) end)
            pcall(function() cFolder:Destroy() end)
            if not ok2 or type(gtable) ~= "table" then
                setStatus("⚠ Convert gagal: "..tostring(gtable):sub(1,40), Color3.fromRGB(255,80,80)); return
            end
            local snapName = projFolderName(gameName)
            pcall(function()
                if type(gtable.Name) == "string" then gtable.Name = snapName end
            end)
            local ok3, json = pcall(hs.JSONEncode, hs, gtable)
            if not ok3 or not json or #json < 4 then
                setStatus("⚠ JSONEncode gagal", Color3.fromRGB(255,80,80)); return
            end
            local fpath = saveToPhone(json, gn, gameName)
            if fpath then
                currentActiveGame = {gn=gn, gameName=gameName, filepath=fpath}
                setStatus("💾 Tersimpan: "..gameName.." ("..math.floor(#json/1024).."KB) ✓",
                    Color3.fromRGB(80,230,110))
                return fpath
            else
                setStatus("⚠ Gagal tulis file ke HP", Color3.fromRGB(255,80,80))
            end
        end

        -- ── Ambil data game aktif dari HP ──────────────────────────────
        local function getActiveGameData()
            local targetGn, targetName, targetFilepath

            if currentActiveGame then
                targetGn       = currentActiveGame.gn
                targetName     = currentActiveGame.gameName
                targetFilepath = currentActiveGame.filepath
            end

            if not targetName then
                for _, info in ipairs(getAllPhoneFiles()) do
                    if playerGui:FindFirstChild(info.gameName) then
                        targetGn       = info.gn
                        targetName     = info.gameName
                        targetFilepath = info.filepath
                        break
                    end
                end
            end

            if not targetName then
                local pf = getAllPhoneFiles()
                if #pf > 0 then
                    targetGn       = pf[1].gn
                    targetName     = pf[1].gameName
                    targetFilepath = pf[1].filepath
                end
            end

            if not targetName then return nil end

            local rawJson = safeRead(targetFilepath)
            if not rawJson or #rawJson < 4 then
                local i2 = findFileForGameNum(targetGn)
                if i2 then rawJson = safeRead(i2.filepath) end
            end
            if not rawJson or #rawJson < 4 then
                local i3 = findFileForGameName(targetName)
                if i3 then rawJson = safeRead(i3.filepath) end
            end
            if not rawJson or #rawJson < 4 then return nil end

            local ok, tableData = pcall(function() return hs:JSONDecode(rawJson) end)
            if not ok or type(tableData) ~= "table" then return nil end

            return targetGn, targetName, targetFilepath, rawJson, tableData
        end

        -- ── LOAD dari HP → taruh di PlayerGui ────────────────────────
        local function loadFromPhoneToPlayerGui(gameNum)
            local gn   = tostring(gameNum)
            local info = findFileForGameNum(gn)
            if not info then
                setStatus("⚠ Tidak ada file game #"..gn.." di HP — simpan dulu!",
                    Color3.fromRGB(255,100,60))
                return false
            end

            local json = safeRead(info.filepath)
            if not json or #json < 4 then
                setStatus("⚠ File kosong/tidak terbaca: "..fileName(info.filepath),
                    Color3.fromRGB(255,80,80))
                return false
            end

            local ok1, data = pcall(function() return hs:JSONDecode(json) end)
            if not ok1 or type(data) ~= "table" then
                setStatus("⚠ JSON tidak valid di "..fileName(info.filepath),
                    Color3.fromRGB(255,80,80))
                return false
            end

            local mc = getMainConvert()
            if not mc then
                setStatus("⚠ MainConvertModule belum siap — tekan Hubungkan",
                    Color3.fromRGB(255,80,80))
                return false
            end

            local uiGameName = getGameNameFromOpenFrame(gn)
                            or (gameNumToInfo[gn] and gameNumToInfo[gn].gameName)
                            or info.gameName
            uiGameName = uiGameName:gsub("^📱%s*", "")

            pcall(function()
                local old = playerGui:FindFirstChild(uiGameName)
                if old then old:Destroy() end
                for _, c in ipairs(playerGui:GetChildren()) do
                    if c.Name:find("TempSLLoad_", 1, true) then c:Destroy() end
                end
            end)

            local ok2, result = pcall(function()
                return mc:ConvertToInstance(data)
            end)

            if not ok2 or not result then
                local eName = uiGameName or ("game"..gn)
                local ef = Instance.new("Folder")
                ef.Name   = eName
                ef.Parent = playerGui
                setStatus("⚠ Konversi gagal: "..tostring(result):sub(1,50)
                    .." | Folder darurat: "..eName, Color3.fromRGB(255,80,80))
                return true
            end

            result.Parent = playerGui

            if uiGameName and uiGameName ~= "" and result.Name ~= uiGameName then
                local existing = playerGui:FindFirstChild(uiGameName)
                if existing and existing ~= result then existing:Destroy() end
                result.Name = uiGameName
            end

            openCount = openCount + 1
            setStatus("📂 #"..openCount.." DIBUKA: "..result.Name..
                " ("..math.floor(#json/1024).."KB)", Color3.fromRGB(80,180,255))

            currentActiveGame = {
                gn       = gn,
                gameName = result.Name,
                filepath = info.filepath,
            }
            return true
        end

        -- ── Manual load ke workspace (FIX v9.18) ─────────────────────
        local function manualLoadToSL(filepath)
            if not filepath then
                setStatus("⚠ Pilih file dulu!", Color3.fromRGB(255,180,60)); return
            end
            if not SLFolder then
                setStatus("⚠ SL belum terhubung", Color3.fromRGB(255,80,80)); return
            end
            local json = safeRead(filepath)
            if not json or #json < 4 then
                setStatus("⚠ File kosong atau tidak bisa dibaca", Color3.fromRGB(255,80,80)); return
            end
            local ok1, data = pcall(function() return hs:JSONDecode(json) end)
            if not ok1 or type(data) ~= "table" then
                setStatus("⚠ JSON tidak valid", Color3.fromRGB(255,80,80)); return
            end
            local mc = getMainConvert()
            if not mc then
                setStatus("⚠ MainConvertModule belum ready", Color3.fromRGB(255,80,80)); return
            end

            setStatus("⏳ Konversi data...", Color3.fromRGB(200,200,80))
            wait()

            local ok2, gameFolder = pcall(function() return mc:ConvertToInstance(data) end)
            if not ok2 or not gameFolder then
                setStatus("⚠ Konversi gagal: "..tostring(gameFolder):sub(1,60),
                    Color3.fromRGB(255,80,80)); return
            end

            local fn    = fileName(filepath)
            local gn    = fn:match("^gamenum(%d+)_") or "0"
            local rawN  = fn:match("^gamenum%d+_(.+)_%d+%.json$") or "project"
            local gname = (gameNumToInfo[gn] and gameNumToInfo[gn].gameName)
                          or rawN:gsub("_"," ")
            pcall(function()
                local old = playerGui:FindFirstChild(gameFolder.Name)
                if old then old:Destroy() end
            end)
            gameFolder.Parent = playerGui

            local sg = playerGui:FindFirstChild("StudioGui")
            if not sg then
                setStatus("⚠ StudioGui belum ada — pakai fallback workspace load",
                    Color3.fromRGB(255,180,60))
                local ws = game:GetService("Workspace")
                for _, c in ipairs(ws:GetChildren()) do
                    if not c:IsA("Camera") and not c:IsA("Terrain") then
                        pcall(function() c:Destroy() end)
                    end
                end
                local wsF = gameFolder:FindFirstChild("Workspace")
                if wsF then
                    for _, c in ipairs(wsF:GetChildren()) do pcall(function() c.Parent = ws end) end
                else
                    for _, c in ipairs(gameFolder:GetChildren()) do pcall(function() c.Parent = ws end) end
                end
                pcall(function() gameFolder:Destroy() end)
                setStatus("✅ Dimuat (fallback) — Play mungkin tidak bekerja",
                    Color3.fromRGB(255,200,60))
                return
            end

            local okCW, ClearWS = pcall(function()
                return require(sg:WaitForChild("ClearClientWorkspaceModule", 5))
            end)
            local okCP, ClonePathGame = pcall(function()
                return require(sg:WaitForChild("ClonePathGameToLocalWorkspaceModule", 5))
            end)
            local okCSG, CloneStarterGui = pcall(function()
                return require(sg:WaitForChild("CloneStarterGuiForEditOrPlayModule", 5))
            end)

            setStatus("⏳ Membersihkan state SL...", Color3.fromRGB(200,200,80))
            wait()
            if okCW and type(ClearWS) == "table" then
                pcall(function() ClearWS:ClearWorkspace() end)
            else
                local ws = game:GetService("Workspace")
                for _, c in ipairs(ws:GetChildren()) do
                    if not c:IsA("Camera") and not c:IsA("Terrain") then
                        pcall(function() c:Destroy() end)
                    end
                end
            end

            setStatus("⏳ Memuat game ke SL (full restore)...", Color3.fromRGB(200,200,80))
            wait()
            local loadOk = false
            if okCP and type(ClonePathGame) == "table" then
                local okLoad, errLoad = pcall(function()
                    ClonePathGame:Load(gameFolder)
                end)
                if okLoad then
                    loadOk = true
                else
                    setStatus("⚠ ClonePathGame:Load error: "..tostring(errLoad):sub(1,50),
                        Color3.fromRGB(255,180,60))
                end
            end

            if not loadOk then
                local ws = game:GetService("Workspace")
                local wsF = gameFolder:FindFirstChild("Workspace")
                if wsF then
                    for _, c in ipairs(wsF:GetChildren()) do pcall(function() c.Parent = ws end) end
                else
                    for _, c in ipairs(gameFolder:GetChildren()) do pcall(function() c.Parent = ws end) end
                end
                setStatus("⚠ Full restore gagal, fallback WS only — Play mungkin stuck",
                    Color3.fromRGB(255,180,60))
            end

            if okCSG and type(CloneStarterGui) == "table" then
                pcall(function() CloneStarterGui:Edit() end)
            end

            pcall(function() gameFolder:Destroy() end)

            openCount = openCount + 1
            currentActiveGame = {
                gn       = gn,
                gameName = gname,
                filepath = filepath,
            }
            setStatus(
                "📂 #"..openCount.." DIBUKA: "..gname
                .." ("..math.floor(#json/1024).."KB) | Play siap ✓",
                Color3.fromRGB(80,180,255))
        end

        -- ── relayInvoke ───────────────────────────────────────────────
        local function relayInvoke(...)
            bypassHook = true
            local ok, r1, r2 = pcall(function(...)
                return ServerFunctions:InvokeServer(...)
            end, ...)
            bypassHook = false
            if ok then return r1, r2 end
            return nil, tostring(r1)
        end

        -- ── publishFromPhone ──────────────────────────────────────────
        local function publishFromPhone(filepath)
            if not filepath then
                setStatus("⚠ Pilih file dulu!", Color3.fromRGB(255,180,60)); return
            end
            if not ServerFunctions then
                setStatus("⚠ SL belum terhubung — tekan 🔎 Hubungkan", Color3.fromRGB(255,80,80)); return
            end
            if not hookActive then
                setStatus("⚠ Hook tidak aktif — aktifkan mode PONSEL dulu", Color3.fromRGB(255,80,80)); return
            end

            local fn    = fileName(filepath)
            local gn    = fn:match("^gamenum(%d+)_") or "1"
            local rawN  = fn:match("^gamenum%d+_(.+)_%d+%.json$") or "project"
            local gname = rawN:gsub("_"," ")

            local json = safeRead(filepath)
            if not json or #json < 4 then
                setStatus("⚠ File kosong / tidak bisa dibaca: "..fn:sub(1,40),
                    Color3.fromRGB(255,80,80)); return
            end

            local okDec, gameTable = pcall(hs.JSONDecode, hs, json)
            if not okDec or type(gameTable) ~= "table" then
                setStatus("⚠ JSON decode gagal — file mungkin corrupt: "..tostring(gameTable):sub(1,50),
                    Color3.fromRGB(255,80,80)); return
            end

            pcall(function()
                if type(gameTable.Name) == "string" then
                    local n = gameTable.Name:lower()
                    if n == "slpanel_snap" or n == "slpanel snap" or n == "sl panel snap" then
                        gameTable.Name = projFolderName(gname)
                    end
                end
            end)

            local slotForRelay = lastKnownSLSlot or gn

            local kb = math.floor(#json / 1024)
            setStatus("⬆ Pub HP: "..gname.." ("..kb.."KB) → relay slot "
                ..tostring(slotForRelay).." (non-chunked)...",
                Color3.fromRGB(200,180,60))

            spawn(function()
                local CHUNK = 3400000
                local v23, v24

                if #json <= CHUNK then
                    pendingGameName = gname
                    v23, v24 = relayInvoke("Save", gameTable, slotForRelay, "", true)
                else
                    setStatus("⬆ Pub HP: file besar ("..kb.."KB) → chunked relay...",
                        Color3.fromRGB(180,180,60))
                    local r1, r2 = relayInvoke("Save", "start")
                    if r1 == nil and r2 and r2 ~= "" then
                        setStatus("⚠ Relay start error: "..tostring(r2):sub(1,50),
                            Color3.fromRGB(255,80,80)); return
                    end
                    local total = math.ceil(#json / CHUNK)
                    local cnt   = 0
                    for i = 1, #json, CHUNK do
                        local ch = json:sub(i, math.min(i + CHUNK - 1, #json))
                        local cr1, cr2 = relayInvoke("Save", ch)
                        if cr1 == nil and cr2 and cr2 ~= "" then
                            setStatus("⚠ Chunk gagal di byte "..i..": "..tostring(cr2):sub(1,40),
                                Color3.fromRGB(255,80,80)); return
                        end
                        cnt = cnt + 1
                        setStatus("⬆ Chunk "..cnt.."/"..total.."...", Color3.fromRGB(180,180,60))
                        wait()
                    end
                    v23, v24 = relayInvoke("Save", "end", slotForRelay, "", true)
                end

                if v23 == true then
                    publishCount = publishCount + 1
                    if reloadFunc then spawn(function() wait(0.1); reloadFunc() end) end
                    setStatus(
                        "✅ Relay OK! SL buka PublishFrame → Pilih tempat + isi API key",
                        Color3.fromRGB(80,230,110))
                    pcall(function()
                        local sg  = playerGui:FindFirstChild("StudioGui")
                        if not sg then return end
                        local tb  = sg:FindFirstChild("TopBar")
                        local sdf = tb and tb:FindFirstChild("SaveDetailsFrame")
                        local box = sdf and sdf:FindFirstChild("GameNameTextBox")
                        if box then box.Text = gname end
                    end)
                else
                    setStatus(
                        "⚠ Server tolak: "..tostring(v24 or "?"):sub(1,60)
                        .."\n💡 Coba save dulu lewat SL (File→Save) agar slot terdaftar",
                        Color3.fromRGB(255,100,60))
                end
            end)
        end

        -- ── activateHook ──────────────────────────────────────────────
        local function activateHook()
            if hookActive then return true, "Hook sudah aktif" end
            if not hookmetamethod or not getnamecallmethod then
                return false, "hookmetamethod/getnamecallmethod tidak tersedia"
            end
            if not ServerFunctions then
                return false, "ServerFunctions belum ditemukan"
            end

            local ok, err = pcall(function()
                origNamecall = hookmetamethod(game, "__namecall", function(self, ...)
                    local method = getnamecallmethod()
                    if method ~= "InvokeServer" then
                        return origNamecall(self, ...)
                    end

                    local args   = {...}
                    local action = tostring(args[1] or "")

                    if bypassHook then
                        return origNamecall(self, ...)
                    end

                    if not panelEnabled then
                        return origNamecall(self, ...)
                    end

                    if not ServerFunctions or self ~= ServerFunctions then
                        return origNamecall(self, ...)
                    end

                    if action == "Save" then
                        local data = args[2]

                        if data == "start" then
                            chunkBuffer     = {}
                            pendingGameName = pendingGameName or readSaveGameNameFromUI()
                            if saveMode == "ponsel" then return true, nil end

                        elseif type(data) == "string" and data ~= "start" and data ~= "end" then
                            table.insert(chunkBuffer, data)
                            if saveMode == "ponsel" then return true, nil end

                        elseif data == "end" then
                            local slotNum  = args[3]
                            if slotNum ~= nil then lastKnownSLSlot = tostring(slotNum) end
                            local desc     = tostring(args[4] or "")
                            local isPub    = args[5] == true
                            local gameNum  = tostring(slotNum or "0")
                            local gameName = pendingGameName
                                             or readSaveGameNameFromUI()
                                             or ("game"..gameNum)
                            pendingGameName = nil

                            local fullJson = nil
                            if #chunkBuffer > 0 then
                                fullJson    = table.concat(chunkBuffer, "")
                                chunkBuffer = {}
                            end

                            if fullJson and #fullJson > 4 then
                                saveToPhone(fullJson, gameNum, gameName)
                            end

                            if saveMode == "ponsel" then
                                if isPub and fullJson and #fullJson > 4 then
                                    local kb = math.floor(#fullJson / 1024)
                                    setStatus("⬆ Save+Pub relay "..kb.."KB"
                                        .." → server slot "..gameNum.."...",
                                        Color3.fromRGB(180,180,60))

                                    pcall(function()
                                        origNamecall(ServerFunctions, "Save", "start")
                                    end)

                                    local CHUNK = 3400000
                                    for i = 1, #fullJson, CHUNK do
                                        local ch = fullJson:sub(i,
                                            math.min(i + CHUNK - 1, #fullJson))
                                        pcall(function()
                                            origNamecall(ServerFunctions, "Save", ch)
                                        end)
                                        if #fullJson > CHUNK then wait() end
                                    end

                                    local v23, v24 = origNamecall(
                                        ServerFunctions, "Save", "end",
                                        slotNum, desc, true
                                    )

                                    if v23 then
                                        setStatus(
                                            "✓ Relay OK "..kb.."KB"
                                            .." | Pilih tempat → Publish...",
                                            Color3.fromRGB(100,220,100))
                                    else
                                        setStatus(
                                            "⚠ Server tolak: "
                                            ..tostring(v24 or ""):sub(1,50),
                                            Color3.fromRGB(255,120,60))
                                    end

                                    return v23, v24
                                else
                                    return true, nil
                                end
                            end

                        elseif type(data) == "table" then
                            local slotNum  = args[3]
                            if slotNum ~= nil then lastKnownSLSlot = tostring(slotNum) end
                            local desc     = tostring(args[4] or "")
                            local isPub    = args[5] == true
                            local gameNum  = tostring(slotNum or "0")
                            local gameName = pendingGameName
                                             or readSaveGameNameFromUI()
                                             or ("game"..gameNum)
                            pendingGameName = nil
                            chunkBuffer     = {}

                            local okJ, json = pcall(hs.JSONEncode, hs, data)
                            if okJ and json and #json > 4 then
                                saveToPhone(json, gameNum, gameName)
                            else
                                setStatus("⚠ JSONEncode gagal game #"..gameNum,
                                    Color3.fromRGB(255,80,80))
                            end

                            if saveMode == "ponsel" then
                                if isPub then
                                    local kb = math.floor(#(json or "") / 1024)
                                    setStatus("⬆ Save+Pub relay table"
                                        .." ("..kb.."KB) → server slot "..gameNum.."...",
                                        Color3.fromRGB(180,180,60))
                                    local v23, v24 = origNamecall(self, ...)
                                    if v23 then
                                        setStatus(
                                            "✓ Relay OK | Pilih tempat → Publish...",
                                            Color3.fromRGB(100,220,100))
                                    else
                                        setStatus(
                                            "⚠ Server tolak: "
                                            ..tostring(v24 or ""):sub(1,50),
                                            Color3.fromRGB(255,120,60))
                                    end
                                    return v23, v24
                                else
                                    return true, nil
                                end
                            end

                        else
                            local gameNum  = tostring(args[3] or "0")
                            local gameName = pendingGameName
                                             or readSaveGameNameFromUI()
                                             or ("game"..gameNum)
                            pendingGameName = nil
                            if type(data) == "string" and #data > 4 then
                                saveToPhone(data, gameNum, gameName)
                            end
                            if saveMode == "ponsel" then return true, nil end
                        end

                        return origNamecall(self, ...)

                    elseif action == "OpenMenu" then
                        if saveMode == "ponsel" then
                            local r1, r2, r3 = origNamecall(self, ...)
                            spawn(function()
                                wait(0.4)
                                injectPhoneSavesIntoOpenDialog()
                            end)
                            return r1, r2, r3
                        end

                    elseif action == "LoadDbGameToPlayerGui" then
                        if saveMode == "ponsel" then
                            local gameNum = tostring(args[2] or "0")
                            local success = loadFromPhoneToPlayerGui(gameNum)
                            if success then
                                return true
                            else
                                setStatus("⚠ Tidak ada data HP → ke server SL",
                                    Color3.fromRGB(255,180,60))
                                return origNamecall(self, ...)
                            end
                        end

                    elseif action == "ClonePathGameToLocalWorkspaceModule" then
                        if saveMode == "ponsel" then
                            local rawPath     = tostring(args[2] or "")
                            local gamePathName = rawPath:gsub("^[%s%z\xF0-\xFF][\x80-\xBF]*[\x80-\xBF]*[\x80-\xBF]*%s*", "")
                            gamePathName = gamePathName:gsub("^📱%s*",""):gsub("^📂%s*","")

                            if gamePathName == "" then
                                if currentActiveGame then
                                    gamePathName = currentActiveGame.gameName
                                else
                                    for _, c in ipairs(playerGui:GetChildren()) do
                                        if c:IsA("Folder") and c:FindFirstChild("Workspace") then
                                            gamePathName = c.Name; break
                                        end
                                    end
                                end
                            end

                            local gameFolder = playerGui:FindFirstChild(gamePathName)
                            if not gameFolder and rawPath ~= gamePathName then
                                gameFolder = playerGui:FindFirstChild(rawPath)
                            end
                            if not gameFolder and currentActiveGame then
                                gameFolder = playerGui:FindFirstChild(currentActiveGame.gameName)
                                if gameFolder then gamePathName = currentActiveGame.gameName end
                            end

                            if gameFolder then
                                local ws = game:GetService("Workspace")
                                for _, c in ipairs(ws:GetChildren()) do
                                    if not c:IsA("Camera") and not c:IsA("Terrain") then
                                        pcall(function() c:Destroy() end)
                                    end
                                end
                                local wsFolder = gameFolder:FindFirstChild("Workspace")
                                if wsFolder then
                                    for _, c in ipairs(wsFolder:GetChildren()) do
                                        pcall(function() c.Parent = ws end)
                                    end
                                    pcall(function() gameFolder:Destroy() end)
                                else
                                    for _, c in ipairs(gameFolder:GetChildren()) do
                                        pcall(function() c.Parent = ws end)
                                    end
                                    pcall(function() gameFolder:Destroy() end)
                                end
                                setStatus("✅ "..gamePathName.." dimuat ke workspace ✓",
                                    Color3.fromRGB(80,230,110))
                                return true
                            end
                            setStatus("⚠ CloneToWS: folder '"..gamePathName.."' tidak ada di PlayerGui",
                                Color3.fromRGB(255,180,60))
                            return true
                        end

                    elseif action == "ClearGameFromPlayerGui" then
                        return origNamecall(self, ...)
                    end

                    return origNamecall(self, ...)
                end)
            end)

            if not ok then
                return false, "hookmetamethod error: "..tostring(err)
            end
            hookActive = true
            return true, "Hook aktif"
        end

        local function deactivateHook()
            if not hookActive or not origNamecall then return end
            pcall(function() hookmetamethod(game, "__namecall", origNamecall) end)
            origNamecall = nil
            hookActive   = false
        end

        -- ── Monitor & findSL ─────────────────────────────────────────
        local function startMonitor()
            if monConnection then pcall(function() monConnection:Disconnect() end) end
            if not SLFolder then return false end
            monConnection = SLFolder.ChildAdded:Connect(function(child)
                if not child:IsA("Folder") then return end
                wait(0.25)
                if not child.Parent then return end
                if child:FindFirstChild("Workspace") then
                    pendingGameName = child.Name
                end
            end)
            return true
        end

        local function findSLComponents()
            local ok1, sf = pcall(function()
                return rs:WaitForChild("StudioLiteFolder", 10)
            end)
            if not ok1 or not sf then return false end
            SLFolder = sf
            local ok2, srv = pcall(function()
                return sf:WaitForChild("ServerFunctions", 5)
            end)
            if ok2 and srv then ServerFunctions = srv end
            getMainConvert()
            return true
        end

