        -- ── Tab helpers ───────────────────────────────────────────────
        local function updateTabUI()
            local ca=Color3.fromRGB(18,85,200); local ci=Color3.fromRGB(12,20,32)
            local ta=Color3.fromRGB(255,255,255); local ti=Color3.fromRGB(90,130,170)
            btnTabSave.BackgroundColor3  =currentTab=="save"   and ca or ci
            btnTabOpen.BackgroundColor3  =currentTab=="open"   and ca or ci
            btnTabBackup.BackgroundColor3=currentTab=="backup" and ca or ci
            btnTabSave.TextColor3  =currentTab=="save"   and ta or ti
            btnTabOpen.TextColor3  =currentTab=="open"   and ta or ti
            btnTabBackup.TextColor3=currentTab=="backup" and ta or ti
        end

        local function clearScroll()
            for _,c in ipairs(tabScroll:GetChildren()) do
                if not c:IsA("UIListLayout") and not c:IsA("UIPadding") then c:Destroy() end
            end
            selectedPath=nil; selectedEntry=nil
            countLbl.Text="💾"..interceptCount.."  📂"..openCount.."  ⬆"..publishCount
        end

        local function emptyRow(msg)
            local lbl=Instance.new("TextLabel")
            lbl.Size=UDim2.new(1,0,0,130); lbl.BackgroundTransparency=1
            lbl.Text=msg; lbl.TextColor3=Color3.fromRGB(80,130,100); lbl.TextSize=10
            lbl.Font=Enum.Font.Gotham; lbl.TextWrapped=true
            lbl.TextXAlignment=Enum.TextXAlignment.Center; lbl.Parent=tabScroll
        end

        -- showBackupSublist
        local function showBackupSublist(proj)
            clearScroll()
            updateTabUI()
            selectedProjRawName = proj.rawName
            local bups  = getProjectBackups(proj.rawName)
            local pName = proj.gameName

            if #bups == 0 then
                emptyRow("Belum ada backup untuk\n"..pName.."\n\nBackup dibuat otomatis\nsaat project di-save ulang")
                setStatus("Belum ada backup: "..pName, Color3.fromRGB(180,180,80))
                infoLbl.Text = "Backup: "..pName.." | belum ada versi"
                return
            end

            local hdr=Instance.new("TextLabel")
            hdr.Size=UDim2.new(1,0,0,18); hdr.BackgroundTransparency=1
            hdr.Text="🗃 "..pName.." — "..#bups.." versi backup"
            hdr.TextColor3=Color3.fromRGB(100,200,240); hdr.TextSize=10
            hdr.Font=Enum.Font.GothamBold; hdr.TextXAlignment=Enum.TextXAlignment.Left
            hdr.Parent=tabScroll

            local selectedBupEntry = nil

            for _, bup in ipairs(bups) do
                local be=Instance.new("Frame")
                be.Size=UDim2.new(1,0,0,38)
                be.BackgroundColor3=Color3.fromRGB(10,14,22); be.BorderSizePixel=0
                be.Parent=tabScroll
                Instance.new("UICorner",be).CornerRadius=UDim.new(0,6)
                local beStroke=Instance.new("UIStroke",be)
                beStroke.Color=Color3.fromRGB(25,40,70); beStroke.Thickness=1

                local bl=Instance.new("TextLabel")
                bl.Size=UDim2.new(1,-168,0,18); bl.Position=UDim2.new(0,8,0,3)
                bl.BackgroundTransparency=1
                bl.Text="📅 "..formatTimestamp(bup.timestamp)
                bl.TextColor3=Color3.fromRGB(140,200,160); bl.TextSize=9
                bl.Font=Enum.Font.GothamBold; bl.TextXAlignment=Enum.TextXAlignment.Left
                bl.TextTruncate=Enum.TextTruncate.AtEnd; bl.Parent=be

                local bl2=Instance.new("TextLabel")
                bl2.Size=UDim2.new(1,-168,0,14); bl2.Position=UDim2.new(0,8,0,21)
                bl2.BackgroundTransparency=1
                bl2.Text=bup.filename:sub(1,30)
                bl2.TextColor3=Color3.fromRGB(70,120,90); bl2.TextSize=8
                bl2.Font=Enum.Font.Code; bl2.TextXAlignment=Enum.TextXAlignment.Left
                bl2.TextTruncate=Enum.TextTruncate.AtEnd; bl2.Parent=be

                local brRestore=Instance.new("TextButton")
                brRestore.Size=UDim2.new(0,72,0,28); brRestore.Position=UDim2.new(1,-158,0.5,-14)
                brRestore.BackgroundColor3=Color3.fromRGB(55,55,15); brRestore.Text="🔄 Restore"
                brRestore.TextColor3=Color3.fromRGB(230,220,100); brRestore.TextSize=9
                brRestore.Font=Enum.Font.GothamBold; brRestore.BorderSizePixel=0; brRestore.Parent=be
                Instance.new("UICorner",brRestore).CornerRadius=UDim.new(0,6)

                local brDel=Instance.new("TextButton")
                brDel.Size=UDim2.new(0,72,0,28); brDel.Position=UDim2.new(1,-80,0.5,-14)
                brDel.BackgroundColor3=Color3.fromRGB(120,20,20); brDel.Text="🗑 Hapus"
                brDel.TextColor3=Color3.fromRGB(255,200,200); brDel.TextSize=9
                brDel.Font=Enum.Font.GothamBold; brDel.BorderSizePixel=0; brDel.Parent=be
                Instance.new("UICorner",brDel).CornerRadius=UDim.new(0,6)

                local hit=Instance.new("TextButton")
                hit.Size=UDim2.new(1,-165,1,0); hit.Position=UDim2.new(0,0,0,0)
                hit.BackgroundTransparency=1; hit.Text=""; hit.ZIndex=2; hit.Parent=be

                local bFp=bup.filepath; local bTs=bup.timestamp; local bFn=bup.filename

                hit.MouseButton1Click:Connect(function()
                    if selectedBupEntry then
                        selectedBupEntry.BackgroundColor3=Color3.fromRGB(10,14,22)
                        local st=selectedBupEntry:FindFirstChildOfClass("UIStroke")
                        if st then st.Color=Color3.fromRGB(25,40,70) end
                    end
                    selectedBupEntry=be
                    be.BackgroundColor3=Color3.fromRGB(8,30,50)
                    beStroke.Color=Color3.fromRGB(40,120,200)
                    selectedPath=bFp; selectedEntry=be
                    local kb=0
                    pcall(function() local d=safeRead(bFp); if d then kb=math.floor(#d/1024) end end)
                    infoLbl.Text="🗃 "..formatTimestamp(bTs).." | "..kb.."KB | "..bFn:sub(1,28)
                    setStatus("Dipilih backup: "..formatTimestamp(bTs), Color3.fromRGB(120,200,240))
                end)

                brRestore.MouseButton1Click:Connect(function()
                    setStatus("🔄 Restore backup "..formatTimestamp(bTs).."...",
                        Color3.fromRGB(200,200,80))
                    manualLoadToSL(bFp)
                end)

                brDel.MouseButton1Click:Connect(function()
                    safeDelete(bFp)
                    setStatus("🗑 Backup dihapus: "..formatTimestamp(bTs), Color3.fromRGB(220,100,80))
                    if selectedPath==bFp then selectedPath=nil; selectedEntry=nil end
                    wait(0.15)
                    local updatedProjects=getAllProjects()
                    local updatedProj=nil
                    for _, p in ipairs(updatedProjects) do
                        if p.rawName==selectedProjRawName then updatedProj=p; break end
                    end
                    if updatedProj then
                        showBackupSublist(updatedProj)
                    else
                        currentTab="open"; loadFiles()
                    end
                end)
            end

            setStatus("🗃 "..#bups.." backup: "..pName.." | tap untuk pilih, 🗑 untuk hapus",
                Color3.fromRGB(90,220,130))
            infoLbl.Text="Backup: "..pName.." | "..#bups.." versi — tap baris untuk pilih"
        end

        -- makeProjectRow
        local function makeProjectRow(proj, mode)
            local e=Instance.new("Frame")
            e.Name="proj_"..proj.rawName
            e.Size=UDim2.new(1,0,0,50)
            e.BackgroundColor3=Color3.fromRGB(12,17,28); e.BorderSizePixel=0; e.Parent=tabScroll
            Instance.new("UICorner",e).CornerRadius=UDim.new(0,7)
            local eStroke=Instance.new("UIStroke",e)
            eStroke.Color=Color3.fromRGB(25,40,70); eStroke.Thickness=1

            local n1=Instance.new("TextLabel")
            n1.Size=UDim2.new(1,-84,0,22); n1.Position=UDim2.new(0,8,0,4)
            n1.BackgroundTransparency=1; n1.Text=proj.gameName
            n1.TextColor3=Color3.fromRGB(200,240,215); n1.TextSize=11; n1.Font=Enum.Font.GothamBold
            n1.TextXAlignment=Enum.TextXAlignment.Left; n1.TextTruncate=Enum.TextTruncate.AtEnd
            n1.Parent=e

            local actClr=mode=="save" and Color3.fromRGB(15,105,45) or Color3.fromRGB(15,80,190)
            local actTxt=mode=="save" and "💾 Save" or "📂 Open"
            local btnAct=Instance.new("TextButton")
            btnAct.Size=UDim2.new(0,74,0,22); btnAct.Position=UDim2.new(1,-78,0,2)
            btnAct.BackgroundColor3=actClr; btnAct.Text=actTxt
            btnAct.TextColor3=Color3.fromRGB(255,255,255); btnAct.TextSize=10
            btnAct.Font=Enum.Font.GothamBold; btnAct.BorderSizePixel=0
            btnAct.ZIndex=3; btnAct.Parent=e
            Instance.new("UICorner",btnAct).CornerRadius=UDim.new(0,6)

            local dateStr=formatTimestamp(proj.timestamp)
            local n2=Instance.new("TextLabel")
            n2.Size=UDim2.new(1,-90,0,16); n2.Position=UDim2.new(0,8,0,28)
            n2.BackgroundTransparency=1
            n2.Text="🕐 "..dateStr
            n2.TextColor3=Color3.fromRGB(70,150,110); n2.TextSize=8; n2.Font=Enum.Font.Code
            n2.TextXAlignment=Enum.TextXAlignment.Left; n2.TextTruncate=Enum.TextTruncate.AtEnd
            n2.Parent=e

            local moreLabel=proj.backupCount>0 and ("🗃 "..proj.backupCount.." ▼") or "🗃 0 ▼"
            local btnMore=Instance.new("TextButton")
            btnMore.Size=UDim2.new(0,64,0,16); btnMore.Position=UDim2.new(1,-68,0,28)
            btnMore.BackgroundColor3=Color3.fromRGB(20,32,54); btnMore.Text=moreLabel
            btnMore.TextColor3=Color3.fromRGB(100,160,220); btnMore.TextSize=8
            btnMore.Font=Enum.Font.Code; btnMore.BorderSizePixel=0
            btnMore.ZIndex=3; btnMore.Parent=e
            Instance.new("UICorner",btnMore).CornerRadius=UDim.new(0,5)

            local hit=Instance.new("TextButton")
            hit.Size=UDim2.new(1,0,1,0); hit.BackgroundTransparency=1
            hit.Text=""; hit.ZIndex=2; hit.Parent=e
            hit.MouseButton1Click:Connect(function()
                if selectedEntry then selectedEntry.BackgroundColor3=Color3.fromRGB(12,17,28) end
                selectedEntry=e; selectedPath=proj.filepath; selectedProjRawName=proj.rawName
                e.BackgroundColor3=Color3.fromRGB(8,34,55)
                local kb=0
                pcall(function() local d=safeRead(proj.filepath); if d then kb=math.floor(#d/1024) end end)
                infoLbl.Text="["..proj.gn.."] "..proj.gameName
                    .." | "..kb.."KB | "..dateStr.." | bkp:"..proj.backupCount
                setStatus("Dipilih: "..proj.gameName, Color3.fromRGB(120,220,160))
            end)

            btnAct.MouseButton1Click:Connect(function()
                if selectedEntry then selectedEntry.BackgroundColor3=Color3.fromRGB(12,17,28) end
                selectedEntry=e; selectedPath=proj.filepath; selectedProjRawName=proj.rawName
                e.BackgroundColor3=Color3.fromRGB(8,34,55)
                if mode=="save" then
                    spawn(function() saveCurrentToProject(proj.gn, proj.gameName) end)
                else
                    manualLoadToSL(proj.filepath)
                end
            end)

            btnMore.MouseButton1Click:Connect(function()
                currentTab="backup"
                showBackupSublist(proj)
            end)

            return e
        end

        -- loadFiles
        function loadFiles()
            clearScroll()
            updateTabUI()
            local projects=getAllProjects()

            if currentTab=="save" then
                if #projects==0 then
                    emptyRow("Belum ada project di HP\n\nSave dulu lewat Studio Lite\natau ketik nama di bawah\n→ 💾 Save New")
                    setStatus("Kosong — Save project pertama", Color3.fromRGB(180,180,80))
                else
                    for _, p in ipairs(projects) do makeProjectRow(p,"save") end
                    setStatus("💾 "..#projects.." project siap di-save", Color3.fromRGB(90,220,130))
                end

            elseif currentTab=="open" then
                if #projects==0 then
                    emptyRow("Belum ada project di HP\n\nPilih mode 📱 PONSEL\n→ 🔎 Hubungkan ke SL\n→ Save di Studio Lite")
                    setStatus("Kosong — ikuti instruksi di atas", Color3.fromRGB(180,180,80))
                else
                    for _, p in ipairs(projects) do makeProjectRow(p,"open") end
                    setStatus("📂 "..#projects.." project siap dibuka", Color3.fromRGB(90,220,130))
                end

            elseif currentTab=="backup" then
                if not selectedProjRawName then
                    if #projects>0 then showBackupSublist(projects[1])
                    else emptyRow("Pilih project dulu lalu tekan\n🗃 X bkp ▼ di bawah nama project") end
                else
                    local proj=nil
                    for _, p in ipairs(projects) do
                        if p.rawName==selectedProjRawName then proj=p; break end
                    end
                    if proj then showBackupSublist(proj)
                    else emptyRow("Project tidak ditemukan.\nPilih project dari tab SAVE atau OPEN.") end
                end
            end
        end
        reloadFunc = loadFiles

        -- Tab clicks
        btnTabSave.MouseButton1Click:Connect(function()   currentTab="save";   loadFiles() end)
        btnTabOpen.MouseButton1Click:Connect(function()   currentTab="open";   loadFiles() end)
        btnTabBackup.MouseButton1Click:Connect(function() currentTab="backup"; loadFiles() end)

        -- Button callbacks
        btnRefresh.MouseButton1Click:Connect(function() loadFiles() end)

        btnLoad.MouseButton1Click:Connect(function()
            if not selectedPath then
                setStatus("⚠ Pilih project dulu!", Color3.fromRGB(255,180,60)); return
            end
            manualLoadToSL(selectedPath)
        end)

        btnInject.MouseButton1Click:Connect(function()
            spawn(function()
                setStatus("⏳ Inject ke Open dialog SL...", Color3.fromRGB(200,200,80))
                wait(0.2); injectPhoneSavesIntoOpenDialog()
            end)
        end)

        btnPubHP.MouseButton1Click:Connect(function()
            if not selectedPath then
                setStatus("⚠ Pilih project dulu, lalu tekan ⬆ Pub HP",
                    Color3.fromRGB(255,180,60)); return
            end
            publishFromPhone(selectedPath)
        end)

        btnDelete.MouseButton1Click:Connect(function()
            if not selectedPath then
                setStatus("⚠ Pilih project atau backup dulu!", Color3.fromRGB(255,180,60)); return
            end
            local fn=fileName(selectedPath)
            local isBackup=selectedPath:find(BACKUP_FOLDER,1,true)
                          and selectedPath:gsub(BACKUP_FOLDER,""):find("/",1,true)~=nil
            local gn=fn:match("^gamenum(%d+)_")
            if not isBackup and gn and gameNumToInfo[gn] and gameNumToInfo[gn].filepath==selectedPath then
                gameNumToInfo[gn]=nil
            end
            safeDelete(selectedPath)
            setStatus("🗑 Dihapus: "..fn:sub(1,40), Color3.fromRGB(220,100,80))
            selectedPath=nil; selectedEntry=nil
            wait(0.2)
            if currentTab=="backup" and selectedProjRawName then
                local updatedProjects=getAllProjects()
                local updatedProj=nil
                for _, p in ipairs(updatedProjects) do
                    if p.rawName==selectedProjRawName then updatedProj=p; break end
                end
                if updatedProj then showBackupSublist(updatedProj)
                else currentTab="open"; loadFiles() end
            else
                loadFiles()
            end
        end)

        btnSaveNew.MouseButton1Click:Connect(function()
            local pname=newProjBox.Text:match("^%s*(.-)%s*$") or ""
            if #pname<2 then
                setStatus("⚠ Isi nama project (min 2 karakter)", Color3.fromRGB(255,180,60)); return
            end
            local usedGns={}
            for _, p in ipairs(getAllProjects()) do usedGns[p.gn]=true end
            local newGn="1"
            for i=1,99 do
                if not usedGns[tostring(i)] then newGn=tostring(i); break end
            end
            spawn(function()
                local fpath=saveCurrentToProject(newGn, pname)
                if fpath then newProjBox.Text=""; loadFiles() end
            end)
        end)

        -- SL status UI
        local function updateSLStatusUI()
            local parts={"🟢 SL terhubung"}
            if ServerFunctions then table.insert(parts," | SF ✓") end
            if MainConvert     then table.insert(parts," | MC ✓") end
            slLbl.Text=table.concat(parts)
            slLbl.TextColor3=Color3.fromRGB(80,220,100)
            btnConnect.BackgroundColor3=Color3.fromRGB(20,70,30)
            btnConnect.Text="✅ Terhubung"
        end

        btnConnect.MouseButton1Click:Connect(function()
            setStatus("🔎 Mencari Studio Lite...", Color3.fromRGB(200,200,80))
            spawn(function()
                local found=findSLComponents()
                if found then
                    startMonitor(); startNotifOverride(); watchOpenSaveFrameMode()
                    updateSLStatusUI()
                    if not hookActive then
                        local ok,msg=activateHook()
                        setStatus(
                            ok and "✅ PONSEL aktif — Save+Open+Publish dari HP ✓"
                                or "⚠ Monitor aktif | hookmetamethod: "..msg,
                            ok and Color3.fromRGB(80,200,255) or Color3.fromRGB(255,180,60))
                    else
                        setStatus("✅ SL terhubung | hook aktif", Color3.fromRGB(80,230,110))
                    end
                else
                    slLbl.Text="🔴 SL tidak ditemukan — buka Studio Lite dulu"
                    slLbl.TextColor3=Color3.fromRGB(220,80,80)
                    setStatus("⚠ Buka Studio Lite dulu, lalu tekan lagi", Color3.fromRGB(255,180,60))
                end
            end)
        end)

        -- ── INIT ─────────────────────────────────────────────────────
        loadFiles()
        applyToggleState()   -- terapkan state OFF saat startup

        spawn(function()
            local found=findSLComponents()
            if found then
                -- Tidak auto-start koneksi karena panel mulai dalam keadaan OFF
                updateSLStatusUI()
                setStatus("⏸ Panel OFF — tekan ● ON lalu 🔎 Hubungkan ke SL",
                    Color3.fromRGB(200,150,60))
            else
                slLbl.Text="🔴 SL belum terhubung — tekan 🔎 Hubungkan ke SL"
                slLbl.TextColor3=Color3.fromRGB(200,100,60)
                setStatus("Panel OFF — aktifkan dulu sebelum pakai",
                    Color3.fromRGB(180,180,80))
            end
        end)    end)

    -- ── 2) Embed ke DEX ExplorerPanel (async, pola identik ToolboxPC/Plugin) ──
    task.spawn(function()
        local lp = game:GetService("Players").LocalPlayer
        if not lp then return end

        -- Tunggu SL_Panel_v9 + Frame 'Panel' terbentuk (max 5 detik)
        local sg, panel
        local t0 = tick()
        while tick() - t0 < 5 do
            local pg = lp:FindFirstChildOfClass("PlayerGui")
            sg = pg and pg:FindFirstChild("SL_Panel_v9")
            if sg then
                for _, c in ipairs(sg:GetChildren()) do
                    if c:IsA("Frame") and c.Name == "Panel" then
                        panel = c; break
                    end
                end
            end
            if panel and panel.Parent then break end
            task.wait(0.05)
        end
        if not panel or not panel.Parent then
            warn("[Cloud DEX] Panel belum siap setelah build")
            return
        end

        -- Cari DEX ExplorerPanel
        local dexGui = _findDexGui()
        local explorerPanel = dexGui and dexGui:WaitForChild("ExplorerPanel", 10) or nil

        if not explorerPanel then
            -- Fallback: panel tetap floating
            pcall(function() panel.Visible = true end)
            return
        end

        -- ── ScrollingFrame wrapper di ExplorerPanel ────────────────────
        local scrollWrap
        pcall(function()
            scrollWrap = explorerPanel:FindFirstChild("_CloudScrollWrap")
            if not scrollWrap then
                scrollWrap = Instance.new("ScrollingFrame")
                scrollWrap.Name                   = "_CloudScrollWrap"
                scrollWrap.Size                   = UDim2.new(1, 0, 1, 0)
                scrollWrap.Position               = UDim2.new(0, 0, 0, 0)
                scrollWrap.BackgroundTransparency = 1
                scrollWrap.BorderSizePixel        = 0
                scrollWrap.ScrollingDirection     = Enum.ScrollingDirection.Y
                scrollWrap.ScrollBarThickness     = 0
                scrollWrap.CanvasSize             = UDim2.new(0, 0, 0, 0)
                scrollWrap.ClipsDescendants       = true
                scrollWrap.ZIndex                 = 5
                scrollWrap.Parent                 = explorerPanel
            end
        end)

        -- Native size panel admin (W=312, H=540)
        local PW_NATIVE = 312
        local PH_NATIVE = 540

        -- ── Reparent Frame 'Panel' ke wrapper, native size ─────────────
        pcall(function()
            panel.AnchorPoint      = Vector2.new(0, 0)
            panel.Position         = UDim2.new(0, 0, 0, 0)
            panel.Size             = UDim2.new(0, PW_NATIVE, 0, PH_NATIVE)
            panel.ClipsDescendants = true
            panel.Visible          = true
            panel.Parent           = scrollWrap or explorerPanel
        end)

        -- Hilangkan rounded-corner & stroke supaya menyatu dgn ExplorerPanel
        pcall(function()
            for _, child in ipairs(panel:GetChildren()) do
                if child:IsA("UICorner") or child:IsA("UIStroke") then
                    pcall(function() child:Destroy() end)
                end
            end
        end)

        -- Samakan warna ExplorerPanel dgn background panel admin
        pcall(function()
            explorerPanel.BackgroundColor3       = panel.BackgroundColor3
            explorerPanel.BackgroundTransparency = 0
            explorerPanel.BorderSizePixel        = 0
            explorerPanel.ClipsDescendants       = true
        end)

        -- ── UIScale otomatis: scale panel sesuai lebar ExplorerPanel ──
        pcall(function()
            local uiScale = panel:FindFirstChild("_CloudAutoScale")
            if not uiScale then
                uiScale = Instance.new("UIScale")
                uiScale.Name   = "_CloudAutoScale"
                uiScale.Parent = panel
            end
            local function updScale()
                local w = explorerPanel.AbsoluteSize.X
                if w and w > 0 then
                    local s = math.clamp(w / PW_NATIVE, 0.5, 1.6)
                    uiScale.Scale = s
                    if scrollWrap then
                        scrollWrap.CanvasSize =
                            UDim2.new(0, 0, 0, math.ceil(PH_NATIVE * s) + 8)
                    end
                end
            end
            updScale()
            explorerPanel:GetPropertyChangedSignal("AbsoluteSize"):Connect(updScale)
        end)

        -- Naikkan ZIndex semua descendant agar tampil di atas isi DEX
        pcall(function()
            for _, d in ipairs(panel:GetDescendants()) do
                if d:IsA("GuiObject") then
                    pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                end
            end
            panel.DescendantAdded:Connect(function(d)
                if d:IsA("GuiObject") then
                    task.defer(function()
                        pcall(function() d.ZIndex = (d.ZIndex or 1) + 50 end)
                    end)
                end
            end)
        end)

        -- Sinkronkan visibility panel <-> ExplorerPanel
        pcall(function()
            explorerPanel:GetPropertyChangedSignal("Visible"):Connect(function()
                pcall(function() panel.Visible = explorerPanel.Visible end)
            end)
        end)

        -- Auto re-parent jika panel dipindah oleh logika internal
        pcall(function()
            panel.AncestryChanged:Connect(function(_, parent)
                local target = scrollWrap or explorerPanel
                if Settings and Settings.SaveInstanceScripts
                   and parent ~= target and explorerPanel.Parent then
                    pcall(function()
                        panel.Parent      = target
                        panel.AnchorPoint = Vector2.new(0, 0)
                        panel.Position    = UDim2.new(0, 0, 0, 0)
                        panel.Size        = UDim2.new(0, PW_NATIVE, 0, PH_NATIVE)
                        panel.Visible     = true
                    end)
                end
            end)
        end)

    end)
end

createSetting("cloud mode","SaveInstanceScripts",false)
-- v50: pindahkan SaveInstance ke urutan paling atas (sebelum "open tools terrain")
-- supaya tidak keluar dari panel & tata letak rapih.
do
        local _ch = SettingList:GetChildren()
        local _s  = _ch[#_ch]
        if _s then
                _s.LayoutOrder = -1
        end
        _registerPanelToggle(_s, "SaveInstanceScripts", _destroyCloudPanel)
        if _s and _s:FindFirstChild("Change") then
                _s.Change.MouseButton1Click:connect(function()
                        task.defer(function()
                                if Settings.SaveInstanceScripts then
                                        _turnOffOtherPanels("SaveInstanceScripts")
                                        _launchCloudPanel()
                                else
                                        if not _isAnyOtherPanelActive("SaveInstanceScripts") then
                                                _setSettingVisualOn(_s, "SaveInstanceScripts")
                                        else
                                                _destroyCloudPanel()
                                        end
                                end
                        end)
                end)
        end
end
-- ── END CLOUD MODE DEX INTEGRATION ───────────────────────────────────────

-- ══════════════════════════════════════════════════════════════════════
--  ENGINE RENDERING — TOOLBOX PC v2 PANEL
--  Pola identik TERRAIN / TOOLBOX PC / PLUGIN — embed ke ExplorerPanel DEX
--  Toggle ON  → build panel + embed ke ExplorerPanel DEX (full size 1,0,1,0)
--  Toggle OFF → destroy panel + bersihkan wrapper
-- ══════════════════════════════════════════════════════════════════════
local _ENG_GUI_PREFIX  = "SLv50_EngineRenderGui"
local _engRenderPanel  = nil

-- ── Services ────────────────────────────────────────────────────────
local _engHttpService     = game:GetService("HttpService")
local _engMarketplace     = game:GetService("MarketplaceService")
local _engInsertService   = game:GetService("InsertService")
local _engSoundService    = game:GetService("SoundService")

-- ── Tema ────────────────────────────────────────────────────────────
local _ENG_THEME = {
    BG        = Color3.fromRGB(24,24,28),
    BG_DARK   = Color3.fromRGB(16,16,20),
    BG_LIGHT  = Color3.fromRGB(38,38,46),
    BG_ACCENT = Color3.fromRGB(99,102,241),
    BG_ACCENT2= Color3.fromRGB(139,92,246),
    TEXT      = Color3.fromRGB(240,240,245),
    TEXT_DIM  = Color3.fromRGB(150,150,165),
    BORDER    = Color3.fromRGB(55,55,68),
    SUCCESS   = Color3.fromRGB(52,211,153),
    DANGER    = Color3.fromRGB(248,113,113),
}
local _ENG_CATMAP = {Model=10, Decal=13, Audio=9}

-- ── UI helpers ──────────────────────────────────────────────────────
local function _eCorner(p,r) local c=Instance.new("UICorner"); c.CornerRadius=UDim.new(0,r or 6); c.Parent=p; return c end
local function _eStroke(p,c,t) local s=Instance.new("UIStroke"); s.Color=c or _ENG_THEME.BORDER; s.Thickness=t or 1; s.Parent=p; return s end
local function _ePad(p,a) local u=Instance.new("UIPadding"); u.PaddingLeft=UDim.new(0,a); u.PaddingRight=UDim.new(0,a); u.PaddingTop=UDim.new(0,a); u.PaddingBottom=UDim.new(0,a); u.Parent=p; return u end

-- ── HTTP helper ─────────────────────────────────────────────────────
local function _engHttpGet(url)
    local fn
    pcall(function() if syn and syn.request then fn=syn.request end end)
    pcall(function() if not fn and http_request then fn=http_request end end)
    pcall(function() if not fn and request then fn=request end end)
    if fn then
        local ok,res = pcall(fn,{Url=url,Method="GET",Headers={}})
        if ok and res and res.Body then return res.Body end
    end
    local ok,body = pcall(function() return game:HttpGet(url) end)
    if ok then return body end
    return nil
end
local function _engJsonDec(s) local ok,t=pcall(function() return _engHttpService:JSONDecode(s) end); if ok then return t end; return nil end
local function _engNormItem(raw)
    if not raw then return nil end
    local id,name,creator
    if raw.Asset then id=raw.Asset.Id or raw.Asset.id; name=raw.Asset.Name or raw.Asset.name
    elseif raw.asset then id=raw.asset.id; name=raw.asset.name
    else id=raw.id or raw.Id or raw.assetId; name=raw.name or raw.Name end
    if raw.Creator then creator=raw.Creator.Name elseif raw.creator then creator=raw.creator.name end
    if not id then return nil end
    return {id=tonumber(id) or id, name=name or ("Asset "..tostring(id)), creator=creator or "?"}
end

local function _engSearchPage(category, keyword, page, cursor)
    local catId=_ENG_CATMAP[category] or 10; keyword=keyword or ""; page=page or 1
    local results={}; local nextCursor=nil; local hasMore=false
    local cp=(cursor and cursor~="") and ("&cursor=".._engHttpService:UrlEncode(cursor)) or ""
    local url1=string.format("https://apis.roblox.com/toolbox-service/v1/marketplace/%d?category=%d&keyword=%s&limit=30&sortType=0%s",catId,catId,_engHttpService:UrlEncode(keyword),cp)
    local b=_engHttpGet(url1)
    if b then
        local d=_engJsonDec(b)
        if d then
            for _,raw in ipairs(d.data or d.items or {}) do local n=_engNormItem(raw); if n then table.insert(results,n) end end
            local nc=d.nextPageCursor or d.nextCursor; if nc and nc~="" then nextCursor=nc; hasMore=true end
        end
    end
    if #results==0 then
        local cn=(category=="Model" and "Models") or (category=="Decal" and "Decals") or "Audio"
        local url2=string.format("https://catalog.roblox.com/v1/search/items/details?Category=%s&Keyword=%s&Limit=30&PageNumber=%d",cn,_engHttpService:UrlEncode(keyword),page)
        local b2=_engHttpGet(url2)
        if b2 then local d=_engJsonDec(b2); if d then for _,raw in ipairs(d.data or {}) do table.insert(results,{id=raw.id or raw.Id,name=raw.name or raw.Name or "?",creator=raw.creatorName or "?"}) end; if #results==30 then hasMore=true; nextCursor=tostring(page+1) end end end
    end
    return results, nextCursor, hasMore
end

local function _engGetName(id)
    local ok,info=pcall(function() return _engMarketplace:GetProductInfo(tonumber(id)) end)
    if ok and info and info.Name then return info.Name end; return nil
end

-- ── TEXTURE ENGINE: parallel warm-up via hidden ImageLabel ──────────
local _engTexCache=nil
local function _engCacheFrame()
    if _engTexCache and _engTexCache.Parent then return _engTexCache end
    local sg=Instance.new("ScreenGui"); sg.Name="EngTexWarmCache"; sg.IgnoreGuiInset=true; sg.ResetOnSpawn=false; sg.Enabled=true
    pcall(function() sg.Parent=game:GetService("CoreGui") end)
    if not sg.Parent then sg.Parent=game:GetService("Players").LocalPlayer:WaitForChild("PlayerGui") end
    local f=Instance.new("Frame"); f.Size=UDim2.new(0,1,0,1); f.Position=UDim2.new(-9,0,-9,0); f.BackgroundTransparency=1; f.Parent=sg
    _engTexCache=f; return f
end

local function _engDeepFix(model)
    local urlSet={}; local entries={}
    local function reg(inst,prop,val) if val and val~="" then urlSet[val]=true; table.insert(entries,{inst=inst,prop=prop,url=val}) end end
    for _,d in ipairs(model:GetDescendants()) do
        pcall(function()
            if d:IsA("MeshPart") then reg(d,"TextureID",d.TextureID); pcall(function() d.RenderFidelity=Enum.RenderFidelity.Precise end) end
            if d:IsA("SpecialMesh") then reg(d,"TextureId",d.TextureId) end
            if d:IsA("Texture") or d:IsA("Decal") then reg(d,"Texture",d.Texture) end
            if d:IsA("SurfaceAppearance") then reg(d,"ColorMap",d.ColorMap); reg(d,"NormalMap",d.NormalMap); reg(d,"RoughnessMap",d.RoughnessMap); reg(d,"MetalnessMap",d.MetalnessMap) end
            if d:IsA("UnionOperation") then pcall(function() d.RenderFidelity=Enum.RenderFidelity.Precise end); pcall(function() d.CollisionFidelity=Enum.CollisionFidelity.PreciseConvexDecomposition end) end
            if d:IsA("BasePart") then d.Anchored=true end
        end)
    end
    if #entries==0 then return end
    local frame=_engCacheFrame(); local total=0; local done=0; local imgNodes={}
    for url,_ in pairs(urlSet) do
        total=total+1
        local img=Instance.new("ImageLabel"); img.Size=UDim2.new(0,1,0,1); img.BackgroundTransparency=1; img.ImageTransparency=1; img.Image=url; img.Parent=frame
        imgNodes[url]=img
        task.spawn(function()
            local t0=tick(); while tick()-t0<6 do local ok,ld=pcall(function() return img.IsLoaded end); if ok and ld then break end; task.wait(0.03) end; done=done+1
        end)
    end
    local t0=tick(); while done<total and tick()-t0<6 do task.wait(0.03) end
    for _,img in pairs(imgNodes) do pcall(function() img:Destroy() end) end
    for _,e in ipairs(entries) do pcall(function() e.inst[e.prop]=""; task.wait(); e.inst[e.prop]=e.url end) end
end

local function _engInsertAsset(assetId, category, niceName)
    niceName=niceName or ("Asset "..tostring(assetId))
    if category=="Audio" then
        local s=Instance.new("Sound"); s.Name=niceName; s.SoundId="rbxassetid://"..tostring(assetId); s.Volume=1; s.Parent=_engSoundService
        local loaded=false; local conn; conn=s.Loaded:Connect(function() loaded=true; if conn then conn:Disconnect() end end)
        local t0=tick(); while not loaded and tick()-t0<5 do task.wait(0.1) end
        pcall(function() s.TimePosition=0; s:Play() end); task.delay(60,function() if s and s.Parent then s:Destroy() end end); return true
    end
    if category=="Decal" then
        local p=Instance.new("Part"); p.Name=niceName; p.Size=Vector3.new(4,4,1); p.Anchored=true
        local cam=Workspace.CurrentCamera; p.CFrame=cam.CFrame*CFrame.new(0,0,-10); p.Parent=Workspace
        for _,face in ipairs({"Front","Back","Top","Bottom","Left","Right"}) do
            local d=Instance.new("Decal"); d.Texture="rbxassetid://"..tostring(assetId); d.Face=Enum.NormalId[face]; d.Parent=p
        end; return true
    end
    local model; local ok,err=pcall(function() model=_engInsertService:LoadAsset(assetId) end)
    if not (ok and model) then
        local ok2,res=pcall(function() return game:GetObjects("rbxassetid://"..tostring(assetId)) end)
        if ok2 and res and #res>0 then
            model=Instance.new("Model"); model.Name=niceName; for _,c in ipairs(res) do c.Parent=model end
        else return false end
    end
    _engDeepFix(model); model.Name=niceName; model.Parent=Workspace; return true
end

-- ── Build panel sebagai Frame (di-embed ke ExplorerPanel) ────────────
local function _buildEngineRenderingPanel()
    local main=Instance.new("Frame")
    main.Name="EngineRenderPanel"; main.Size=UDim2.new(1,0,1,0); main.Position=UDim2.new(0,0,0,0)
    main.BackgroundColor3=_ENG_THEME.BG; main.BorderSizePixel=0; main.ClipsDescendants=true

    -- Header
    local header=Instance.new("Frame"); header.Size=UDim2.new(1,0,0,30); header.BackgroundColor3=_ENG_THEME.BG_DARK; header.BorderSizePixel=0; header.Parent=main
    local hLbl=Instance.new("TextLabel"); hLbl.BackgroundTransparency=1; hLbl.Size=UDim2.new(1,-20,1,0); hLbl.Position=UDim2.new(0,10,0,0)
    hLbl.Font=Enum.Font.GothamBold; hLbl.TextSize=11; hLbl.TextColor3=_ENG_THEME.TEXT; hLbl.TextXAlignment=Enum.TextXAlignment.Left
    hLbl.Text="TOOLBOX PC  ★  ENGINE"; hLbl.Parent=header
    local dot=Instance.new("Frame"); dot.Size=UDim2.new(0,7,0,7); dot.Position=UDim2.new(1,-12,0.5,-3)
    dot.BackgroundColor3=_ENG_THEME.BG_ACCENT; dot.BorderSizePixel=0; dot.Parent=header; _eCorner(dot,4)

    -- Tab bar
    local tabs=Instance.new("Frame"); tabs.Size=UDim2.new(1,-14,0,24); tabs.Position=UDim2.new(0,7,0,34)
    tabs.BackgroundTransparency=1; tabs.Parent=main
    local tlay=Instance.new("UIListLayout"); tlay.FillDirection=Enum.FillDirection.Horizontal; tlay.Padding=UDim.new(0,4); tlay.Parent=tabs
    local currentCat="Model"; local catButtons={}
    local function setCategory(c)
        currentCat=c
        for k,b in pairs(catButtons) do b.BackgroundColor3=(k==c) and _ENG_THEME.BG_ACCENT or _ENG_THEME.BG_LIGHT; b.TextColor3=(k==c) and _ENG_THEME.TEXT or _ENG_THEME.TEXT_DIM end
    end
    for _,c in ipairs({"Model","Decal","Audio"}) do
        local b=Instance.new("TextButton"); b.Size=UDim2.new(0,72,1,0); b.Text=c; b.Font=Enum.Font.GothamBold; b.TextSize=10
        b.TextColor3=_ENG_THEME.TEXT_DIM; b.BackgroundColor3=_ENG_THEME.BG_LIGHT; b.BorderSizePixel=0; b.AutoButtonColor=false; b.Parent=tabs
        _eCorner(b,4); catButtons[c]=b; b.MouseButton1Click:Connect(function() setCategory(c) end)
    end
    setCategory("Model")

    -- Search bar
    local searchBg=Instance.new("Frame"); searchBg.Size=UDim2.new(1,-14,0,26); searchBg.Position=UDim2.new(0,7,0,62)
    searchBg.BackgroundColor3=_ENG_THEME.BG_DARK; searchBg.BorderSizePixel=0; searchBg.Parent=main
    _eCorner(searchBg,5); _eStroke(searchBg,_ENG_THEME.BORDER,1)
    local search=Instance.new("TextBox"); search.Size=UDim2.new(1,-60,1,0); search.Position=UDim2.new(0,0,0,0)
    search.PlaceholderText="Cari model / decal / audio / Asset ID..."; search.Text=""; search.ClearTextOnFocus=false
    search.Font=Enum.Font.Gotham; search.TextSize=10; search.TextColor3=_ENG_THEME.TEXT; search.PlaceholderColor3=_ENG_THEME.TEXT_DIM
    search.BackgroundTransparency=1; search.BorderSizePixel=0; search.TextXAlignment=Enum.TextXAlignment.Left; search.Parent=searchBg; _ePad(search,7)
    local goBtn=Instance.new("TextButton"); goBtn.Size=UDim2.new(0,52,0,20); goBtn.Position=UDim2.new(1,-55,0.5,-10)
    goBtn.Text="CARI"; goBtn.Font=Enum.Font.GothamBold; goBtn.TextSize=9; goBtn.TextColor3=Color3.new(1,1,1)
    goBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT; goBtn.BorderSizePixel=0; goBtn.AutoButtonColor=false; goBtn.Parent=searchBg; _eCorner(goBtn,4)
    goBtn.MouseEnter:Connect(function() goBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT2 end)
    goBtn.MouseLeave:Connect(function() goBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT end)

    -- Results grid
    local resultsFrame=Instance.new("ScrollingFrame"); resultsFrame.Size=UDim2.new(1,-14,1,-130); resultsFrame.Position=UDim2.new(0,7,0,94)
    resultsFrame.BackgroundTransparency=1; resultsFrame.BorderSizePixel=0; resultsFrame.ScrollBarThickness=4
    resultsFrame.ScrollBarImageColor3=_ENG_THEME.BG_LIGHT; resultsFrame.CanvasSize=UDim2.new(0,0,0,0)
    resultsFrame.AutomaticCanvasSize=Enum.AutomaticSize.Y; resultsFrame.Parent=main
    local grid=Instance.new("UIGridLayout"); grid.CellSize=UDim2.new(1/3,0,0,104); grid.CellPadding=UDim2.new(0,0,0,4); grid.Parent=resultsFrame
    local rpad=Instance.new("UIPadding"); rpad.PaddingLeft=UDim.new(0,0); rpad.PaddingTop=UDim.new(0,4); rpad.PaddingRight=UDim.new(0,0); rpad.PaddingBottom=UDim.new(0,4); rpad.Parent=resultsFrame

    -- Status bar
    local statusBar=Instance.new("Frame"); statusBar.Size=UDim2.new(1,-14,0,20); statusBar.Position=UDim2.new(0,7,1,-26)
    statusBar.BackgroundColor3=_ENG_THEME.BG_DARK; statusBar.BorderSizePixel=0; statusBar.Parent=main; _eCorner(statusBar,4)
    local statusLbl=Instance.new("TextLabel"); statusLbl.BackgroundTransparency=1; statusLbl.Size=UDim2.new(1,-8,1,0); statusLbl.Position=UDim2.new(0,6,0,0)
    statusLbl.Font=Enum.Font.Gotham; statusLbl.TextSize=9; statusLbl.TextColor3=_ENG_THEME.TEXT_DIM; statusLbl.TextXAlignment=Enum.TextXAlignment.Left; statusLbl.Text="Siap"; statusLbl.Parent=statusBar
    local function setStatus(msg,color) statusLbl.Text=msg; statusLbl.TextColor3=color or _ENG_THEME.TEXT_DIM end

    -- Load More button
    local loadMoreBtn=Instance.new("TextButton"); loadMoreBtn.Size=UDim2.new(1,-14,0,24); loadMoreBtn.Position=UDim2.new(0,7,1,-52)
    loadMoreBtn.Text="⬇  MUAT LEBIH BANYAK"; loadMoreBtn.Font=Enum.Font.GothamBold; loadMoreBtn.TextSize=9
    loadMoreBtn.TextColor3=_ENG_THEME.TEXT; loadMoreBtn.BackgroundColor3=_ENG_THEME.BG_LIGHT; loadMoreBtn.BorderSizePixel=0
    loadMoreBtn.AutoButtonColor=false; loadMoreBtn.Visible=false; loadMoreBtn.Parent=main; _eCorner(loadMoreBtn,4); _eStroke(loadMoreBtn,_ENG_THEME.BORDER,1)

    -- Pagination state
    local currentKeyword=""; local currentPage=1; local currentCursor=nil; local totalLoaded=0; local isLoading=false

    local function clearResults()
        for _,c in ipairs(resultsFrame:GetChildren()) do if c:IsA("Frame") then c:Destroy() end end
        totalLoaded=0; currentPage=1; currentCursor=nil; loadMoreBtn.Visible=false
    end

    local function makeCard(item)
        local card=Instance.new("Frame"); card.BackgroundColor3=_ENG_THEME.BG_LIGHT; card.BorderSizePixel=0; card.Parent=resultsFrame; _eCorner(card,6); _eStroke(card,_ENG_THEME.BORDER,1)
        local thumb=Instance.new("ImageLabel"); thumb.Size=UDim2.new(1,-6,0,56); thumb.Position=UDim2.new(0,3,0,3)
        thumb.BackgroundColor3=_ENG_THEME.BG_DARK; thumb.BorderSizePixel=0; thumb.Image="rbxthumb://type=Asset&id="..tostring(item.id).."&w=150&h=150"; thumb.Parent=card; _eCorner(thumb,4)
        local nameLbl=Instance.new("TextLabel"); nameLbl.Size=UDim2.new(1,-6,0,12); nameLbl.Position=UDim2.new(0,3,0,61)
        nameLbl.BackgroundTransparency=1; nameLbl.Text=tostring(item.name); nameLbl.Font=Enum.Font.GothamBold; nameLbl.TextSize=8
        nameLbl.TextColor3=_ENG_THEME.TEXT; nameLbl.TextXAlignment=Enum.TextXAlignment.Left; nameLbl.TextTruncate=Enum.TextTruncate.AtEnd; nameLbl.Parent=card
        local idLbl=Instance.new("TextLabel"); idLbl.Size=UDim2.new(1,-6,0,10); idLbl.Position=UDim2.new(0,3,0,74)
        idLbl.BackgroundTransparency=1; idLbl.Text="ID:"..tostring(item.id); idLbl.Font=Enum.Font.Gotham; idLbl.TextSize=7
        idLbl.TextColor3=_ENG_THEME.TEXT_DIM; idLbl.TextXAlignment=Enum.TextXAlignment.Left; idLbl.Parent=card
        local insertBtn=Instance.new("TextButton"); insertBtn.Size=UDim2.new(1,-6,0,14); insertBtn.Position=UDim2.new(0,3,1,-18)
        insertBtn.Text="INSERT"; insertBtn.Font=Enum.Font.GothamBold; insertBtn.TextSize=8; insertBtn.TextColor3=Color3.new(1,1,1)
        insertBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT; insertBtn.BorderSizePixel=0; insertBtn.AutoButtonColor=false; insertBtn.Parent=card; _eCorner(insertBtn,4)
        insertBtn.MouseEnter:Connect(function() insertBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT2 end)
        insertBtn.MouseLeave:Connect(function() if insertBtn.Text=="INSERT" then insertBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT end end)
        insertBtn.MouseButton1Click:Connect(function()
            insertBtn.Text="..."; insertBtn.BackgroundColor3=_ENG_THEME.TEXT_DIM
            setStatus("Memuat: "..tostring(item.name),_ENG_THEME.TEXT_DIM)
            task.spawn(function()
                local nm=item.name
                if not nm or tostring(nm):match("^Asset %d") then local rn=_engGetName(item.id); if rn then nm=rn; item.name=rn; nameLbl.Text=rn end end
                local ok=_engInsertAsset(item.id,currentCat,nm)
                insertBtn.Text=ok and "✓" or "✕"; insertBtn.BackgroundColor3=ok and _ENG_THEME.SUCCESS or _ENG_THEME.DANGER
                setStatus(ok and ("OK: "..nm) or ("Gagal: "..nm), ok and _ENG_THEME.SUCCESS or _ENG_THEME.DANGER)
                task.wait(1.5); insertBtn.Text="INSERT"; insertBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT
            end)
        end)
        return {item=item,nameLbl=nameLbl,card=card}
    end

    local function enrichNames(cards)
        task.spawn(function()
            for _,c in ipairs(cards) do local nm=_engGetName(c.item.id); if nm then c.item.name=nm; c.nameLbl.Text=nm end; task.wait(0.04) end
        end)
    end

    local function loadPage(keyword,page,cursor,append)
        if isLoading then return end; isLoading=true
        loadMoreBtn.Text="  Memuat..."; loadMoreBtn.BackgroundColor3=_ENG_THEME.BG_DARK; setStatus("Mencari...",_ENG_THEME.TEXT_DIM)
        task.spawn(function()
            local list,nextCursor,hasMore=_engSearchPage(currentCat,keyword,page,cursor)
            if not append then for _,c in ipairs(resultsFrame:GetChildren()) do if c:IsA("Frame") then c:Destroy() end end; totalLoaded=0 end
            if #list==0 and totalLoaded==0 then setStatus("Tidak ada hasil.",_ENG_THEME.DANGER); loadMoreBtn.Visible=false; isLoading=false; return end
            local cards={}; for _,it in ipairs(list) do table.insert(cards,makeCard(it)) end
            totalLoaded=totalLoaded+#list; currentCursor=nextCursor; currentPage=page+1
            enrichNames(cards)
            if hasMore then loadMoreBtn.Text="⬇  MUAT LEBIH  ("..totalLoaded.." dimuat)"; loadMoreBtn.BackgroundColor3=_ENG_THEME.BG_LIGHT; loadMoreBtn.Visible=true
            else loadMoreBtn.Visible=false end
            setStatus(totalLoaded.." hasil ditemukan",_ENG_THEME.SUCCESS); isLoading=false
        end)
    end

    local function doSearch()
        local kw=search.Text or ""; currentKeyword=kw; currentPage=1; currentCursor=nil; totalLoaded=0; isLoading=false
        local idOnly=tonumber(kw)
        if idOnly then clearResults(); local nm=_engGetName(idOnly) or ("Asset "..idOnly); makeCard({id=idOnly,name=nm,creator="?"}); setStatus("Asset ID: "..idOnly,_ENG_THEME.SUCCESS); return end
        loadPage(kw,1,nil,false)
    end

    loadMoreBtn.MouseButton1Click:Connect(function() if not isLoading then loadPage(currentKeyword,currentPage,currentCursor,true) end end)
    loadMoreBtn.MouseEnter:Connect(function() if loadMoreBtn.Text~="  Memuat..." then loadMoreBtn.BackgroundColor3=_ENG_THEME.BG_ACCENT end end)
    loadMoreBtn.MouseLeave:Connect(function() if loadMoreBtn.Text~="  Memuat..." then loadMoreBtn.BackgroundColor3=_ENG_THEME.BG_LIGHT end end)
    goBtn.MouseButton1Click:Connect(doSearch)
    search.FocusLost:Connect(function(enter) if enter then doSearch() end end)
    for _,b in pairs(catButtons) do b.MouseButton1Click:Connect(function() search.Text=""; isLoading=false; doSearch() end) end
    task.spawn(function() setStatus("Memuat rekomendasi...",_ENG_THEME.TEXT_DIM); loadPage("house",1,nil,false) end)

    _engRenderPanel=main
    return main
end

-- ── Destroy ─────────────────────────────────────────────────────────
local function _destroyEngineRenderingPanel()
    pcall(function()
        local cg=game:GetService("CoreGui")
        for _,v in ipairs(cg:GetChildren()) do if v.Name:sub(1,#_ENG_GUI_PREFIX)==_ENG_GUI_PREFIX then v:Destroy() end end
    end)
    pcall(function()
        local lp=game:GetService("Players").LocalPlayer; local pg=lp and lp:FindFirstChildOfClass("PlayerGui")
        if pg then for _,v in ipairs(pg:GetChildren()) do if v.Name:sub(1,#_ENG_GUI_PREFIX)==_ENG_GUI_PREFIX then v:Destroy() end end end
    end)
    pcall(function()
        local dexGui=_findDexGui()
        if dexGui then
            local ep=dexGui:FindFirstChild("ExplorerPanel",true)
            if ep then
                local sw=ep:FindFirstChild("_EngRenderScrollWrap"); if sw then sw:Destroy() end
                local p=ep:FindFirstChild("EngineRenderPanel"); if p then p:Destroy() end
            end
        end
    end)
    _engRenderPanel=nil
end

-- ── Launch ──────────────────────────────────────────────────────────
local function _launchEngineRenderingPanel()
    _destroyEngineRenderingPanel()
    local panel=_buildEngineRenderingPanel()
    task.spawn(function()
        local dexGui=_findDexGui()
        local explorerPanel=dexGui and dexGui:WaitForChild("ExplorerPanel",10) or nil
        if not explorerPanel then
            local sg=Instance.new("ScreenGui"); sg.Name=_ENG_GUI_PREFIX.."_sg"; sg.IgnoreGuiInset=true; sg.ResetOnSpawn=false
            pcall(function() sg.Parent=game:GetService("CoreGui") end)
            if not sg.Parent then sg.Parent=game:GetService("Players").LocalPlayer:WaitForChild("PlayerGui") end
            panel.Size=UDim2.new(0,280,0,500); panel.Position=UDim2.new(0,8,0,55); panel.Parent=sg; return
        end
        local scrollWrap
        pcall(function()
            scrollWrap=explorerPanel:FindFirstChild("_EngRenderScrollWrap")
            if not scrollWrap then
                scrollWrap=Instance.new("ScrollingFrame"); scrollWrap.Name="_EngRenderScrollWrap"
                scrollWrap.Size=UDim2.new(1,0,1,0); scrollWrap.Position=UDim2.new(0,0,0,0); scrollWrap.BackgroundTransparency=1
                scrollWrap.BorderSizePixel=0; scrollWrap.ScrollingDirection=Enum.ScrollingDirection.Y; scrollWrap.ScrollBarThickness=0
                scrollWrap.CanvasSize=UDim2.new(0,0,0,0); scrollWrap.ClipsDescendants=true; scrollWrap.ZIndex=5; scrollWrap.Parent=explorerPanel
            end
        end)
        pcall(function()
            panel.Name="EngineRenderPanel"; panel.AnchorPoint=Vector2.new(0,0); panel.Position=UDim2.new(0,0,0,0)
            panel.Size=UDim2.new(1,0,1,0); panel.ClipsDescendants=true; panel.Visible=true; panel.Parent=scrollWrap or explorerPanel
        end)
        pcall(function()
            for _,child in ipairs(panel:GetChildren()) do if child:IsA("UICorner") or child:IsA("UIStroke") then pcall(function() child:Destroy() end) end end
        end)
        pcall(function()
            explorerPanel.BackgroundColor3=panel.BackgroundColor3; explorerPanel.BackgroundTransparency=0
            explorerPanel.BorderSizePixel=0; explorerPanel.ClipsDescendants=true
        end)
        pcall(function()
            for _,d in ipairs(panel:GetDescendants()) do if d:IsA("GuiObject") then pcall(function() d.ZIndex=(d.ZIndex or 1)+50 end) end end
            panel.DescendantAdded:Connect(function(d) if d:IsA("GuiObject") then task.defer(function() pcall(function() d.ZIndex=(d.ZIndex or 1)+50 end) end) end end)
        end)
        pcall(function()
            explorerPanel:GetPropertyChangedSignal("Visible"):Connect(function() pcall(function() panel.Visible=explorerPanel.Visible end) end)
        end)
        pcall(function()
            panel.AncestryChanged:Connect(function(_,parent)
                local target=scrollWrap or explorerPanel
                if parent~=target and explorerPanel.Parent then
                    pcall(function() panel.Parent=target; panel.AnchorPoint=Vector2.new(0,0); panel.Position=UDim2.new(0,0,0,0); panel.Size=UDim2.new(1,0,1,0); panel.Visible=true end)
                end
            end)
        end)
    end)
end

createSetting("engine rendering","EngineRendering",false)
do
    local _ch = SettingList:GetChildren()
    local _s  = _ch[#_ch]
    _registerPanelToggle(_s, "EngineRendering", _destroyEngineRenderingPanel)
    if _s and _s:FindFirstChild("Change") then
        _s.Change.MouseButton1Click:connect(function()
            task.defer(function()
                if Settings.EngineRendering then
                    _turnOffOtherPanels("EngineRendering")
                    _launchEngineRenderingPanel()
                else
                    if not _isAnyOtherPanelActive("EngineRendering") then
                        _setSettingVisualOn(_s, "EngineRendering")
                    else
                        _destroyEngineRenderingPanel()
                    end
                end
            end)
        end)
    end
end
-- ── END ENGINE RENDERING PANEL ────────────────────────────────────────────

local function getSelection()
        if not TotallyNotGetSelection then return nil end
        local ok, t = pcall(function() return TotallyNotGetSelection:Invoke() end)
        if ok and t and #t > 0 then
                return t[1]
        else
                return nil
        end
end

Mouse.Button1Down:connect(function()
        if CurrentWindow == "Explorer" and Settings.ClickSelect then
                local target = Mouse.Target
                if target and TotallyNotSetSelection then
                        pcall(function() TotallyNotSetSelection:Invoke({target}) end)
                end
        end
end)

TotallyNotSelectionChanged.Event:connect(function()
        if Settings.SelBox then
                local success,err = pcall(function()
                        local selection = getSelection()
                        SelectionBox.Adornee = selection
                end)
                if err then
                        SelectionBox.Adornee = nil
                end
        end
end)

SettingsListener.OnInvoke = ReturnSetting

