    -- ════════════════════════════════════════════════
    --  ANIMATION LOOP — shimmer + glow pulse
    -- ════════════════════════════════════════════════
    local startClock = tick()
    local animConn
    local titleShown = false
    animConn = RunService.Heartbeat:Connect(function(dt)
        local t = tick() - startClock

        -- Title glow pulse halus
        pcall(function()
            local p = math.sin(t * 1.5) * 0.5 + 0.5
            titleGlow.BackgroundTransparency = 0.88 + p * 0.07
            titleGlow.Size = UDim2.new(0, 200 + p * 20, 0, 80 + p * 10)
        end)

        -- Diamond rotate halus (header)
        diamond.Rotation = 45 + math.sin(t * 1.2) * 8

        -- Ambient glow breathing
        ambGlow.BackgroundTransparency = 0.93 + math.sin(t * 0.8) * 0.04

        -- Shimmer sweep across title (loop ~3 detik)
        if titleShown then
            local sx = ((t * 110) % 360) - 50
            shimmer.Position = UDim2.new(0, sx, 0.45, 0)
        end

        -- Subtitle subtle gold cycle
        if subtitle.TextTransparency < 0.95 then
            local p = math.sin(t * 1.2) * 0.5 + 0.5
            local r = 150 + p * 60
            local g = 160 + p * 50
            local b = 180 - p * 30
            subtitle.TextColor3 = Color3.fromRGB(
                math.floor(r), math.floor(g), math.floor(b)
            )
        end
    end)

    -- ════════════════════════════════════════════════
    --  TIMELINE 9 DETIK — ELEGANT REVEAL
    -- ════════════════════════════════════════════════
    -- 0.0–0.6s: tunggu slide-in selesai
