    T(hLbl,    0.6, {TextTransparency = 0})
    T(hRight,  0.6, {TextTransparency = 0})
    T(diamond, 0.5, {BackgroundTransparency = 0})
    T(topLine, 0.7, {Size = UDim2.new(1, -40, 0, 1)}, Enum.EasingStyle.Quint)

    task.wait(0.45)
    -- 1.0s: title pop (scale dari 0.7 → 1)
    title.TextSize = 30
    title.TextTransparency = 0.5
    T(title, 0.7, {TextSize = 44, TextTransparency = 0},
      Enum.EasingStyle.Back, Enum.EasingDirection.Out)
    titleShown = true

    task.wait(0.55)
    -- 1.55s: divider expand simetris + diamond ◆ muncul
    T(divLineL, 0.7, {Size = UDim2.new(0, 90, 0, 1)}, Enum.EasingStyle.Quint)
    T(divLineR, 0.7, {Size = UDim2.new(0, 90, 0, 1)}, Enum.EasingStyle.Quint)
    task.wait(0.30)
    T(divDot, 0.4, {TextTransparency = 0})

    task.wait(0.30)
    -- 2.15s: subtitle fade in
    T(subtitle, 0.7, {TextTransparency = 0.15})

    task.wait(0.55)
    -- 2.7s: loading section fade in
    T(loadCap,   0.5, {TextTransparency = 0})
    T(pctLbl,    0.5, {TextTransparency = 0})
    T(barBg,     0.5, {BackgroundTransparency = 0.3})
    T(statusLbl, 0.5, {TextTransparency = 0.2})

    task.wait(0.50)
    -- 3.2s: bar fill bertahap dengan status berubah
    local stages = {
        {pct = 0.20, status = "Loading core modules...",     dur = 0.55},
        {pct = 0.45, status = "Loading icons & assets...",   dur = 0.65},
        {pct = 0.70, status = "Initializing toolbox...",     dur = 0.75},
        {pct = 0.92, status = "Configuring interface...",    dur = 0.65},
