            bar.Size  = UDim2.new(p, 0, 1, 0)
            pctLbl.Text = ("%d%%"):format(math.floor(p * 100 + 0.5))
            task.wait(st.dur / steps)
        end
    end

    -- ~6.25s: status ready
    statusLbl.Text     = "Welcome to MZYY V8"
    T(statusLbl, 0.4, {TextColor3 = C_GOLD_LT, TextTransparency = 0})
