    pcall(function() SideMenu.Visible = true end)

    task.wait(1.85)

    -- ~8.1s: Fade out elegan semua elemen
    T(IntroFrame, 0.7, {BackgroundTransparency = 1, Position = UDim2.new(0, -300, 0, 20)},
      Enum.EasingStyle.Quart, Enum.EasingDirection.In)
    T(bg,         0.6, {BackgroundTransparency = 1})
    T(ambGlow,    0.6, {BackgroundTransparency = 1})
    T(titleGlow,  0.6, {BackgroundTransparency = 1})
    T(title,      0.6, {TextTransparency = 1})
    T(subtitle,   0.6, {TextTransparency = 1})
    T(hLbl,       0.5, {TextTransparency = 1})
    T(hRight,     0.5, {TextTransparency = 1})
    T(diamond,    0.5, {BackgroundTransparency = 1})
