-- ══════════════════════════════════════════════════════════════════════
--  DEX THEME SYNC v2 — SYGKMUNII
--  Menyinkronkan warna panel DEX (Explorer/Properties/SideMenu/ScrollingFrame)
--  agar sesuai dengan palette SL Sidebar Premium v5.0
--  FIX: threshold benar (0.62), ScrollingFrame opak bg0, border dihapus
-- ══════════════════════════════════════════════════════════════════════

task.spawn(function()
    -- Tunggu DEX ScreenGui muncul di CoreGui atau PlayerGui
    local dexGui = nil
    local searched = 0
    repeat
        task.wait(0.3)
        searched = searched + 1
        for _, v in ipairs(game:GetService("CoreGui"):GetChildren()) do
            if v.Name == "Dex" then dexGui = v; break end
        end
        if not dexGui then
            local lp = game:GetService("Players").LocalPlayer
            if lp then
                local pg = lp:FindFirstChild("PlayerGui")
                if pg then
                    for _, v in ipairs(pg:GetChildren()) do
                        if v.Name == "Dex" then dexGui = v; break end
                    end
                end
            end
        end
    until dexGui or searched > 20

    if not dexGui then return end

    -- ── Palette (mirror dari C di atas) ──────────────────────────────
    local D = {
        bg0   = Color3.fromRGB( 26,  26,  26),   -- body bg paling gelap
        bg1   = Color3.fromRGB( 36,  36,  36),   -- panel utama
        bg2   = Color3.fromRGB( 45,  45,  45),   -- panel sekunder
        bg3   = Color3.fromRGB( 54,  54,  54),   -- header/row
        bg4   = Color3.fromRGB( 64,  64,  64),   -- hover/button
        bg5   = Color3.fromRGB( 80,  80,  80),   -- border
        accA  = Color3.fromRGB(  0, 162, 255),
        accB  = Color3.fromRGB(  0, 117, 204),
        txtP  = Color3.fromRGB(232, 232, 232),
        txtS  = Color3.fromRGB(192, 192, 192),
        txtD  = Color3.fromRGB(138, 138, 138),
        selBg = Color3.fromRGB(  0,  75, 150),
    }

    local function lum(c) return c.R*0.299 + c.G*0.587 + c.B*0.114 end
    local function isBlue(c) return c.B > 0.25 and c.B > c.R+0.07 and c.B > c.G+0.07 end

    local function remapBg(obj)
        -- Paksa transparency = 0 (opak penuh) agar bg gelap benar-benar kelihatan
        obj.BackgroundTransparency = 0
        local c = obj.BackgroundColor3
        local b = lum(c)
        if isBlue(c) and b > 0.10 then
            obj.BackgroundColor3 = D.selBg
        elseif b > 0.82 then obj.BackgroundColor3 = D.bg1   -- putih/terang
        elseif b > 0.60 then obj.BackgroundColor3 = D.bg2
        elseif b > 0.38 then obj.BackgroundColor3 = D.bg3
        elseif b > 0.18 then obj.BackgroundColor3 = D.bg4
        else                  obj.BackgroundColor3 = D.bg0
        end
        obj.BorderSizePixel = 0
        pcall(function() obj.BorderColor3 = D.bg5 end)
    end

    local function themeDexObj(obj)
        pcall(function()

            -- SKIP: color swatch material agar tidak ditimpa abu-abu
            local oName = obj.Name or ""
            if oName:sub(1,10)=="MatSwatch_" or oName:sub(1,12)=="ColorSwatch_"
               or oName=="MatDot" or oName=="GrassDot" or oName=="GroundDot" then return end

            -- ── Frame ─────────────────────────────────────────────────
            if obj:IsA("Frame") then
                -- Skip frame yang memang transparan (overlay, dll)
                if obj.BackgroundTransparency > 0.62 then return end
                remapBg(obj)
                return
            end

            -- ── ScrollingFrame → bg gelap opak + scrollbar kontras ────
            if obj:IsA("ScrollingFrame") then
                -- Selalu paksa opak supaya tidak tembus-putih
                obj.BackgroundColor3    = D.bg0
                obj.BackgroundTransparency = 0
                obj.BorderSizePixel     = 0
                obj.ScrollBarThickness  = 4
                obj.ScrollBarImageColor3 = D.accA
                -- Image scrollbar default DEX pakai textures hitam → ganti ke warna solid
                pcall(function() obj.TopImage    = "rbxasset://textures/ui/Scroll/scroll-middle.png" end)
                pcall(function() obj.MidImage    = "rbxasset://textures/ui/Scroll/scroll-middle.png" end)
                pcall(function() obj.BottomImage = "rbxasset://textures/ui/Scroll/scroll-middle.png" end)
                return
            end

            -- ── TextLabel / TextButton / TextBox ──────────────────────
            if obj:IsA("TextLabel") or obj:IsA("TextButton") or obj:IsA("TextBox") then
                -- Teks gelap → terang
                if lum(obj.TextColor3) < 0.60 then
                    obj.TextColor3 = D.txtP
                end
                if obj:IsA("TextButton") then
                    if obj.BackgroundTransparency < 0.62 then
                        local bc = obj.BackgroundColor3
                        if lum(bc) > 0.18 and not isBlue(bc) then
                            obj.BackgroundColor3       = D.bg3
                            obj.BackgroundTransparency = 0.25
                        end
                    end
                    obj.BorderSizePixel = 0
                end
                if obj:IsA("TextBox") then
                    if obj.BackgroundTransparency < 0.62 then
                        obj.BackgroundColor3       = D.bg2
                        obj.BackgroundTransparency = 0
                    end
                    obj.BorderSizePixel = 0
                end
                return
            end

            -- ── ImageLabel / ImageButton ──────────────────────────────
            if obj:IsA("ImageLabel") or obj:IsA("ImageButton") then
                if obj.BackgroundTransparency < 0.85 then
                    local bc = obj.BackgroundColor3
                    if lum(bc) > 0.15 and not isBlue(bc) then
                        obj.BackgroundColor3 = D.bg3
                    end
                end
                obj.BorderSizePixel = 0
                -- Ikon abu gelap → txtS supaya terlihat di bg gelap
                pcall(function()
                    local ic = obj.ImageColor3
                    if lum(ic) < 0.45 and ic.R < 0.5 and ic.G < 0.5 and ic.B < 0.5 then
                        obj.ImageColor3 = D.txtS
                    end
                end)
                return
            end

        end)
    end

    -- ── Terapkan ke semua descendants sekarang ────────────────────────
    for _, obj in ipairs(dexGui:GetDescendants()) do
        themeDexObj(obj)
    end

    -- ── Watcher: theme objek baru (row Explorer, property dll) ────────
    dexGui.DescendantAdded:Connect(function(obj)
        task.defer(function() pcall(themeDexObj, obj) end)
    end)
end)


