        local _okWrite = pcall(function() mySG.Parent = _cg end)
        if _okWrite and mySG.Parent == _cg then
            _mySG_parent_target = _cg
        end
    end
end
if mySG.Parent == nil then
    mySG.Parent = PlayerGui
    _mySG_parent_target = PlayerGui
end

