-- ── Copy / Paste handler ──────────────────────────────────────────────
local function safeSetClipboard(s)
    local fns = { setclipboard, set_clipboard, toclipboard, writeclipboard }
    for _, fn in ipairs(fns) do
        if type(fn) == "function" then
            local ok = pcall(fn, s)
            if ok then return true end
        end
    end
    return false
end

local function safeGetClipboard()
    local fns = { getclipboard, get_clipboard, readclipboard, getrenv and (getrenv().getclipboard) }
    for _, fn in ipairs(fns) do
        if type(fn) == "function" then
            local ok, r = pcall(fn)
            if ok and type(r) == "string" then return r end
        end
    end
    return nil
end

copyBtn.MouseButton1Click:Connect(function()
    local txt = editBox.ContentText
    if not txt or txt == "" then txt = editBox.Text or "" end
    if safeSetClipboard(txt) then
        statusLbl.TextColor3 = C.green
        statusLbl.Text = "✓ Disalin"
    else
        statusLbl.TextColor3 = C.red
        statusLbl.Text = "✗ Clipboard tidak tersedia"
    end
    task.delay(2, function()
        if statusLbl and statusLbl.Parent then statusLbl.Text = "" end
    end)
end)

pasteBtn.MouseButton1Click:Connect(function()
    local clip = safeGetClipboard()
    if not clip then
        statusLbl.TextColor3 = C.red
        statusLbl.Text = "✗ Clipboard kosong"
        task.delay(2, function()
            if statusLbl and statusLbl.Parent then statusLbl.Text = "" end
        end)
        return
    end
    -- Selalu masuk ke dalam panel: replace seluruh isi editBox dengan clipboard
    -- Kalau editBox sedang fokus & ada cursor, sisipkan di posisi cursor.
    local cur = editBox.CursorPosition
    local curText = editBox.Text or ""
    if cur and cur > 0 and #curText > 0 then
        local cur0 = cur - 1
        local before = string.sub(curText, 1, cur0)
        local after  = string.sub(curText, cur0 + 1)
        editBox.Text = before .. clip .. after
        pcall(function() editBox.CursorPosition = cur + #clip end)
    else
        editBox.Text = clip
        pcall(function() editBox.CursorPosition = #clip + 1 end)
    end
    -- Pastikan teks pasted terlihat: scroll ke atas panel
    task.defer(function()
        pcall(function()
            body.CanvasPosition = Vector2.new(0, 0)
        end)
    end)
    statusLbl.TextColor3 = C.green
    statusLbl.Text = "✓ Ditempel ke panel"
    task.delay(2, function()
        if statusLbl and statusLbl.Parent then statusLbl.Text = "" end
    end)
end)

