-- ══════════════════════════════════════════════════════════════════════
--  GUTTER UPDATE
-- ══════════════════════════════════════════════════════════════════════
local lastLineCount = -1
local function updateGutter()
    local txt = editBox.Text or ""
    local n = 1
    if #txt > 0 then
        local _, c = txt:gsub("\n","\n"); n = c + 1
    end
    if n == lastLineCount then return end
    lastLineCount = n
    local digits = #tostring(n)
    local newW = math.max(44, digits * 9 + 14)
    if newW ~= GUTTER_W then
        GUTTER_W = newW
        gutter.Size = UDim2.new(0, GUTTER_W, 0, gutter.Size.Y.Offset)
        editBox.Position = UDim2.new(0, GUTTER_W+4, 0, 0)
        editBox.Size = UDim2.new(1, -(GUTTER_W+14), 1, -10)
    end
    local buf = table.create and table.create(n) or {}
    for i = 1, n do buf[i] = tostring(i) end
    gutter.Text = table.concat(buf, "\n")
end
editBox:GetPropertyChangedSignal("Text"):Connect(updateGutter)
updateGutter()

-- ══════════════════════════════════════════════════════════════════════
--  COLORIZE (1:1 ColorizeSourceModule Studio Lite — dark theme)
-- ══════════════════════════════════════════════════════════════════════
local KW_DARK = {
    ["local"]    = "<b><font color='#9090ff'>local</font></b>",
    ["elseif"]   = "<b><font color='#9090ff'>elseif</font></b>",
    ["for"]      = "<b><font color='#9090ff'>for</font></b>",
    ["if"]       = "<b><font color='#9090ff'>if</font></b>",
    ["then"]     = "<b><font color='#9090ff'>then</font></b>",
    ["else"]     = "<b><font color='#9090ff'>else</font></b>",
    ["end"]      = "<b><font color='#9090ff'>end</font></b>",
    ["while"]    = "<b><font color='#9090ff'>while</font></b>",
    ["function"] = "<b><font color='#9090ff'>function</font></b>",
    ["in"]       = "<b><font color='#9090ff'>in</font></b>",
    ["and"]      = "<b><font color='#9090ff'>and</font></b>",
    ["or"]       = "<b><font color='#9090ff'>or</font></b>",
    ["return"]   = "<b><font color='#9090ff'>return</font></b>",
    ["break"]    = "<b><font color='#9090ff'>break</font></b>",
}
local STR_COL  = "#ff2020"
local FUNC_COL = "#00ffff"
local COMM_COL = "#00ff00"

-- 1:1 sama dengan ColorizeSourceModule:ColorizeSource(src, p5=false, p6=true)
local function colorize(src)
    if type(src) ~= "string" or #src == 0 then return "" end
    local indent, nextInd, out = "", "", ""
    for _, line in ipairs(src:split("\n")) do
        local s = line:gsub("<","&lt;"):gsub("\t","    ")
        local ci = s:find("--", 1, true)
        local comm
        if ci then
            comm = '<font color="'..COMM_COL..'">'..s:sub(ci)..'</font>'
            s = s:sub(1, ci-1)
        end
        out = out .. indent
        s = s:match("^%s*(.*)") or s
        if     s:sub(1,4) == "else" then indent=indent:sub(5); nextInd="    "
        elseif s:sub(1,3) == "end"  then indent=indent:sub(5)
        elseif (s:sub(1,2)=="if" or s:sub(1,5)=="while"
             or s:sub(1,3)=="for" or s:find("function",1,true))
               and s:sub(-3)~="end" then nextInd="    "
        else nextInd=""
        end
        local colored = s:gsub("%w+", KW_DARK)
                         :gsub('%b""', '<font color="'..STR_COL..'">%1</font>')
                         :gsub("%w+%(", '<font color="'..FUNC_COL..'">%1</font>')
        if comm then colored = colored .. comm end
        out = out .. colored .. "\n"
        indent = indent .. nextInd
    end
    return out
end

local function refreshColorize()
    if editBox:IsFocused() then return end
    local ok, r = pcall(colorize, editBox.ContentText)
    if ok and r then editBox.Text = r end
end

-- ══════════════════════════════════════════════════════════════════════
--  STATE INTI
--  currentSLCodeBox = referensi ke SL_CodeTextBox ASLI milik scrObj
--  (child langsung dari Script/LocalScript/ModuleScript di game tree)
--  Ini adalah SATU-SATUNYA pointer save yang kita butuhkan.
--  Sama persis dengan: SaveChangesTo.Value = v513  (dari ShowScript SL)
-- ══════════════════════════════════════════════════════════════════════
local currentSLCodeBox = nil   -- SL_CodeTextBox ASLI (target save)
local currentScript    = nil   -- scrObj (untuk judul)

-- ══════════════════════════════════════════════════════════════════════
--  STATUS FLASH
-- ══════════════════════════════════════════════════════════════════════
local function flashStatus(msg, ok)
    statusLbl.TextColor3 = ok and C.green or C.red
    statusLbl.Text = msg
    task.delay(2.5, function()
        if statusLbl and statusLbl.Parent then statusLbl.Text = "" end
    end)
end

-- ══════════════════════════════════════════════════════════════════════
--  SNAP TO TOP
-- ══════════════════════════════════════════════════════════════════════
local function snapToTop()
    pcall(function()
        body.CanvasPosition    = Vector2.new(0,0)
        editBox.CursorPosition = 1
        editBox.SelectionStart = -1
    end)
end

-- ══════════════════════════════════════════════════════════════════════
--  SAVE LOGIC — 1:1 dengan Studio Lite SL_ColorizeAndEditLocal:
--
--  SL native (SL_ColorizeAndEditLocal FocusLost):
--    script.Parent:WaitForChild("SaveChangesTo").Value.Text
--      = script.Parent.ContentText
--
--  Artinya: tulis plaintext ke SL_CodeTextBox ASLI (.Text property).
--  Ketika SL ShowScript() dipanggil lagi, dia Clone SL_CodeTextBox
--  dan membaca .ContentText dari clone — yang identik dengan .Text asli.
--  Dengan menulis ke .Text SL_CodeTextBox asli, kita insert source
--  langsung ke dalam sistem SL tanpa bypass apapun.
-- ══════════════════════════════════════════════════════════════════════
local function doSave(reason)
    if not currentSLCodeBox then return end
    local src = editBox.ContentText
    -- Tulis ke SL_CodeTextBox asli — IDENTIK dengan pola SL native
    local ok, err = pcall(function()
        currentSLCodeBox.Text = src
    end)
    -- Jika gagal (SL_CodeTextBox read-only di executor ini), coba via
    -- sethiddenproperty atau setscriptable
    if not ok then
        pcall(function()
            if typeof(setscriptable) == "function" then
                setscriptable(currentSLCodeBox, "Text", true)
            end
            currentSLCodeBox.Text = src
            ok = true
        end)
    end
    if not ok then
        pcall(function()
            if typeof(sethiddenproperty) == "function" then
                sethiddenproperty(currentSLCodeBox, "Text", src)
                ok = true
            end
        end)
    end
    if ok then
        flashStatus("✓ Tersimpan" .. (reason and (" ("..reason..")") or ""), true)
    else
        flashStatus("✗ Gagal: " .. tostring(err or "?"), false)
    end
end

saveBtn.MouseButton1Click:Connect(function() doSave() end)

UIS.InputBegan:Connect(function(inp, proc)
    if proc then return end
    if inp.KeyCode == Enum.KeyCode.S
    and (UIS:IsKeyDown(Enum.KeyCode.LeftControl)
      or UIS:IsKeyDown(Enum.KeyCode.RightControl)) then
        if mySG.Enabled and currentSLCodeBox then doSave("Ctrl+S") end
    end
end)

-- ══════════════════════════════════════════════════════════════════════
--  EDITBOX EVENTS — 1:1 SL_ColorizeAndEditLocal
--
--  SL native:
--    Focused  → script.Parent.Text = script.Parent.ContentText  (plain)
--    FocusLost→ task.wait()
--               SaveChangesTo.Value.Text = script.Parent.ContentText
--               script.Parent.Text = colorize(ContentText)
-- ══════════════════════════════════════════════════════════════════════
editBox.Focused:Connect(function()
    -- Tampilkan plaintext agar user edit teks bersih (tanpa tag rich-text)
    editBox.Text = editBox.ContentText
end)

editBox.FocusLost:Connect(function()
    task.wait()  -- 1:1 dengan SL native
    -- Auto-save ke SL_CodeTextBox asli
    if currentSLCodeBox then
        pcall(function() currentSLCodeBox.Text = editBox.ContentText end)
    end
    -- Re-colorize
    refreshColorize()
end)

-- ══════════════════════════════════════════════════════════════════════
--  OPEN SCRIPT ke PANEL — showInPanel(scrObj)
--
--  Mirror ShowScript(p506) dari Explorer Studio Lite:
--    for _, v513 in pairs(p506:GetChildren()) do
--        if v513.Name:sub(1,3) == "SL_" then
--            local v514 = v513:Clone()
--            ...
--            if v514:FindFirstChild("SaveChangesTo") then
--                v514.SaveChangesTo.Value = v513  ← pointer ke ASLI
--            end
--            if v513.Name == "SL_CodeTextBox" then
--                ...
--            end
--        end
--    end
--    v507.Visible = true
--
--  Versi kita: skip clone (kita punya editBox sendiri),
--  cukup baca .ContentText dari SL_CodeTextBox asli,
--  simpan referensinya ke currentSLCodeBox.
-- ══════════════════════════════════════════════════════════════════════
local function showInPanel(scrObj)
    if not scrObj then return end
    if not (scrObj:IsA("Script") or scrObj:IsA("LocalScript") or scrObj:IsA("ModuleScript")) then
        return
    end

    -- Cari SL_CodeTextBox ASLI (child langsung scrObj)
    -- Ini adalah child yang sama dengan yang di-Clone oleh ShowScript SL.
    local slCodeBox = nil
    for _, child in ipairs(scrObj:GetChildren()) do
        if child.Name == "SL_CodeTextBox" then
            slCodeBox = child
            break
        end
    end

    -- Sembunyikan ViewScriptFrame bawaan SL (biar tidak dobel tampil)
    local vsf = StudioGui:FindFirstChild("ViewScriptFrame")
    if vsf then
        pcall(function() vsf.Visible = false end)
    end

    currentScript    = scrObj
    currentSLCodeBox = slCodeBox

    -- Judul: "ParentName.ScriptName"  (sama dengan titleLbl.Text di SL)
    local nm = scrObj.Name
    local par = scrObj.Parent
    if par then nm = par.Name .. "." .. nm end
    titleLbl.Text = nm
    statusLbl.Text = ""

    -- Load source ke editBox
    local src = ""
    if slCodeBox then
        -- Baca ContentText dari SL_CodeTextBox asli
        -- (ini plaintext yang SL_ColorizeAndEditLocal juga pakai)
        pcall(function() src = slCodeBox.ContentText or "" end)
        if src == "" then
            pcall(function() src = slCodeBox.Text or "" end)
        end
    end

    -- Fallback: baca Source langsung / decompile
    if src == "" then
        pcall(function() src = scrObj.Source or "" end)
        if src == "" and type(decompile) == "function" then
            local ok, dec = pcall(decompile, scrObj)
            if ok and type(dec) == "string" then src = dec end
        end
    end

    -- Set ke editBox, colorize
    editBox.Text = src
    mySG.Enabled = true
    mySG.DisplayOrder = 200

    snapToTop()
    task.spawn(function()
        for _ = 1, 8 do RunSvc.Heartbeat:Wait(); snapToTop() end
    end)
    task.defer(refreshColorize)
end

-- ══════════════════════════════════════════════════════════════════════
--  HOOK DEX EXPLORER → SelectionChanged
--
--  Sama dengan logika di Explorer.lua SL:
--    if p236[1]:IsA("LuaSourceContainer") then
--        ShowScript(p236[1])
--    end
-- ══════════════════════════════════════════════════════════════════════
local function hookDex()
    -- ★ FIX PERSIST v2.0: cari Dex di CoreGui dulu (lokasi baru, persisten),
    --   baru fallback ke PlayerGui (untuk backward-compat).
    local Dex = nil
    do
        local _ok, _cg = pcall(function() return game:GetService("CoreGui") end)
        if _ok and _cg then
            for _, v in ipairs(_cg:GetChildren()) do
                if v.Name == "Dex" then Dex = v; break end
            end
        end
    end
    if not Dex then
        Dex = PlayerGui:WaitForChild("Dex", 60)
    end
    if not Dex then warn("[SLv11] Dex tidak ditemukan"); return end
    local SE = Dex:WaitForChild("ScriptEditor", 30)
    if not SE then warn("[SLv11] ScriptEditor tidak ditemukan"); return end

    local GetSelection    = SE:WaitForChild("GetSelection", 10)
    local SelectionChanged = SE:WaitForChild("SelectionChanged", 10)
    local OpenScriptEv    = SE:FindFirstChild("OpenScript")

    -- SelectionChanged: user klik script di Explorer SL
    if SelectionChanged then
        SelectionChanged.Event:Connect(function()
            local ok, sel = pcall(function() return GetSelection:Invoke() end)
            if not ok or type(sel) ~= "table" or #sel == 0 then return end
            local obj = sel[1]
            if obj and obj:IsA("LuaSourceContainer") then
                showInPanel(obj)
            end
        end)
    end

    -- OpenScript event: hook tambahan (jika ada)
    if OpenScriptEv then
        OpenScriptEv.Event:Connect(function(scrObj)
            if scrObj and scrObj:IsA("LuaSourceContainer") then
                showInPanel(scrObj)
            end
        end)
    end
end

task.spawn(hookDex)

-- ══════════════════════════════════════════════════════════════════════
--  HOOK ViewScriptFrame — intercept saat SL native tampilkan editor
--
--  Ini adalah hook PALING ANDAL:
--    Saat SL native memanggil ShowScript() → ViewScriptFrame.Visible = true
--    Kita tangkap event itu, baca scrObj dari data yang sudah di-populate
--    SL di dalam frame, lalu sembunyikan frame SL & buka panel kita.
--
--  Cara baca scrObj dari ViewScriptFrame:
--    SL mengisi ScrollingFrame dengan clone SL_CodeTextBox.
--    Clone punya SaveChangesTo.Value = SL_CodeTextBox ASLI.
--    Dari SL_CodeTextBox asli kita bisa naik ke .Parent = scrObj.
-- ══════════════════════════════════════════════════════════════════════
local function hookViewScriptFrame(vsf)
    if not vsf or vsf:GetAttribute("SLv11_Hooked") then return end
    vsf:SetAttribute("SLv11_Hooked", true)

    local handling = false
    local function handle()
        if handling or not vsf.Visible then return end
        handling = true

        -- Sembunyikan panel SL dulu
        pcall(function() vsf.Visible = false end)

        -- Ambil scrObj dari SaveChangesTo.Value di dalam clone
        -- Studio Lite mengisi: v514.SaveChangesTo.Value = v513 (asli)
        -- v513.Parent = scrObj
        local scroll = vsf:FindFirstChild("ScrollingFrame")
        local scrObj = nil
        if scroll then
            -- Tunggu sampai SL selesai populate (async clone)
            local t0 = tick()
            while tick()-t0 < 0.5 do
                for _, ch in ipairs(scroll:GetChildren()) do
                    if ch.Name == "SL_CodeTextBox" then
                        local saveRef = ch:FindFirstChild("SaveChangesTo")
                        if saveRef and saveRef.Value and saveRef.Value.Parent then
                            scrObj = saveRef.Value.Parent
                            break
                        end
                    end
                end
                if scrObj then break end
                task.wait(0.05)
            end
        end

        if scrObj and scrObj:IsA("LuaSourceContainer") then
            showInPanel(scrObj)
        end

        handling = false
    end

    vsf:GetPropertyChangedSignal("Visible"):Connect(function()
        if vsf.Visible then task.defer(handle) end
    end)

    if vsf.Visible then task.defer(handle) end
end

-- Pasang hook ke ViewScriptFrame yang sudah ada
local existingVsf = StudioGui:FindFirstChild("ViewScriptFrame")
if existingVsf then hookViewScriptFrame(existingVsf) end

-- Watch jika SL re-create ViewScriptFrame
StudioGui.ChildAdded:Connect(function(ch)
    if ch.Name == "ViewScriptFrame" then
        task.defer(function() hookViewScriptFrame(ch) end)
    end
end)

-- ══════════════════════════════════════════════════════════════════════
--  HOOK _G.openScript (jika Studio Lite expose via _G)
--
--  Studio Lite di-decompile oleh SLVM — fungsi openScript() tidak
--  ada di _G standar. Tapi kalau SL versi tertentu expose-nya,
--  kita tangkap juga.
-- ══════════════════════════════════════════════════════════════════════
task.spawn(function()
    local t0 = tick()
    while type(_G.openScript) ~= "function" and tick()-t0 < 30 do
        task.wait(0.2)
    end
    if type(_G.openScript) ~= "function" then return end
    if _G.SLv11_openScriptWrapped then return end
    _G.SLv11_openScriptWrapped = true

    local orig = _G.openScript
    _G.openScript = function(scrObj, ...)
        if scrObj and typeof(scrObj) == "Instance"
        and scrObj:IsA("LuaSourceContainer") then
            pcall(showInPanel, scrObj)
        end
        return orig(scrObj, ...)
    end
end)

-- ══════════════════════════════════════════════════════════════════════
--  SL_CodeTextBox WATCHER
--
--  Ketika SL buka script baru di ViewScriptFrame YANG SUDAH ADA
--  (tanpa toggle Visible), SL hanya mengisi ulang ScrollingFrame.
--  Kita perlu mendeteksi perubahan SL_CodeTextBox di dalam scroll.
-- ══════════════════════════════════════════════════════════════════════
task.spawn(function()
    local vsf = StudioGui:WaitForChild("ViewScriptFrame", 30)
    if not vsf then return end
    local scroll = vsf:WaitForChild("ScrollingFrame", 10)
    if not scroll then return end

    local function watchCodeBox(box)
        if not box or box:GetAttribute("SLv11_Watched") then return end
        box:SetAttribute("SLv11_Watched", true)

        box:GetPropertyChangedSignal("Text"):Connect(function()
            if not vsf.Visible then return end
            -- SL sedang update isi editor → kita intercept
            task.defer(function()
                if not vsf.Visible then return end
                local saveRef = box:FindFirstChild("SaveChangesTo")
                if saveRef and saveRef.Value and saveRef.Value.Parent then
                    local scrObj = saveRef.Value.Parent
                    if scrObj:IsA("LuaSourceContainer") then
                        pcall(function() vsf.Visible = false end)
                        showInPanel(scrObj)
                    end
                end
            end)
        end)
    end

    scroll.ChildAdded:Connect(function(ch)
        if ch.Name == "SL_CodeTextBox" then
            task.defer(function() watchCodeBox(ch) end)
        end
    end)
    for _, ch in ipairs(scroll:GetChildren()) do
        if ch.Name == "SL_CodeTextBox" then watchCodeBox(ch) end
    end
end)

print("[SLv11] Script Editor Native Mirror aktif ✓")
print("[SLv11] Klik script di Explorer Studio Lite untuk membuka panel.")
